/* =====================================================================
 * SOF Field Formulary — drug dataset (165 medications, 28 categories)
 *   Merged & expanded from the Tactical Pharmacology (case-scenario) and
 *   Small Unit Care (structured reference + quiz) interactives, plus
 *   worldwide SOF additions and international/alternate drug names.
 *   Each drug: id, name, brand, aka[], cat, cls, mech, dose, ind, contra,
 *   se, notes, tccc, duty, scenarios[] (case teaching), quiz[].
 * ===================================================================== */
window.FORMULARY_DRUGS = [{"id": 1,"name": "Acetaminophen","brand": "Tylenol","aka": ["Paracetamol","APAP","Panadol","Calpol"],"cat": "Analgesics & Pain Management","cls": "Non-opioid analgesic, antipyretic","mech": "Inhibits prostaglandin synthesis in CNS; inhibits hypothalamic heat-regulating center","dose": "325-1000 mg PO q6h (max 4 g/day); reduce dose in hepatic impairment","ind": "Mild-moderate pain, headache, fever reduction","contra": "Severe hepatic impairment","se": "Hepatotoxicity (overdose), rash, nausea","notes": "First-line for mild pain; K-9: Contraindicated","tccc": false,"duty": "go","scenarios": [{"scenario": "A 31-year-old SOAR Pilot is grounded for 24 hours due to a fever and a significant tension headache he developed overnight. He needs to return to flight status as soon as he is afebrile and symptom-free. He cannot take medications that would cause drowsiness or affect blood clotting.","context": "Real-World Context: This is one of the most common sick-call presentations in aviation units. Think of Acetaminophen as the “swiss army knife” of pain relief for operators who must stay sharp — it kills pain and fever without the cognitive fog or bleeding risk. Pilots live under a microscope of aeromedical standards; even an OTC antihistamine can ground them. In garrison, a flight surgeon will clear a pilot once they’re 24 hours afebrile, so this med buys them the fastest road back to the cockpit. In a deployed setting, managing a pilot’s fever quickly can mean the difference between a mission launching or scrubbing.","diagnosis": "The patient has a Febrile Illness, likely viral, with an associated tension headache. The goal is to manage symptoms (fever and pain) without side effects that would impair a pilot’s function.","opqrst": "Onset: Gradual, over the past 12 hours. Provocation: Light and noise make the headache worse. Quality: \"A tight band around my head.\" Radiation: Headache is global, non-radiating. Severity: 6/10. Time: Constant.","sample": "Signs/Symptoms: Headache, generalized muscle aches, subjective fever. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Water, 1 hour ago. Events: Suspected viral syndrome.","vitals": "Heart Rate: 90 bpm | Blood Pressure: 125/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 101.3°F","exam": "Basic neurological exam to rule out serious causes of headache (no focal deficits). Assess for neck stiffness (absent).","primary": "Acetaminophen (Tylenol) — 650–1000 mg PO every 4–6 hours. Max dose of 4g in 24 hours. Ideal choice as it has no effect on platelets and is not sedating.","alternative": "Meloxicam — 15 mg PO, once a day. A reasonable alternative if acetaminophen is not available, as it has minimal effect on platelet function compared to other NSAIDs.","avoid": "Ibuprofen or Aspirin due to anti-platelet effects. Opioids due to sedative effects.","dutyStatus": "FULLY MISSION CAPABLE. No duty restrictions. Safe for all operational roles including flight status.","onsetDuration": "Onset: 30–60 min PO. Duration: 4–6 hours per dose.","cognitive": "None. No sedation, no impairment of reaction time or decision-making.","field": "Component of the CWMP. Must monitor cumulative dosing — max 3g/day to avoid hepatotoxicity. Avoid in known liver disease or heavy alcohol use."}],"quiz": [{"q": "What is the maximum recommended daily dose of acetaminophen in a healthy adult?","choices": ["2 g/day","4 g/day","6 g/day","8 g/day"],"answer": 1,"explain": "The standard adult ceiling is 4 g/day, with lower limits in hepatic impairment to avoid hepatotoxicity."}]},{"id": 2,"name": "Aspirin (ASA)","brand": "Bayer","aka": ["Acetylsalicylic Acid","Disprin"],"cat": "Analgesics & Pain Management","cls": "NSAID, salicylate, antiplatelet","mech": "Irreversibly inhibits COX-1 and COX-2, blocking thromboxane A2 and platelet aggregation","dose": "MI: 325 mg chewed; Secondary prevention: 81-325 mg daily","ind": "ACS/MI, stroke prevention, mild-moderate pain, fever","contra": "Active bleeding, aspirin allergy, children with viral illness (Reye syndrome)","se": "GI bleeding, tinnitus, allergic reactions","notes": "FIRST medication in suspected MI; minimize in combat due to coagulopathy","tccc": true,"duty": "go","scenarios": [{"scenario": "A 58-year-old civilian engineering contractor attached to a Civil Affairs team suddenly stops working, clutches his chest, and complains of crushing chest pain that is radiating to his left arm. He is pale, sweating profusely, and short of breath.","context": "Real-World Context: Older contractors are a fixture of modern deployments, and they bring their civilian risk factors with them — hypertension, high cholesterol, sedentary lifestyles, and stress. Think of Aspirin in this context not as a painkiller but as a “fire extinguisher for a blood clot.” When a coronary artery clogs, platelets pile on like traffic at a crash scene. Chewing aspirin immediately floods the bloodstream with anti-platelet action, keeping that clot from growing. The emphasis on chewing (not swallowing whole) matters: absorption through the oral mucosa gets aspirin into the blood within minutes. The old mnemonic was MONA (Morphine, Oxygen, Nitroglycerin, Aspirin). Current practice is shifting Morphine out in favor of Fentanyl for superior pain control, and Oxygen is now only given if SpO2 drops below 94%.","diagnosis": "This is a classic presentation of an Acute Coronary Syndrome (ACS), highly suspicious for an Acute Myocardial Infarction (AMI) or \"heart attack.\" The immediate priority is to prevent further clot formation.","opqrst": "Onset: Sudden, 10 minutes ago. Provocation: Not relieved by rest. Quality: \"Like an elephant is sitting on my chest.\" Radiation: To the left jaw and left arm. Severity: 10/10. Time: Constant.","sample": "Signs/Symptoms: Crushing substernal chest pain, diaphoresis (sweating), dyspnea (shortness of breath), anxiety. Allergies: NKDA. Medications: Takes a \"blood pressure pill.\" Past Pertinent History: Hypertension, high cholesterol. Last Oral Intake: Breakfast 1 hour ago. Events: Spontaneous onset of symptoms at rest.","vitals": "Heart Rate: 110 bpm | Blood Pressure: 155/95 mmHg | Respiratory Rate: 24 breaths/min | SpO2: 93% on room air | Temperature: 98.0°F","exam": "Obtain 12-lead EKG if available to look for ST-elevation. Auscultate lungs for signs of heart failure (crackles).","primary": "Aspirin (ASA) — 324 mg (four 81 mg chewable baby aspirins) or one 325 mg tablet, chewed and swallowed. This is for its immediate anti-platelet effect.","alternative": "","avoid": "","dutyStatus": "FULLY MISSION CAPABLE for standard doses. No duty restrictions.","onsetDuration": "Onset: Chewed — 15 min (critical for ACS). Duration: Antiplatelet effect lasts 7–10 days.","cognitive": "None.","field": "Irreversible platelet inhibition — increases bleeding risk for the duration. Contraindicated in trauma casualties at risk of hemorrhage. Always chew for ACS to ensure rapid absorption."}],"quiz": [{"q": "In a patient with suspected acute myocardial infarction, what is the recommended aspirin dose and route?","choices": ["81 mg swallowed whole","325 mg chewed","650 mg PR","100 mg IV"],"answer": 1,"explain": "Aspirin is the first medication in suspected MI, given as 325 mg chewed for rapid antiplatelet effect."},{"q": "Why should aspirin be avoided in a child with a viral illness?","choices": ["It causes tooth discoloration","It triggers Reye syndrome","It blunts the fever response","It worsens dehydration"],"answer": 1,"explain": "Aspirin is contraindicated in children with viral illness due to the risk of Reye syndrome."}]},{"id": 3,"name": "Ibuprofen","brand": "Advil/Motrin","aka": ["Brufen","Nurofen","Advil","Motrin"],"cat": "Analgesics & Pain Management","cls": "NSAID, analgesic, antipyretic","mech": "Reversibly inhibits COX-1 and COX-2, reducing prostaglandin synthesis","dose": "200-800 mg PO q6-8h (max 3200 mg/day)","ind": "Pain, inflammation, fever, dysmenorrhea","contra": "GI bleeding, severe renal impairment, third trimester pregnancy","se": "GI upset, GI bleeding, renal impairment","notes": "Take with food; avoid in dehydration/shock","tccc": false,"duty": "limited","scenarios": [{"scenario": "A Ranger on a winter warfare training exercise in Alaska removed his gloves for 20 minutes to operate a piece of equipment. Two hours later, he reports to the medic that he can’t feel his fingers. They appear white, waxy, and are hard to the touch.","context": "Real-World Context: Frostbite is tissue destruction by ice crystal formation inside and between cells — think of it as the polar opposite of a burn, but with equally devastating results. The real damage isn’t from the freezing itself; it’s from the reperfusion injury when blood flow returns. As frozen tissue thaws, a cascade of prostaglandins and thromboxanes (inflammatory mediators) floods the damaged blood vessels, causing clots that block circulation to the tissue. Ibuprofen is specifically recommended in frostbite protocols NOT as a painkiller (though it helps) but as an anti-prostaglandin/anti-thromboxane agent — think of it as a chemical fire retardant applied before the inflammatory inferno of rewarming. The cardinal rule of frostbite management is NEVER rewarm if there is ANY chance of refreezing; a freeze-thaw-refreeze cycle causes exponentially worse damage than leaving it frozen. Rewarming is done in a 98–102°F water bath (NOT hot water, NOT dry heat, NOT rubbing) and is excruciating — have Fentanyl or Ketamine ready before you start.","diagnosis": "The casualty has Deep Frostbite (3rd/4th degree). The tissue is frozen solid. Treatment is focused on preventing further injury and preparing for rewarming, which is extremely painful and should only be done when definitive care is available.","opqrst": "Patient reports complete numbness. \"I can't feel anything.\" Pain will become severe upon rewarming.","sample": "Signs/Symptoms: Fingers are white/yellow, hard, and feel \"wooden.\" No capillary refill. Blisters may or may not be present. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Prolonged exposure of bare skin to sub-freezing temperatures.","vitals": "(Systemically stable) Core Temp: 97.0°F","exam": "Assess the extent of the injury. Remove any constricting jewelry. DO NOT rewarm the tissue if there is any possibility of it refreezing before reaching definitive care.","primary": "","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Ibuprofen is best avoided in which field scenario?","choices": ["A soldier with a tension headache","A casualty in shock or significant dehydration","Mild knee strain with normal vitals","Menstrual cramps"],"answer": 1,"explain": "As an NSAID, ibuprofen can worsen renal perfusion, so it is avoided in dehydration or shock."}]},{"id": 4,"name": "Ketorolac","brand": "Toradol","aka": ["Toradol","Ketorolac Tromethamine"],"cat": "Analgesics & Pain Management","cls": "NSAID analgesic","mech": "Potent COX inhibitor with primarily analgesic effects","dose": "15-30 mg IV/IM q6h or 10 mg PO q4-6h (MAX 5 DAYS TOTAL)","ind": "Moderate to severe acute pain (short-term)","contra": "GI bleeding, renal impairment, perioperative CABG, hypovolemia","se": "GI bleeding, renal toxicity, platelet dysfunction","notes": "TCCC analgesic option; max 5 days; avoid in shock","tccc": true,"duty": "limited","scenarios": [{"scenario": "A 31-year-old Ranger severely strains his quadriceps muscle while sprinting during a training exercise. He has immediate, significant pain and difficulty bearing weight. He is not in shock and has no other injuries. The medic needs to provide strong, non-opioid pain relief.","context": "Real-World Context: Ketorolac is the “sniper rifle” of NSAIDs — it delivers opioid-level pain relief without any of the sedation, respiratory depression, or cognitive impairment that opioids cause. Think of it as Ibuprofen’s much stronger, injectable cousin. The IV/IM route bypasses the GI tract for rapid onset (15–30 minutes), making it ideal when a patient is in too much pain to wait for oral medication to kick in. The critical limitation: Ketorolac is a short-course drug only, maximum 5 days. Beyond that, the risk of GI bleeding and renal injury climbs steeply. It’s also contraindicated in any patient with potential internal bleeding (trauma casualties with abdominal injuries), renal impairment, or those on anticoagulants. For a clean musculoskeletal injury like this strain, it’s the perfect tool — fast, potent, and keeps the operator mentally sharp.","diagnosis": "The patient has an Acute, Severe Musculoskeletal Strain. The goal is potent, non-sedating, non-opioid analgesia to manage the pain and inflammation.","opqrst": "Onset: Sudden, while sprinting. Provocation: Any attempt to contract the muscle or bear weight. Quality: \"Sharp, tearing pain.\" Radiation: Localized to the anterior thigh. Severity: 8/10. Time: Constant.","sample": "Signs/Symptoms: Severe pain, tenderness, and swelling over the quadriceps muscle. A palpable defect may be present. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Acute muscle strain.","vitals": "Heart Rate: 95 bpm | Blood Pressure: 135/80 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam": "Assess for ability to extend the knee against gravity. Palpate the muscle for defects. Rule out fracture.","primary": "Ketorolac (Toradol) — 30 mg IV or 60 mg IM as a single dose. Provides analgesia comparable to some opioids for acute pain. Use should not exceed 5 days due to risk of GI bleed and renal injury.","alternative": "High-Dose Ibuprofen (800 mg PO) or Naproxen (500 mg PO). Combat Wound Medication Pack (Meloxicam/Acetaminophen): Could be used, but may not be strong enough for severe initial pain.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario": "During a MEDCAP, a 40-year-old local male farmer is brought to the medics, writhing in agony. He complains of sudden, severe pain in his left flank that radiates down to his groin. He is nauseous and cannot find a position of comfort.","context": "Real-World Context: Kidney stone pain (renal colic) is famously ranked alongside childbirth and burns as the most intense pain a human can experience. The stone isn’t just sitting there hurting — it’s triggering violent spasms of the ureter (the tube from kidney to bladder), like a fire alarm that won’t stop ringing. What makes NSAIDs (especially Ketorolac) superior to opioids here is that they attack the ROOT CAUSE of the pain: prostaglandin-mediated ureteral spasm and inflammation. Think of Ketorolac as both turning off the alarm AND fixing the short circuit, while opioids just muffle the alarm sound without stopping it. The classic presentation — a patient who literally cannot sit still, constantly shifting positions trying to find relief — is almost pathognomonic. The benign abdominal exam despite 10/10 pain is the diagnostic clue: peritonitis and bowel obstruction cause patients to lie still; renal colic causes them to writhe.","diagnosis": "This is a classic presentation of Renal Colic caused by a kidney stone (nephrolithiasis). The primary goal is aggressive pain management. NSAIDs are particularly effective as they reduce inflammation and spasm in the ureter.","opqrst": "Onset: Sudden, 1 hour ago. Provocation: None; constant and unrelenting. Quality: \"The worst pain of my life.\" Radiation: From the left flank/back down to the testicle. Severity: 10/10. Time: Constant waves of severe pain.","sample": "Signs/Symptoms: Severe flank pain, nausea/vomiting, hematuria (blood in urine). Allergies: Unknown. Medications: None. Past Pertinent History: Has had this happen once before. Last Oral Intake: Vomited water 10 minutes ago. Events: Spontaneous onset of renal colic.","vitals": "Heart Rate: 115 bpm | Blood Pressure: 160/95 mmHg (elevated from pain) | Respiratory Rate: 24 breaths/min | Temperature: 99.0°F","exam": "Patient is in visible distress, constantly moving. Abdominal exam is surprisingly benign. Severe costovertebral angle (CVA) tenderness on the left side.","primary": "Ketorolac (Toradol) — 30 mg IV or 60 mg IM. The drug of choice for renal colic pain due to its potent analgesic and anti-inflammatory properties.","alternative": "Opioids (e.g., Fentanyl or Morphine): Can be used if Ketorolac is contraindicated or insufficient, but NSAIDs are generally considered superior for this type of pain. IV Fluids: To promote hydration and help pass the stone.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What is the maximum total duration of ketorolac therapy?","choices": ["5 days","10 days","14 days","30 days"],"answer": 0,"explain": "Ketorolac is limited to a maximum of 5 days total because of GI and renal toxicity risk."},{"q": "Ketorolac is contraindicated in which surgical setting?","choices": ["Appendectomy","Perioperative CABG","Wound debridement","Fracture reduction"],"answer": 1,"explain": "Ketorolac is contraindicated perioperatively in CABG due to bleeding and cardiovascular risk."}]},{"id": 5,"name": "Naproxen","brand": "Aleve/Naprosyn","aka": ["Naprosyn","Aleve","Naproxen Sodium"],"cat": "Analgesics & Pain Management","cls": "NSAID, analgesic","mech": "Reversibly inhibits COX-1 and COX-2","dose": "250-500 mg PO BID (max 1000 mg/day)","ind": "Acute pain, fever, gout, migraine, arthritis","contra": "GI ulceration, renal dysfunction, bleeding disorders","se": "GI ulceration, hypertension, CV risk","notes": "Longer duration than ibuprofen; onset 30-60 min","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 45-year-old Special Forces Team Sergeant complains of chronic, nagging lower back pain that is stiff in the morning and aches after a long day on his feet. It is not severe, but he needs a long-acting anti-inflammatory to manage it through the day.","context": "Real-World Context: Chronic mechanical back pain is the occupational disease of the special operations community — years of rucking, jumping, and carrying heavy loads compress and degrade the lumbar discs. Think of the spinal discs as shock absorbers that slowly lose their fluid and elasticity after thousands of cycles. Naproxen is the “marathon runner” of NSAIDs: its 12–17 hour half-life means twice-daily dosing provides continuous anti-inflammatory coverage, unlike Ibuprofen’s 4–6 hour sprints that require dosing four times a day. For a Team Sergeant who needs reliable all-day relief without constantly popping pills on patrol, Naproxen is the practical choice. The key distinction from Meloxicam (CWMP): Naproxen is for chronic daily management, while Meloxicam in the CWMP is for acute combat injury. Both are NSAIDs, but they fill different roles — like a daily vitamin versus an emergency ration.","diagnosis": "The patient has Chronic Mechanical Lower Back Pain, likely from degenerative arthritis. The goal is to provide long-lasting anti-inflammatory and analgesic effects.","opqrst": "Onset: Chronic, for years. Provocation: Activity, long periods of standing. Quality: \"A dull ache.\" Radiation: Stays in the lower back. Severity: 3–4/10. Time: Worse at the end of the day.","sample": "Signs/Symptoms: Chronic, non-radicular lower back pain. Allergies: NKDA. Medications: Takes Tylenol occasionally. Past Pertinent History: Degenerative disc disease. Last Oral Intake: Normal. Events: Managing chronic pain.","vitals": "Within normal limits.","exam": "Mild tenderness over the lumbar spine. Normal neurologic exam.","primary": "Naproxen (Aleve) — 220–440 mg PO twice a day. An NSAID with a longer half-life than ibuprofen, well-suited for twice-daily dosing to provide all-day relief.","alternative": "Ibuprofen (Motrin): 400–600 mg every 6–8 hours. Also effective, but requires more frequent dosing. Meloxicam (Mobic): A once-daily NSAID.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Compared with ibuprofen, a key practical advantage of naproxen is that it has a","choices": ["Faster onset","Longer duration of action","Lower cardiovascular risk","Stronger COX-2 selectivity"],"answer": 1,"explain": "Naproxen has a longer duration than ibuprofen, allowing twice-daily dosing."}]},{"id": 6,"name": "Meloxicam","brand": "Mobic","aka": ["Mobic","Movalis","Mobicox"],"cat": "Analgesics & Pain Management","cls": "NSAID, analgesic","mech": "Preferential COX-2 inhibition","dose": "7.5-15 mg PO once daily","ind": "Acute pain, osteoarthritis, rheumatoid arthritis","contra": "Renal dysfunction, GI ulceration, bleeding disorders","se": "GI ulceration, CV risk, hypertension","notes": "Once daily dosing; slower onset","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 26-year-old male Ranger is on a multi-day patrol. During a movement through uneven terrain, he rolls his right ankle. He can bear weight and continue with the mission but reports nagging pain and has some mild swelling. He is alert and oriented, and his only complaint is his ankle.","context": "Real-World Context: The Combat Wound Medication Pack (CWMP) is the first rung of the TCCC Triple-Option Analgesia ladder — it’s the “self-aid” option that every warfighter carries. Think of Meloxicam as a “long-burn candle” compared to Ibuprofen’s “flashlight battery.” Meloxicam is a COX-2 preferential NSAID, meaning it targets inflammation with less GI irritation than traditional NSAIDs, and its once-daily dosing means a warfighter on patrol doesn’t need to remember pills every 4–6 hours. Paired with extended-release Acetaminophen (which attacks pain through a different mechanism — central nervous system modulation), the CWMP creates a synergistic analgesic effect greater than either drug alone, without any sedation or cognitive impairment. This is what makes it “fight-through” medicine: the Ranger stays alert, stays armed, and stays in the fight.","diagnosis": "This casualty is conscious and alert, experiencing mild to moderate pain from a musculoskeletal injury. The patient is hemodynamically stable and still able to function as a combatant. This is the first option in the TCCC \"Triple-Option Analgesia\" strategy. The Combat Wound Medication Pack (CWMP) should be administered.","opqrst": "Onset: Sudden, 1 hour ago. Provocation: Worse with walking, better with rest. Quality: \"Achy and sore.\" Radiation: Pain is in the right ankle only. Severity: 4/10. Time: Constant since the injury.","sample": "Signs/Symptoms: Mild swelling and tenderness to palpation over the right ankle. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: MRE and water 2 hours ago. Events: Slipped on loose rock and rolled his ankle.","vitals": "Heart Rate: 88 bpm | Blood Pressure: 132/78 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 98.7°F","exam": "Neuromuscular exam of the right ankle, assessing for pulses, sensation, and motor function. Slight pain on exam with movement.","primary": "","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Meloxicam is best described mechanistically as which type of NSAID?","choices": ["Irreversible COX-1 inhibitor","Preferential COX-2 inhibitor","Pure COX-3 inhibitor","Lipoxygenase inhibitor"],"answer": 1,"explain": "Meloxicam preferentially inhibits COX-2 and is dosed once daily."}]},{"id": 7,"name": "Ketamine","brand": "Ketalar","aka": ["Ketalar","Ketanest","Special K"],"cat": "Analgesics & Pain Management","cls": "Dissociative anesthetic, NMDA antagonist","mech": "Blocks NMDA receptors; provides dissociative anesthesia with cardiovascular stability","dose": "Analgesia: 0.1-0.3 mg/kg IV, 0.5-1 mg/kg IN; Sedation: 1-2 mg/kg IV; RSI: 1.5-2 mg/kg IV","ind": "Analgesia in trauma/shock, procedural sedation, RSI","contra": "Severe HTN, eclampsia (relative: psychosis)","se": "Emergence reactions, hypersalivation, transient HTN","notes": "TCCC FIRST-LINE in shock; safe in TBI; maintains BP","tccc": true,"duty": "limited","scenarios": [{"scenario": "A 32-year-old Special Forces Engineer Sergeant sustains a traumatic amputation of his left foot from a pressure-plate IED. A tourniquet has been applied to his thigh, and bleeding is controlled, but he is in excruciating pain, agitated, and showing early signs of shock.","context": "Real-World Context: Ketamine is the crown jewel of battlefield analgesia — think of it as the one drug designed for the worst day of someone’s life. Unlike opioids (Fentanyl, Morphine) that suppress the cardiovascular system, Ketamine actually supports blood pressure and heart rate through sympathetic stimulation, making it the ONLY safe choice for a casualty already sliding into shock. It works by “disconnecting” the brain from the body — the patient enters a dissociative state where they’re technically conscious (eyes open, nystagmus present) but completely detached from pain. Think of it as pulling the plug between the brain’s pain receiver and the body’s pain transmitter. The IM/IN routes are invaluable when IV access hasn’t been established yet in the chaos of a blast injury. The clinical endpoint is nystagmus (eye wiggling), not unconsciousness. This scenario also highlights the complete trauma package: TXA to prevent clot breakdown, blood products for volume, Calcium Gluconate to counteract citrate from transfusion, and antibiotics for the open wound.","diagnosis": "The casualty is in Hemorrhagic Shock with severe pain. This is the third option in the TCCC \"Triple-Option Analgesia\" strategy. Analgesics that could worsen shock (like opioids that lower blood pressure) must be avoided.","opqrst": "Patient is agitated and screaming in pain, unable to provide a detailed OPQRST. Pain is clearly severe and originating from the injury site.","sample": "Signs/Symptoms: Traumatic amputation below the knee, pale/cool skin, altered mental status (agitated, confused). Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Unknown. Events: Blast injury from an IED.","vitals": "Heart Rate: 135 bpm, weak radial pulse | Blood Pressure: 90/60 mmHg | Respiratory Rate: 26 breaths/min | SpO2: 95% on room air | Temperature: 97.5°F","exam": "Confirm tourniquet effectiveness. Assess for other blast injuries. Neurological assessment for signs of head injury vs. shock.","primary": "","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Why is ketamine a TCCC first-line analgesic in a casualty who is in shock?","choices": ["It causes profound vasodilation","It maintains blood pressure and is safe in TBI","It is a pure opioid with no respiratory effect","It reverses hemorrhage"],"answer": 1,"explain": "Ketamine provides dissociative analgesia with cardiovascular stability and is considered safe in TBI."},{"q": "What is the analgesic intranasal (IN) dose of ketamine?","choices": ["0.1-0.3 mg/kg","0.5-1 mg/kg","1.5-2 mg/kg","5 mg/kg"],"answer": 1,"explain": "Ketamine analgesia is 0.1-0.3 mg/kg IV but 0.5-1 mg/kg intranasal."}]},{"id": 8,"name": "Fentanyl","brand": "Sublimaze","aka": ["Sublimaze","Durogesic","Actiq"],"cat": "Analgesics & Pain Management","cls": "Opioid analgesic, mu-receptor agonist","mech": "Full mu-opioid agonist; 100x potency of morphine","dose": "25-100 mcg IV q30-60min; 1-2 mcg/kg intranasal","ind": "Moderate to severe pain, procedural sedation adjunct","contra": "Respiratory depression, MAOIs within 14 days","se": "Respiratory depression, hypotension, chest wall rigidity","notes": "TCCC option; less histamine release; fast onset","tccc": true,"duty": "","scenarios": [],"quiz": [{"q": "How does fentanyl compare in potency to morphine?","choices": ["About 10x less potent","Roughly equal potency","About 100x more potent","About 1000x more potent"],"answer": 2,"explain": "Fentanyl is a full mu-opioid agonist with roughly 100x the potency of morphine."},{"q": "An advantage of fentanyl over morphine in trauma is that fentanyl causes","choices": ["More histamine release","Less histamine release and faster onset","Greater hypotension","Longer duration"],"answer": 1,"explain": "Fentanyl releases less histamine and has a fast onset, making it favorable in trauma."}]},{"id": 9,"name": "Morphine","brand": "MS Contin","aka": ["MS Contin","Morphine Sulfate","Oramorph","MSO4"],"cat": "Analgesics & Pain Management","cls": "Opioid analgesic, mu-receptor agonist","mech": "Full mu-opioid agonist; causes analgesia, euphoria, respiratory depression","dose": "2.5-10 mg IV q2-4h; 5-15 mg IM/SQ q4h; titrate to effect","ind": "Severe acute pain, preanesthesia, acute pulmonary edema","contra": "Respiratory depression, hypotension, head injury, hypovolemia","se": "Respiratory depression, hypotension, histamine release","notes": "AVOID in shock/hemorrhage and TBI; causes vasodilation","tccc": true,"duty": "","scenarios": [],"quiz": [{"q": "Why is morphine avoided in hemorrhagic shock and TBI?","choices": ["It raises intracranial pressure via dissociation","It causes vasodilation and can worsen hypotension","It blocks platelet function","It triggers chest wall rigidity"],"answer": 1,"explain": "Morphine causes histamine-mediated vasodilation and hypotension, so it is avoided in shock and head injury."},{"q": "What is a typical IV starting dose range of morphine for severe acute pain?","choices": ["0.1-0.3 mg","2.5-10 mg","25-50 mg","100 mg"],"answer": 1,"explain": "Morphine is dosed 2.5-10 mg IV every 2-4 hours, titrated to effect."}]},{"id": 10,"name": "Hydromorphone","brand": "Dilaudid","aka": ["Dilaudid","Dihydromorphinone","Palladone"],"cat": "Analgesics & Pain Management","cls": "Opioid analgesic","mech": "Semisynthetic mu-opioid agonist; 8-10x more potent than morphine","dose": "0.5-2 mg IV/IM/SQ q2-3h; 2-4 mg PO q4-6h","ind": "Moderate to severe pain","contra": "Respiratory depression, paralytic ileus","se": "Respiratory depression, sedation, nausea","notes": "Alternative to morphine; similar precautions","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "Hydromorphone is approximately how potent relative to morphine?","choices": ["Equal potency","2x more potent","8-10x more potent","100x more potent"],"answer": 2,"explain": "Hydromorphone is a semisynthetic mu-agonist about 8-10x more potent than morphine."}]},{"id": 11,"name": "Sufentanil","brand": "Sufenta","aka": ["Sufenta"],"cat": "Analgesics & Pain Management","cls": "Opioid analgesic","mech": "Synthetic mu-opioid agonist; 5-10x more potent than fentanyl","dose": "0.1-0.5 mcg/kg IV","ind": "Severe pain, anesthesia adjunct","contra": "Respiratory depression, MAOIs","se": "Respiratory depression, bradycardia, chest wall rigidity","notes": "Most potent opioid; anesthesia setting primarily","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "Sufentanil is described as the most potent opioid, being how potent relative to fentanyl?","choices": ["2x less potent","Equal potency","5-10x more potent","100x more potent"],"answer": 2,"explain": "Sufentanil is 5-10x more potent than fentanyl and used primarily in the anesthesia setting."}]},{"id": 12,"name": "Naloxone","brand": "Narcan","aka": ["Narcan","Naloxone Hydrochloride"],"cat": "Analgesics & Pain Management","cls": "Opioid antagonist","mech": "Competitive antagonist at mu, kappa, delta opioid receptors","dose": "0.04-2 mg IV/IM/IN; may repeat q2-3min; consider infusion for long-acting opioids","ind": "Opioid overdose, reversal of opioid respiratory depression","contra": "Hypersensitivity (relative: opioid dependence)","se": "Acute withdrawal, hypertension, pulmonary edema","notes": "Titrate to respirations, not consciousness; monitor for re-sedation","tccc": true,"duty": "limited","scenarios": [{"scenario": "A 22-year-old male Ranger sustained a lower leg fracture. For pain control during a prolonged field extraction, he was given an oral transmucosal fentanyl lozenge. Fifteen minutes later, his team finds him unresponsive with very slow breathing.","context": "Real-World Context: Opioid-induced respiratory depression is the “dark side” of the most powerful pain drugs in the medic’s toolkit. Fentanyl suppresses the brainstem’s respiratory drive — think of it as slowly turning down the volume dial on the brain’s “breathe now” signal until it fades to silence. The classic triad is unmistakable: unresponsive, pinpoint pupils, respiratory rate below 12. Naloxone is the perfect pharmacological antidote — it competitively blocks opioid receptors, physically bumping the fentanyl off the receptor sites. Think of it as changing the locks while the intruder is inside. The critical nuance: titrate to BREATHING, not to consciousness. Slamming the full 2mg dose into a trauma patient will instantly reverse ALL pain control, sending them from unconscious to screaming in agony with a fracture — and the resulting catecholamine surge can cause cardiac events. Start with 0.4mg, support ventilations with a BVM, and add 0.4mg every 2–3 minutes until respiratory rate improves to >12/min. The duration warning: Naloxone lasts 30–90 minutes, but Fentanyl can last longer. Re-sedation is a real threat, so continuous monitoring after reversal is mandatory.","diagnosis": "This casualty is experiencing Opioid-Induced Respiratory Depression secondary to fentanyl administration. The immediate life threat is respiratory arrest.","opqrst": "Not applicable; patient is unresponsive.","sample": "Signs/Symptoms: Unresponsive to verbal or painful stimuli, pinpoint pupils (miosis), slow and shallow respirations, cyanosis (blue lips and skin). Allergies: NKDA. Medications: 800 mcg fentanyl lozenge 15 minutes ago. Past Pertinent History: Closed tibia fracture 1 hour ago. Last Oral Intake: Fentanyl lozenge. Events: Medicated for severe pain, now unresponsive.","vitals": "Heart Rate: 50 bpm | Blood Pressure: 95/60 mmHg | Respiratory Rate: 6 breaths/min, shallow | SpO2: 85% and falling | Temperature: 98.0°F","exam": "Neurological assessment for level of consciousness (unresponsive on AVPU scale) and pupil examination. Airway and respiratory assessment to confirm bradypnea and airway patency.","primary": "","alternative": "Ventilatory Support: While preparing naloxone, the immediate priority is to support the patient’s breathing using a Bag-Valve Mask (BVM) to prevent hypoxia and respiratory arrest. There is no direct pharmacological alternative to Naloxone.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "When titrating naloxone in an opioid overdose, the endpoint should be","choices": ["Full return of consciousness","Adequate respirations","Pupil dilation","A heart rate over 100"],"answer": 1,"explain": "Naloxone is titrated to restore adequate respirations, not full consciousness, to limit withdrawal."},{"q": "After giving naloxone for a long-acting opioid, what is the key ongoing concern?","choices": ["Permanent hearing loss","Re-sedation as naloxone wears off","Delayed hepatotoxicity","Rebound hypertension only"],"answer": 1,"explain": "Naloxone is short-acting, so patients must be monitored for re-sedation and may need an infusion."}]},{"id": 13,"name": "Lidocaine","brand": "Xylocaine","aka": ["Lignocaine","Xylocaine","Lidocaine Hydrochloride"],"cat": "Local Anesthetics","cls": "Local anesthetic, Class Ib antiarrhythmic","mech": "Blocks sodium channels in nerve membranes, preventing depolarization","dose": "Infiltration: 0.5-2% solution; max 4.5 mg/kg without epi, 7 mg/kg with epi","ind": "Local/regional anesthesia, wound repair, nerve blocks","contra": "Amide anesthetic allergy, severe heart block","se": "CNS toxicity (tinnitus, seizures), cardiovascular depression","notes": "Add epi for vasoconstriction (not on digits, nose, ears, penis)","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "When is epinephrine-containing lidocaine contraindicated?","choices": ["Scalp laceration repair","Infiltration of digits, nose, ears, or penis","Large abdominal wounds","Intramuscular blocks"],"answer": 1,"explain": "Epinephrine-containing lidocaine is avoided in end-arterial areas like digits, nose, ears, and penis."}]},{"id": 14,"name": "Bupivacaine","brand": "Marcaine","aka": ["Marcaine","Sensorcaine","Bupivacaine Hydrochloride"],"cat": "Local Anesthetics","cls": "Local anesthetic, amide","mech": "Blocks sodium channels; longer duration than lidocaine","dose": "Infiltration: 0.25-0.5%; max 2.5 mg/kg without epi, 3 mg/kg with epi","ind": "Regional anesthesia, nerve blocks, epidural","contra": "Amide allergy, IV regional anesthesia (Bier block)","se": "Cardiotoxicity (more than lidocaine), CNS toxicity","notes": "NEVER use for IV regional anesthesia; long duration 4-8h","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "Bupivacaine should never be used for which technique?","choices": ["Epidural anesthesia","Peripheral nerve blocks","IV regional anesthesia (Bier block)","Local infiltration"],"answer": 2,"explain": "Bupivacaine is contraindicated in IV regional (Bier block) anesthesia due to its cardiotoxicity."}]},{"id": 15,"name": "Tetracaine","brand": "Pontocaine","aka": ["Amethocaine","Pontocaine"],"cat": "Local Anesthetics","cls": "Local anesthetic, ester","mech": "Blocks sodium channels; topical use primarily","dose": "Ophthalmic: 1-2 drops; Topical: varies by formulation","ind": "Ophthalmic anesthesia, topical anesthesia","contra": "Ester anesthetic allergy","se": "Corneal toxicity with prolonged use, local irritation","notes": "Primarily topical/ophthalmic use","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "What is a notable risk of prolonged topical tetracaine use on the eye?","choices": ["Glaucoma","Corneal toxicity","Retinal detachment","Cataract formation"],"answer": 1,"explain": "Prolonged ophthalmic tetracaine use can cause corneal toxicity, so it is for short-term use only."}]},{"id": 16,"name": "Moxifloxacin","brand": "Avelox","aka": ["Avelox","Vigamox"],"cat": "Antibiotics","cls": "Fluoroquinolone","mech": "Inhibits DNA gyrase and topoisomerase IV","dose": "400 mg PO/IV daily x 5-14 days","ind": "TCCC prophylaxis, respiratory infections, skin infections","contra": "Fluoroquinolone allergy, myasthenia gravis, QT prolongation","se": "QT prolongation, tendon rupture, C. diff, photosensitivity","notes": "TCCC FIRST-LINE oral antibiotic; broad coverage","tccc": true,"duty": "limited","scenarios": [{"scenario": "A 25-year-old attached support intel analyst is in a vehicle struck by an IED. A small piece of shrapnel has penetrated his right globe. He complains of severe eye pain and vision loss.","context": "Real-World Context: A penetrating globe injury is one of the most anxiety-inducing battlefield injuries for both the patient and the medic. The eye is essentially a sterile, fluid-filled sphere, and once its wall is breached, infection (endophthalmitis) can destroy any remaining vision within days. Think of the eye as a clean room with a hole punched in the wall — every bacterium that enters is a threat. Moxifloxacin is chosen specifically because it has outstanding penetration into ocular tissues (one of the few systemic antibiotics that achieves therapeutic levels inside the eye). The Fox Shield (rigid eye shield) is critical: never use a pressure patch, as any pressure on a ruptured globe will push more fluid out. Shielding BOTH eyes prevents sympathetic eye movement (when the good eye moves, the injured eye moves with it, potentially worsening the injury). The anti-emetic (Ondansetron) before pain management is a deliberate sequence — vomiting dramatically increases intraocular pressure and can expel the eye’s contents.","diagnosis": "The casualty has a Penetrating Globe Injury. The priorities are to prevent further injury, manage pain, and provide prophylactic antibiotics to prevent endophthalmitis.","opqrst": "Onset: Sudden, with the blast. Provocation: Eye movement. Quality: \"Sharp, intense pain.\" Radiation: Pain is in and around the right eye. Severity: 9/10. Time: Constant.","sample": "Signs/Symptoms: Visible metallic foreign body in the right eye, abnormal pupil shape, some loss of intraocular fluid, vision loss in the affected eye. Allergies: Penicillin (rash). Medications: None. Past Pertinent History: Wears corrective lenses. Last Oral Intake: Unknown. Events: IED blast.","vitals": "Heart Rate: 100 bpm | Blood Pressure: 145/85 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 100% on room air | Temperature: 98.6°F","exam": "Visual acuity test (if possible). Inspect the eye without applying pressure. Apply a rigid eye shield (Fox Shield) to the affected eye. Also shield the uninjured eye to prevent sympathetic eye movement.","primary": "Moxifloxacin (Avelox) — 400 mg PO. Given as a broad-spectrum antibiotic. Confirm no allergies to fluoroquinolones.","alternative": "If the patient cannot take oral meds, Ceftriaxone (2g IV) or Ertapenem (1g IV). Given the penicillin allergy, Ertapenem is a safer IV choice.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Which oral antibiotic is the TCCC first-line agent for a casualty who can tolerate PO?","choices": ["Doxycycline","Moxifloxacin 400 mg daily","Amoxicillin/clavulanate","Cephalexin"],"answer": 1,"explain": "Moxifloxacin 400 mg PO daily is the TCCC first-line oral antibiotic with broad coverage."},{"q": "Moxifloxacin is contraindicated in a patient with which condition?","choices": ["Hypertension","Myasthenia gravis","Asthma","Hypothyroidism"],"answer": 1,"explain": "As a fluoroquinolone, moxifloxacin is contraindicated in myasthenia gravis and with QT prolongation."}]},{"id": 17,"name": "Ertapenem","brand": "Invanz","aka": ["Invanz"],"cat": "Antibiotics","cls": "Carbapenem","mech": "Inhibits cell wall synthesis by binding PBPs","dose": "1 g IV/IM q24h (IM: reconstitute with 1% lidocaine)","ind": "TCCC prophylaxis (abdominal trauma), severe infections","contra": "Carbapenem/beta-lactam allergy, lidocaine allergy (IM)","se": "Diarrhea, nausea, headache, seizures (high doses)","notes": "TCCC IV/IM option; excellent anaerobic coverage; once daily","tccc": true,"duty": "limited","scenarios": [{"scenario": "A 35-year-old Special Forces medic is treating a local partner force soldier who sustained a penetrating abdominal injury from shrapnel 8 hours ago during a remote patrol. The soldier is now febrile, tachycardic, and has a rigid, tender abdomen, indicating peritonitis.","context": "Real-World Context: A penetrating abdominal injury that goes 8 hours without surgical intervention is a guaranteed peritonitis case — gut contents (bacteria, digestive enzymes, fecal matter) have been spilling into the sterile abdominal cavity, creating a polymicrobial infection of staggering complexity. Think of it as a sewage spill inside a clean room. The bacterial cocktail includes E. coli, Klebsiella, Bacteroides, and dozens of other species that require broad-spectrum firepower to cover. Ertapenem is the field medic’s dream antibiotic for this scenario: a carbapenem (“the nuclear option” of antibiotics) that covers virtually every aerobic AND anaerobic organism found in the gut, all in a single once-daily dose. That dosing advantage is enormous in a field setting — compared to the alternative of running two separate IV antibiotics on different schedules while managing a critically ill patient on a remote patrol. The IM route is available if IV access is lost, making it even more field-friendly.","diagnosis": "The patient has Septic Shock secondary to Peritonitis from a perforated bowel. This requires a powerful, broad-spectrum antibiotic that covers a wide range of gut flora (aerobes and anaerobes).","opqrst": "Patient is moaning in pain, guarding his abdomen, and has a decreased level of consciousness.","sample": "Signs/Symptoms: Fever, tachycardia, hypotension, rigid and diffusely tender abdomen, signs of sepsis. Allergies: Unknown. Medications: Has received morphine for pain. Past Pertinent History: Unknown. Last Oral Intake: >8 hours ago. Events: Penetrating abdominal trauma with delayed medical care.","vitals": "Heart Rate: 130 bpm | Blood Pressure: 90/50 mmHg | Respiratory Rate: 26 breaths/min | SpO2: 94% on room air | Temperature: 102.5°F","exam": "Abdominal exam reveals rebound tenderness and involuntary guarding. Bowel sounds are absent.","primary": "Invanz (Ertapenem) — 1g IV or IM, once a day. A carbapenem antibiotic ideal for this scenario because it has excellent broad-spectrum coverage and its once-a-day dosing is highly advantageous in a field setting.","alternative": "A combination of Ceftriaxone (for gram-negatives) PLUS Metronidazole (for anaerobes). Effective but requires administering two separate drugs.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario": "A 29-year-old male Ranger underwent an emergency appendectomy two days ago at a forward facility. He now presents with a high fever, chills, and worsening, diffuse abdominal pain. His surgical incision site is red, warm, and draining purulent fluid.","context": "Real-World Context: Post-operative intra-abdominal infections in austere environments are a worst-case scenario: the patient has already been weakened by surgery, the wound was made in less-than-ideal conditions, and the bacteria are now established behind the body’s defenses. Think of it as an enemy force that has breached the perimeter and is now fortified inside the wire. The purulent drainage and failure of oral antibiotics (he’s vomiting them up) signals escalation — this infection is winning, and you need to bring in heavier weapons delivered by a route that bypasses the GI tract entirely. Ertapenem IV is the heavy artillery: broad-spectrum, once-daily, and effective against the mixed aerobic-anaerobic flora that characterize post-surgical abdominal infections. The third option listed, Moxifloxacin, is a useful fallback because it’s a single IV drug with reasonable intra-abdominal coverage, though not as comprehensive as a carbapenem.","diagnosis": "This casualty is showing signs of a post-operative Complicated Intra-abdominal Infection and is developing Sepsis. The priority is broad-spectrum antibiotic coverage and fluid resuscitation.","opqrst": "Onset: Pain has gradually worsened over the past 24 hours. Provocation: Worse with any movement or palpation. Quality: \"Deep, constant, and aching.\" Radiation: Diffuse across the lower abdomen but centered on the right lower quadrant. Severity: 8/10. Time: Constant and worsening.","sample": "Signs/Symptoms: Fever, chills, abdominal tenderness with guarding, foul-smelling drainage from the surgical site. Allergies: NKDA. Medications: Was prescribed oral antibiotics but has been unable to keep them down. Past Pertinent History: Appendectomy 2 days prior. Last Oral Intake: Vomited sips of water 1 hour ago. Events: Post-operative period complicated by infection.","vitals": "Heart Rate: 115 bpm | Blood Pressure: 100/60 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 96% on room air | Temperature: 102.8°F","exam": "Abdominal exam for tenderness, rebound tenderness, and guarding. Assessment of the surgical wound for signs of infection. Cardiovascular exam for signs of sepsis.","primary": "","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Ertapenem is the TCCC IV/IM antibiotic of choice particularly for which injury?","choices": ["Isolated extremity gunshot","Penetrating abdominal trauma","Facial burns","Eye injury"],"answer": 1,"explain": "Ertapenem offers excellent anaerobic coverage, making it preferred for penetrating abdominal trauma."},{"q": "When giving ertapenem by the IM route, it is reconstituted with what?","choices": ["Sterile water only","1% lidocaine","Normal saline only","Dextrose 5%"],"answer": 1,"explain": "IM ertapenem is reconstituted with 1% lidocaine, so lidocaine allergy is a contraindication for IM use."}]},{"id": 18,"name": "Amoxicillin/Clavulanate","brand": "Augmentin","aka": ["Co-amoxiclav","Augmentin"],"cat": "Antibiotics","cls": "Aminopenicillin + beta-lactamase inhibitor","mech": "Amoxicillin inhibits cell wall synthesis; clavulanate inhibits beta-lactamases","dose": "500 mg q8h or 875 mg q12h PO x 5-7 days","ind": "Bite wounds, diabetic foot, otitis media, sinusitis, pneumonia","contra": "Penicillin/beta-lactam allergy, cholestatic jaundice with prior use","se": "Diarrhea, nausea, rash, C. diff, hepatotoxicity","notes": "Good for polymicrobial infections; covers oral flora","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "What does the clavulanate component of amoxicillin/clavulanate contribute?","choices": ["Inhibition of bacterial protein synthesis","Inhibition of beta-lactamases","Antifungal activity","Pseudomonal coverage"],"answer": 1,"explain": "Clavulanate inhibits beta-lactamases, extending amoxicillin's spectrum, useful for bite wounds and oral flora."}]},{"id": 19,"name": "Azithromycin","brand": "Zithromax","aka": ["Zithromax","Z-Pak","Azithromycin Dihydrate"],"cat": "Antibiotics","cls": "Macrolide","mech": "Inhibits protein synthesis at 50S ribosomal subunit","dose": "500 mg day 1, then 250 mg daily x 4 days; or 500 mg daily x 3 days","ind": "Respiratory infections, STIs, atypical pneumonia","contra": "Macrolide allergy, hepatic dysfunction with prior use","se": "GI upset, QT prolongation, hepatotoxicity","notes": "Z-pack; good atypical coverage","tccc": false,"duty": "go","scenarios": [{"scenario": "An attached Air Force intelligence analyst deployed to the Philippines develops profuse, watery diarrhea, abdominal cramping, and low-grade fever after eating from a local food stall two days ago. He is having 8–10 bowel movements a day and is starting to feel weak and dehydrated.","context": "Real-World Context: Traveler’s diarrhea is the single most common illness among deployed personnel in the developing world — think of it as the body’s alarm system when foreign bacteria hijack the gut. In Southeast Asia specifically, fluoroquinolone resistance is rampant (Cipro won’t work reliably), making Azithromycin the go-to. A single 500 mg dose can knock out E. coli, Shigella, and Campylobacter, dramatically shortening illness from 5–7 days to 1–2. The real danger isn’t the diarrhea itself — it’s the dehydration. An intelligence analyst who is cognitively impaired from fluid loss is operationally useless. Aggressive oral rehydration alongside the antibiotic is the one-two punch.","diagnosis": "This is a classic case of moderate to severe Traveler’s Diarrhea, likely from a bacterial source like E. coli, Shigella, or Campylobacter. The goal is to reduce the duration of illness and prevent dehydration.","opqrst": "Onset: Gradual, over 24 hours. Provocation: Eating or drinking. Quality: \"Watery and explosive\" diarrhea with \"crampy\" abdominal pain. Radiation: Abdominal cramps are diffuse. Severity: 7/10 distress. Time: Constant.","sample": "Signs/Symptoms: Watery diarrhea (no blood), abdominal cramping, malaise, fever. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Consumed questionable food/water.","vitals": "Heart Rate: 98 bpm | Blood Pressure: 115/75 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% | Temperature: 100.8°F","exam": "Assess for dehydration (tachycardia, dry mucous membranes, decreased skin turgor). Abdominal exam reveals hyperactive bowel sounds and mild diffuse tenderness.","primary": "Azithromycin — 500 mg PO as a single dose. Highly effective for many causes of traveler’s diarrhea, especially in Southeast Asia where fluoroquinolone resistance is common.","alternative": "Fluoroquinolones (e.g., Ciprofloxacin): 500 mg PO twice a day for 1–3 days. A good option in other parts of the world. Loperamide (Imodium): For symptomatic relief as long as the patient does not have high fever or bloody stool.","avoid": "","dutyStatus": "MISSION CAPABLE. No duty restrictions from the medication itself; the underlying illness may limit readiness.","onsetDuration": "Onset: Therapeutic levels within 2–3 hours. Duration: Tissue levels persist for 5+ days after the last dose.","cognitive": "None.","field": "Ordering by the bottle (30-count) rather than Z-Packs saves significant cost and pack space. The long tissue half-life means a short 1–3 day course is effective. GI side effects (nausea, cramping) may temporarily worsen before improvement."},{"scenario": "A 23-year-old female Air Force support analyst presents to the medic with a 5-day history of mild lower abdominal discomfort and a change in vaginal discharge. She is sexually active and concerned about an STI.","context": "Real-World Context: STIs are a persistent readiness issue across all branches. Chlamydia in particular is a “silent saboteur” — it’s often asymptomatic for weeks and can cause permanent fertility damage if untreated. The beauty of the Azithromycin 1g single-dose regimen is compliance: in a deployed or field environment, asking someone to remember a 7-day twice-daily Doxycycline course is asking for treatment failure. One dose, observed by the medic, and you know it’s done. A practical supply tip: order Azithromycin in bulk bottles rather than the pre-packaged 6-pill Z-Packs. The cost per dose drops dramatically, and you get far more flexibility in dosing for different conditions.","diagnosis": "This presentation is highly suspicious for a Sexually Transmitted Infection (STI), most commonly Chlamydia. Treatment is often presumptive based on clinical signs and history.","opqrst": "Onset: 5 days ago. Provocation: None. Quality: \"Dull ache.\" Radiation: None. Severity: 3/10. Time: Intermittent.","sample": "Signs/Symptoms: Mucopurulent discharge, lower abdominal ache, reports painful urination (dysuria). Allergies: NKDA. Medications: Oral contraceptives. Past Pertinent History: None. Last Oral Intake: Normal. Events: Unprotected sexual contact with a new partner.","vitals": "Heart Rate: 72 bpm | Blood Pressure: 118/70 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 100% on room air | Temperature: 99.1°F","exam": "Pelvic exam may reveal cervical motion tenderness and mucopurulent discharge. Abdominal exam to rule out other causes. Urine or swab sample for STI testing.","primary": "Azithromycin — 1g (1000 mg) PO as a single dose. Preferred regimen for its simplicity and high efficacy for uncomplicated chlamydia.","alternative": "Doxycycline — 100 mg PO twice a day for 7 days. Also highly effective but requires a longer course of treatment.","avoid": "","dutyStatus": "FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration": "Single 1g dose provides therapeutic tissue levels for 5+ days.","cognitive": "None.","field": "Single-dose observed therapy ensures compliance. Partner notification and treatment is essential to prevent reinfection. Dual treatment with Ceftriaxone is standard when treating presumptively for both Chlamydia and Gonorrhea."}],"quiz": [{"q": "Azithromycin exerts its antibacterial effect by","choices": ["Inhibiting DNA gyrase","Inhibiting cell wall synthesis","Inhibiting protein synthesis at the 50S subunit","Disrupting folate synthesis"],"answer": 2,"explain": "As a macrolide, azithromycin binds the 50S ribosomal subunit to inhibit protein synthesis."}]},{"id": 20,"name": "Cefazolin","brand": "Ancef","aka": ["Ancef","Kefzol","Cefazolin Sodium"],"cat": "Antibiotics","cls": "First-generation cephalosporin","mech": "Inhibits bacterial cell wall synthesis","dose": "1-2 g IV q8h","ind": "Surgical prophylaxis, skin infections, bone infections","contra": "Cephalosporin allergy (caution with penicillin allergy)","se": "Diarrhea, rash, eosinophilia","notes": "Surgical prophylaxis standard; gram-positive coverage","tccc": false,"duty": "go","scenarios": [{"scenario": "A SARC medic is preparing to perform a field surgical procedure (a fasciotomy) on a Ranger with acute compartment syndrome in his lower leg. To prevent post-operative infection, the medic needs to administer a prophylactic antibiotic before making the first incision.","context": "Real-World Context: Compartment syndrome is a ticking clock — think of it as a tourniquet being applied from the inside. Swelling within the rigid fascial compartment compresses blood vessels and nerves, and irreversible muscle death begins within 6 hours. A field fasciotomy is one of the most aggressive procedures a SOF medic may perform, and the sterile field is, at best, compromised. Cefazolin is the “standard pre-op shield” for surgical prophylaxis — a first-generation cephalosporin that blankets the skin flora (Staph and Strep) that are the primary culprits for surgical site infections. The timing is critical: it must be in the bloodstream BEFORE the knife touches skin, which means administration within 60 minutes of incision to achieve adequate tissue levels.","diagnosis": "The patient requires an emergent Fasciotomy. A key step in preventing a post-surgical infection is the administration of Pre-operative Prophylactic Antibiotics.","opqrst": "Patient has severe, deep pain in his lower leg, unresponsive to analgesia. \"Pain out of proportion\" to the visible injury.","sample": "Signs/Symptoms: Tense, swollen, and shiny lower leg; severe pain with passive stretch of the toes. Allergies: NKDA. Medications: Has received Ketamine for pain. Past Pertinent History: Blunt trauma to the leg 2 hours ago. Last Oral Intake: 4 hours ago. Events: Developing compartment syndrome requiring surgical intervention.","vitals": "Heart Rate: 110 bpm | Blood Pressure: 140/85 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 99%","exam": "Palpation of a rock-hard muscle compartment. Loss of sensation between the first and second toes. Weak or absent distal pulses (a late sign).","primary": "Cefazolin (Ancef) — 2g IV/IO administered within 60 minutes before the initial incision. A first-generation cephalosporin with excellent activity against skin flora like Staphylococcus and Streptococcus.","alternative": "Clindamycin or Vancomycin. These are used if the patient has a significant allergy to cephalosporins/penicillins.","avoid": "","dutyStatus": "FULLY MISSION CAPABLE after administration.","onsetDuration": "Onset: Rapid IV/IM. Must be given within 60 minutes before surgical incision.","cognitive": "None.","field": "Requires IV/IM administration and cold chain storage for reconstituted solution. For field surgical procedures, have it drawn up and ready before prep begins. The timing window (within 60 min pre-incision) is a hard requirement for surgical prophylaxis effectiveness."}],"quiz": [{"q": "Cefazolin is most commonly used clinically for","choices": ["Pseudomonal pneumonia","Surgical prophylaxis and gram-positive skin infections","Anaerobic abdominal infections","Atypical pneumonia"],"answer": 1,"explain": "Cefazolin, a first-generation cephalosporin, is the standard for surgical prophylaxis with gram-positive coverage."}]},{"id": 21,"name": "Ceftriaxone","brand": "Rocephin","aka": ["Rocephin","Ceftriaxone Sodium"],"cat": "Antibiotics","cls": "Third-generation cephalosporin","mech": "Inhibits bacterial cell wall synthesis","dose": "1-2 g IV/IM q12-24h (meningitis: 2 g IV q12h)","ind": "Severe infections, meningitis, gonorrhea, pneumonia","contra": "Cephalosporin/penicillin allergy, neonates with hyperbilirubinemia","se": "Diarrhea, rash, biliary sludge","notes": "Do NOT mix with calcium-containing solutions; good CNS penetration","tccc": false,"duty": "go","scenarios": [{"scenario": "A 21-year-old male Ranger presents with a 2-day history of painful urination and a thick, yellowish discharge from his penis. He reports unprotected sexual contact about a week ago.","context": "Real-World Context: Gonorrhea is one of the “old soldiers” of infectious disease — it has been a readiness problem since before antibiotics existed. The thick, purulent discharge is virtually diagnostic. Ceftriaxone IM is the standard of care because gonorrhea has systematically developed resistance to nearly every other antibiotic class over the decades; think of it as an arms race where this cephalosporin is currently our best remaining weapon. The dual-treatment approach (Ceftriaxone for gonorrhea PLUS Azithromycin or Doxycycline for the assumed chlamydia co-infection) reflects the reality that these two infections travel together like a package deal in roughly 40% of cases. The clinical pearl on reconstituting Rocephin with 1% Lidocaine is gold — this injection is notoriously painful, and the Lidocaine makes it far more tolerable.","diagnosis": "This is a classic presentation for Gonorrhea, a common STI. Due to high rates of co-infection, patients are almost always treated for both Gonorrhea and Chlamydia.","opqrst": "Onset: 2 days ago. Provocation: During urination. Quality: \"Burning pain.\" Radiation: Localized to the urethra. Severity: 7/10. Time: Only with urination.","sample": "Signs/Symptoms: Purulent urethral discharge, dysuria (painful urination). Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Normal. Events: Unprotected sexual contact.","vitals": "Heart Rate: 70 bpm | Blood Pressure: 122/76 mmHg | Respiratory Rate: 12 breaths/min | SpO2: 100% on room air | Temperature: 99.0°F","exam": "Examination of the genitalia reveals purulent discharge from the urethral meatus. Urine or swab sample collected for testing.","primary": "Ceftriaxone (Rocephin) — 250 mg as a single IM injection. This is the standard of care for uncomplicated gonorrhea.","alternative": "","avoid": "","dutyStatus": "FULLY MISSION CAPABLE after injection.","onsetDuration": "Onset: Rapid IM absorption. Duration: Long half-life provides sustained therapeutic levels.","cognitive": "None.","field": "Reconstitute with 3.2 mL of 1% Lidocaine (not sterile water) to reduce injection pain. Requires IM injection technique. Must be used with Azithromycin for dual coverage. Refrigerate reconstituted solution if not used immediately."}],"quiz": [{"q": "Ceftriaxone must NOT be co-administered with which type of solution?","choices": ["Normal saline","Calcium-containing solutions","Dextrose solutions","Lactated Ringer's free of calcium"],"answer": 1,"explain": "Ceftriaxone should not be mixed with calcium-containing solutions due to precipitation risk."}]},{"id": 22,"name": "Cephalexin","brand": "Keflex","aka": ["Keflex","Cefalexin","Cephalexin Monohydrate"],"cat": "Antibiotics","cls": "First-generation cephalosporin","mech": "Inhibits bacterial cell wall synthesis","dose": "250-500 mg PO q6h or 500 mg PO q12h","ind": "Skin infections, UTI, strep pharyngitis","contra": "Cephalosporin allergy","se": "GI upset, rash, C. diff","notes": "Oral option for mild skin infections; MSSA coverage","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "Cephalexin is an appropriate oral choice for which infection?","choices": ["Pseudomonal pneumonia","Mild MSSA skin infection or strep pharyngitis","MRSA bacteremia","Anaerobic abscess"],"answer": 1,"explain": "Cephalexin, a first-generation cephalosporin, covers MSSA and is used for mild skin infections and strep throat."}]},{"id": 23,"name": "Ciprofloxacin","brand": "Cipro","aka": ["Cipro","Ciproxin","Ciprofloxacin Hydrochloride"],"cat": "Antibiotics","cls": "Fluoroquinolone","mech": "Inhibits DNA gyrase and topoisomerase IV","dose": "250-750 mg PO q12h or 200-400 mg IV q12h","ind": "UTI, travelers diarrhea, anthrax prophylaxis, pseudomonal infections","contra": "Fluoroquinolone allergy, myasthenia gravis","se": "Tendon rupture, QT prolongation, CNS effects","notes": "Excellent gram-negative/pseudomonal coverage","tccc": false,"duty": "go","scenarios": [{"scenario": "A 26-year-old female Air Force SERE Instructor presents with a 2-day history of increased urinary frequency, urgency, and a burning sensation upon urination. She has no fever or back pain.","context": "Real-World Context: UTIs are among the most common medical complaints for female service members in austere environments, where hygiene opportunities are limited, hydration may be inadequate, and holding urine during operations is often unavoidable. Think of the urinary tract as a one-way river — bacteria try to swim upstream, and anything that slows the flow (dehydration, holding it) gives them a foothold. Cipro is a powerful fluoroquinolone that concentrates heavily in the urine, making it highly effective for UTIs. The critical detail here is the Sulfa allergy — Bactrim (TMP-SMX), which is normally a first-line UTI treatment, is off the table. A negative CVA tenderness exam is your clinical guardrail confirming this is a lower tract infection (bladder) and hasn’t ascended to the kidneys, which would change the urgency and treatment significantly.","diagnosis": "The patient has an Uncomplicated Urinary Tract Infection (UTI), also known as cystitis. Given her allergy to sulfa drugs, Bactrim is contraindicated.","opqrst": "Onset: 2 days ago. Provocation: Urination. Quality: \"Burning.\" Radiation: None. Severity: 6/10. Time: Only with urination.","sample": "Signs/Symptoms: Dysuria, urinary frequency, and urgency. Allergies: Sulfa drugs (causes a rash). Medications: None. Past Pertinent History: Has had UTIs before. Last Oral Intake: Drinking lots of water. Events: Spontaneous onset of symptoms.","vitals": "Heart Rate: 76 bpm | Blood Pressure: 115/70 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 99.2°F","exam": "Abdomen is soft and non-tender. No costovertebral angle (CVA) tenderness, which argues against a kidney infection. A urine dipstick test is positive for nitrites and leukocyte esterase.","primary": "Ciprofloxacin (Cipro) — 500 mg PO twice a day for 3 days. A fluoroquinolone that is very effective for UTIs, though resistance is growing.","alternative": "Nitrofurantoin (Macrobid): 100 mg PO twice a day for 5 days. Excellent choice, but not effective if there is suspicion for a kidney infection. Keflex (Cephalexin): Another good option, especially if local resistance patterns for Cipro are high.","avoid": "","dutyStatus": "MISSION CAPABLE. Rare risk of tendon rupture (Achilles) with heavy physical activity.","onsetDuration": "Onset: 1–2 hours PO. Full course: 3–7 days depending on indication.","cognitive": "Minimal. Rare CNS effects (dizziness, headache).","field": "FDA black box warning for tendon rupture and peripheral neuropathy — operators performing high-impact activities should be counseled. Avoid concurrent use with antacids or calcium supplements (reduces absorption). Reserve for confirmed indications to support antibiotic stewardship."}],"quiz": [{"q": "Ciprofloxacin is especially valued for coverage of which organisms?","choices": ["Anaerobes","Gram-negative and pseudomonal organisms","MRSA","Atypical fungi"],"answer": 1,"explain": "Ciprofloxacin provides excellent gram-negative and pseudomonal coverage."}]},{"id": 24,"name": "Clindamycin","brand": "Cleocin","aka": ["Cleocin","Dalacin","Clindamycin Hydrochloride"],"cat": "Antibiotics","cls": "Lincosamide","mech": "Inhibits protein synthesis at 50S ribosomal subunit","dose": "150-450 mg PO q6h or 600-900 mg IV q8h","ind": "Skin infections, osteomyelitis, dental infections, MRSA, necrotizing fasciitis","contra": "History of C. diff colitis","se": "C. diff colitis (HIGH RISK), diarrhea","notes": "ADD to beta-lactam for necrotizing infections; covers MRSA","tccc": false,"duty": "go","scenarios": [{"scenario": "A 30-year-old Ranger develops a rapidly spreading, painful red rash on his lower leg starting from a small cut he got 2 days ago. The area is swollen, hot to the touch, and he has a fever. He has a severe allergy to Penicillin (anaphylaxis).","context": "Real-World Context: Cellulitis in the field spreads like a wildfire — what starts as a minor scrape becomes a limb-threatening infection within 24–48 hours if the body’s defenses are overwhelmed. Marking the borders of the redness with a pen is one of the most important field assessment techniques: it turns a subjective observation (“it looks worse”) into an objective measurement (“it’s advanced 3cm past the line in 6 hours”). Clindamycin is the “go-to detour” for penicillin-allergic patients — it covers the gram-positive organisms (Staph and Strep) that cause most cellulitis without crossing the penicillin allergy bridge. An added benefit: Clindamycin inhibits toxin production, which matters in aggressive Strep infections where bacterial toxins are causing much of the tissue damage.","diagnosis": "The patient has Cellulitis, a common bacterial skin infection, likely caused by Staphylococcus or Streptococcus. Due to his severe penicillin allergy, cephalosporins (like Cefazolin or Keflex) are also contraindicated.","opqrst": "Onset: Redness began yesterday and has rapidly expanded. Provocation: Touch. Quality: \"Hot and aching.\" Radiation: Spreading up the leg from the ankle. Severity: 6/10. Time: Constant.","sample": "Signs/Symptoms: Expanding erythema with poorly defined borders, swelling, warmth, tenderness. Red streaks may be visible (lymphangitis). Allergies: Severe Penicillin allergy. Medications: None. Past Pertinent History: None. Last Oral Intake: Normal. Events: Skin infection following minor trauma.","vitals": "Heart Rate: 105 bpm | Blood Pressure: 128/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 101.5°F","exam": "Mark the borders of the redness with a pen to track progression. Palpate for tenderness and crepitus (gas in the tissue, a sign of severe infection).","primary": "Clindamycin — 300–450 mg PO four times a day. Excellent activity against the gram-positive organisms that cause most cases of cellulitis and is a go-to for penicillin-allergic patients.","alternative": "Doxycycline or Trimethoprim-Sulfamethoxazole (Bactrim): Also good options, especially if there is concern for MRSA.","avoid": "","dutyStatus": "FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration": "Onset: 1–2 hours PO, faster IV/IM. Full course: 7–10 days.","cognitive": "None.","field": "Excellent option for penicillin-allergic patients. Monitor daily for progression of cellulitis (mark borders with pen). Risk of C. difficile colitis with prolonged use — if the patient develops severe diarrhea during treatment, suspect C. diff and adjust."}],"quiz": [{"q": "What is the highest-risk adverse effect of clindamycin?","choices": ["Tendon rupture","C. difficile colitis","QT prolongation","Photosensitivity"],"answer": 1,"explain": "Clindamycin carries a high risk of C. difficile colitis and is contraindicated with prior C. diff."}]},{"id": 25,"name": "Doxycycline","brand": "Vibramycin","aka": ["Vibramycin","Doxycycline Hyclate","Doryx"],"cat": "Antibiotics","cls": "Tetracycline","mech": "Inhibits protein synthesis at 30S ribosomal subunit","dose": "100 mg PO/IV q12h","ind": "Tick-borne diseases, STIs, atypical pneumonia, malaria prophylaxis","contra": "Pregnancy, children <8 years","se": "Photosensitivity, GI upset, esophageal ulceration","notes": "Take with water, remain upright; covers Rickettsia, Chlamydia","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 25-year-old Special Forces medic is bitten by a tick during a patrol in a wooded area of the eastern United States. He removed the tick several hours later. The next day, he develops fever, chills, a severe headache, and muscle aches.","context": "Real-World Context: Tick-borne illnesses are the unseen enemy of the American wilderness — and for SOF units training in places like Fort Liberty, Camp Merrill, or the Mountain Phase of Ranger School, tick bites are nearly unavoidable. Doxycycline is the undisputed champion for tick-borne diseases, covering Rocky Mountain Spotted Fever, Ehrlichiosis, Anaplasmosis, and Lyme Disease. Think of it as the “universal key” that opens every tick-borne lock. The urgency with RMSF cannot be overstated: untreated, it has a mortality rate of 20–25%, and delay of even a few days in starting Doxycycline dramatically increases the risk of death. The classic rash (starting on wrists/ankles and spreading centrally, eventually involving palms and soles) is a helpful clue, but treatment should NEVER wait for the rash — it may not appear for days, and some patients never develop it. The clinical mantra: if a patient in a tick-endemic area presents with fever, headache, and myalgias, start Doxycycline immediately and sort out the specific diagnosis later.","diagnosis": "Given the history of a tick bite and the clinical presentation (fever, headache, myalgias), this is highly suspicious for a tick-borne illness, most emergently Rocky Mountain Spotted Fever (RMSF). Treatment should be started immediately based on suspicion.","opqrst": "Onset: Gradual over the past 24 hours. Provocation: None. Quality: \"Aching all over,\" with a \"splitting\" headache. Radiation: Headache is global. Severity: 8/10. Time: Constant.","sample": "Signs/Symptoms: Fever, chills, severe headache, myalgias (muscle aches). A faint rash may be starting to appear on his wrists and ankles. Allergies: NKDA. Medications: None. Past Pertinent History: Known tick bite yesterday. Last Oral Intake: Decreased appetite. Events: Onset of symptoms after a tick bite.","vitals": "Heart Rate: 100 bpm | Blood Pressure: 115/70 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 97% on room air | Temperature: 102.8°F","exam": "Carefully inspect the skin for any rash, particularly on the palms and soles. Perform a basic neurological exam.","primary": "Doxycycline — 100 mg PO twice a day for 7–14 days. The drug of choice for nearly all rickettsial (tick-borne) diseases, including RMSF, Ehrlichiosis, and Lyme Disease. Delaying treatment for RMSF can be fatal.","alternative": "There are no good alternatives to Doxycycline for RMSF. In rare cases (e.g., severe allergy in a non-pregnant patient), Chloramphenicol might be considered, but it is a distant second choice.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What counseling point is important when prescribing oral doxycycline?","choices": ["Take at bedtime lying flat","Take with water and remain upright to avoid esophageal ulceration","Take with antacids","Avoid all sunlight permanently"],"answer": 1,"explain": "Doxycycline can cause esophageal ulceration, so it is taken with water while remaining upright."}]},{"id": 26,"name": "Levofloxacin","brand": "Levaquin","aka": ["Levaquin","Tavanic"],"cat": "Antibiotics","cls": "Fluoroquinolone","mech": "Inhibits DNA gyrase and topoisomerase IV","dose": "750 mg PO/IV daily x 5-14 days","ind": "Respiratory infections, UTI, skin infections","contra": "Fluoroquinolone allergy, myasthenia gravis","se": "Tendon rupture, QT prolongation, peripheral neuropathy","notes": "Once daily dosing; broad spectrum","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 55-year-old local village elder presents to a MEDCAP with a 4-day history of worsening cough, shortness of breath, and fever. He looks tired and is breathing more rapidly than normal. He has a history of smoking.","context": "Real-World Context: Community-acquired pneumonia in an older smoker is a bread-and-butter diagnosis during MEDCAPs in developing nations — limited healthcare access means these patients present later and sicker than they would in the U.S. Levofloxacin is called a “respiratory fluoroquinolone” because it was practically designed for lung infections. Think of it as a skeleton key that opens every common pneumonia lock: Streptococcus pneumoniae (the classic bacterial cause), Haemophilus influenzae (common in smokers), and the atypical organisms like Mycoplasma and Legionella that standard penicillins miss entirely. The once-daily dosing is a MEDCAP advantage — you can watch the patient take the first dose and send them home with a simple regimen. The SpO2 of 91% is concerning and suggests significant lung involvement; if available, supplemental oxygen should be considered. A smoker’s damaged mucociliary escalator means bacterial clearance is already compromised, making antibiotics even more critical.","diagnosis": "This is a presentation of Community-Acquired Pneumonia (CAP) in an older adult with comorbidities (smoking). He requires an antibiotic with broad coverage against common respiratory pathogens.","opqrst": "Onset: 4 days ago. Provocation: Exertion. Quality: \"Wet, heavy cough.\" Radiation: Chest discomfort. Severity: 6/10. Time: Worsening daily.","sample": "Signs/Symptoms: Productive cough (yellow sputum), shortness of breath, fever, fatigue. Allergies: Unknown. Medications: None. Past Pertinent History: Long-time smoker. Last Oral Intake: Poor appetite. Events: Developing a lung infection.","vitals": "Heart Rate: 105 bpm | Blood Pressure: 130/80 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 91% on room air | Temperature: 101.9°F","exam": "Auscultation of the lungs reveals decreased breath sounds and crackles (rales) in the right lower lobe.","primary": "Levofloxacin (Levaquin) — 750 mg PO once a day for 5–7 days. A “respiratory fluoroquinolone” with excellent activity against S. pneumoniae, H. influenzae, and atypical pathogens like Mycoplasma and Legionella.","alternative": "Moxifloxacin (Avelox): Another respiratory fluoroquinolone. Augmentin PLUS a macrolide like Azithromycin.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "A practical dosing advantage of levofloxacin is that it is given","choices": ["Four times daily","Once daily","Every 6 hours","Only intravenously"],"answer": 1,"explain": "Levofloxacin is dosed once daily with broad spectrum coverage."}]},{"id": 27,"name": "Metronidazole","brand": "Flagyl","aka": ["Flagyl","Metronidazole Benzoate","Metrogel"],"cat": "Antibiotics","cls": "Nitroimidazole antibiotic/antiprotozoal","mech": "Disrupts bacterial DNA; active against anaerobes","dose": "500 mg PO/IV q8h x 7-14 days","ind": "C. diff, giardiasis, trichomoniasis, anaerobic infections, H. pylori","contra": "Disulfiram within 2 weeks","se": "Metallic taste, nausea, peripheral neuropathy, disulfiram reaction","notes": "AVOID ALCOHOL; excellent anaerobic coverage","tccc": false,"duty": "limited","scenarios": [{"scenario": "During a long-term MEDCAP in a remote village with poor sanitation, several team members and locals develop prolonged, foul-smelling, greasy diarrhea, abdominal cramping, and excessive gas. They have been drinking from a local well.","context": "Real-World Context: Giardia is the “backpacker’s plague” and a deployment classic — the parasite lurks in contaminated water worldwide and is remarkably resilient (it forms cysts that survive standard water treatment if iodine or filtration isn’t used). Think of Giardia as a squatter that takes over the small intestine’s lining, blocking nutrient absorption like a parasite covering solar panels. The “greasy, foul-smelling” stool (steatorrhea) is the hallmark clue — fat isn’t being absorbed because the parasite has carpeted the intestinal villi. The “sulfur-smelling” burps are another classic sign. Metronidazole works by generating toxic free radicals inside the anaerobic parasite that damage its DNA. The CRITICAL patient education: absolutely NO alcohol during treatment and for 3 days after. Metronidazole blocks aldehyde dehydrogenase, the same enzyme that Antabuse (the alcohol-aversion drug) blocks. Drinking alcohol will trigger violent nausea, vomiting, flushing, and headache — a disulfiram-like reaction that makes a hungover morning look like a spa day.","diagnosis": "This cluster of symptoms is classic for Giardiasis, an intestinal infection caused by the protozoan parasite Giardia lamblia, often contracted from contaminated water.","opqrst": "Onset: Gradual, over the past week. Provocation: Eating. Quality: \"Greasy, foul\" diarrhea and \"sulfur-smelling\" burps. Radiation: Diffuse abdominal bloating and cramping. Severity: 6/10 discomfort. Time: Chronic, ongoing.","sample": "Signs/Symptoms: Steatorrhea (greasy stools), bloating, flatulence, malaise, weight loss. Allergies: Unknown. Medications: None. Past Pertinent History: None. Events: Outbreak of gastrointestinal illness in a group sharing a water source.","vitals": "Largely normal, may show signs of mild dehydration.","exam": "Abdomen is distended and tympanitic, with some mild diffuse tenderness.","primary": "Flagyl (Metronidazole) — 500 mg PO twice a day for 5–7 days. Very effective for Giardiasis. Patients MUST avoid all alcohol during and for 3 days after treatment to prevent a severe disulfiram-like reaction.","alternative": "Tinidazole (Tindamax): Often preferred as it can be given as a single 2g dose. Albendazole: Another effective anti-parasitic.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What critical instruction must patients on metronidazole follow?","choices": ["Avoid dairy products","Avoid alcohol","Avoid sunlight","Take only on an empty stomach"],"answer": 1,"explain": "Metronidazole causes a disulfiram-like reaction with alcohol, which must be avoided."}]},{"id": 28,"name": "Nitrofurantoin","brand": "Macrobid","aka": ["Macrobid","Macrodantin","Furadantin"],"cat": "Antibiotics","cls": "Nitrofuran antibiotic","mech": "Disrupts bacterial protein synthesis and cell wall","dose": "100 mg PO BID x 5-7 days","ind": "Uncomplicated UTI (bladder only)","contra": "Renal impairment, G6PD deficiency, pregnancy at term","se": "GI upset, pulmonary toxicity (chronic use)","notes": "UTI only; does NOT reach kidney","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 22-year-old female soldier presents to a MEDCAP complaining of a 3-day history of urinary burning and frequency. She is otherwise healthy. The medic performs a urine dipstick, which is positive for infection. She needs a first-line treatment that is not a fluoroquinolone or sulfa drug.","context": "Real-World Context: Nitrofurantoin is the “smart bomb” of UTI antibiotics — it concentrates almost exclusively in the bladder, delivering high local drug levels right where the infection lives while sparing the rest of the body’s microbiome. Think of it as a targeted airstrike on the bladder versus the carpet-bombing of broad-spectrum antibiotics like Cipro. This selectivity is why resistance rates remain remarkably low even after decades of use — the drug doesn’t hang around in the blood long enough to pressure bacteria elsewhere into developing resistance. It’s also why it ONLY works for lower UTIs (cystitis) and is useless for kidney infections (pyelonephritis) — it never reaches therapeutic levels in the kidneys or bloodstream. For deployed female service members, Macrobid is often preferred over Bactrim because sulfa allergies are relatively common and fluoroquinolone stewardship is important (saving Cipro for when you really need it).","diagnosis": "The patient has an Uncomplicated Urinary Tract Infection (Cystitis). Nitrofurantoin is an excellent first-line choice because it concentrates in the bladder and has low rates of resistance.","opqrst": "Onset: 3 days ago. Provocation: Urination. Quality: \"Burning.\" Radiation: None. Severity: 5/10. Time: Only with urination.","sample": "Signs/Symptoms: Dysuria, urinary frequency. No fever or flank pain. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Spontaneous onset.","vitals": "Within normal limits.","exam": "Abdomen is soft and non-tender. No CVA tenderness. Urine dipstick is positive for leukocyte esterase.","primary": "Macrobid (Nitrofurantoin) — 100 mg PO twice a day for 5 days.","alternative": "Trimethoprim-Sulfamethoxazole (Bactrim): Another first-line choice, but resistance is more common. Fosfomycin: A single-dose powder, also a good first-line option.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Nitrofurantoin is appropriate only for which type of infection?","choices": ["Pyelonephritis","Uncomplicated bladder UTI","Bacteremia","Pneumonia"],"answer": 1,"explain": "Nitrofurantoin does not reach the kidney, so it is used only for uncomplicated bladder UTIs."}]},{"id": 29,"name": "Penicillin G Benzathine","brand": "Bicillin","aka": ["Bicillin L-A","Benzathine Benzylpenicillin","Benzathine Penicillin G"],"cat": "Antibiotics","cls": "Natural penicillin","mech": "Inhibits bacterial cell wall synthesis","dose": "Strep: 1.2 million units IM x1; Syphilis: 2.4 million units IM","ind": "Group A strep pharyngitis, syphilis","contra": "Penicillin allergy","se": "Anaphylaxis, injection site pain","notes": "Long-acting depot form; single dose treatment","tccc": false,"duty": "limited","scenarios": [{"scenario": "A Navy Corpsman is at a training facility and diagnoses a 19-year-old Marine with a clear case of Strep Throat. The Marine is known to be non-compliant with taking medication. To ensure the infection is fully treated and prevent him from infecting the rest of his platoon, the Corpsman opts for a single-dose treatment.","context": "Real-World Context: Non-compliance is the Achilles’ heel of antibiotic therapy — a 19-year-old Marine who feels better after 3 days will stop taking a 10-day course of pills, leaving the Strep partially treated and the risk of rheumatic fever alive. Bicillin L-A is the “one and done” solution: a single deep IM injection of a long-acting penicillin formulation that creates a slow-release depot in the muscle, maintaining therapeutic levels for over a week. Think of it as a time-release capsule embedded in the muscle. The Corpsman watches the injection go in and knows with 100% certainty the full treatment has been delivered. In a barracks environment where Strep can tear through a platoon like wildfire, this also serves a public health function — the Marine is effectively non-infectious within 24 hours. The injection is notoriously thick and painful (it’s essentially injecting a suspension of penicillin crystals), so proper technique matters: use a large-gauge needle (18–21G), inject into the upper outer gluteal quadrant, and have the patient relax the muscle.","diagnosis": "The patient has Streptococcal Pharyngitis. Given concerns about treatment compliance, a long-acting, single-dose antibiotic is the ideal choice.","opqrst": "Onset: 3 days ago. Provocation: Swallowing. Quality: \"Sore and scratchy.\" Radiation: None. Severity: 6/10. Time: Constant.","sample": "Signs/Symptoms: Sore throat, tonsillar exudates, fever, tender cervical lymph nodes. Allergies: NKDA. Medications: None. Past Pertinent History: Has had strep throat before. Last Oral Intake: Water. Events: Positive rapid strep test.","vitals": "Heart Rate: 88 bpm | Blood Pressure: 128/76 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 100% | Temperature: 101.0°F","exam": "Classic findings of streptococcal pharyngitis.","primary": "Bicillin L-A (Penicillin G Benzathine) — 1.2 million units as a single deep IM injection. Provides a sustained therapeutic level of penicillin for over a week.","alternative": "A full 10-day course of oral Amoxicillin or Penicillin VK. If penicillin-allergic, a course of Azithromycin.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "A key feature of penicillin G benzathine is that it","choices": ["Requires four-times-daily oral dosing","Is a long-acting IM depot allowing single-dose treatment","Provides anaerobic coverage","Must be given IV over 24 hours"],"answer": 1,"explain": "Penicillin G benzathine is a long-acting IM depot used for single-dose treatment of strep and syphilis."}]},{"id": 30,"name": "Penicillin VK","brand": "Pen VK","aka": ["Penicillin V","Phenoxymethylpenicillin","Pen-Vee K"],"cat": "Antibiotics","cls": "Natural penicillin","mech": "Inhibits bacterial cell wall synthesis","dose": "500 mg PO q6h","ind": "Strep pharyngitis, skin infections, dental infections","contra": "Penicillin allergy","se": "Diarrhea, nausea, rash","notes": "Take on empty stomach; narrow gram-positive spectrum","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "How should oral penicillin VK be taken for best absorption?","choices": ["With a high-fat meal","On an empty stomach","With milk","With antacids"],"answer": 1,"explain": "Penicillin VK is taken on an empty stomach and covers a narrow gram-positive spectrum."}]},{"id": 31,"name": "Trimethoprim/Sulfamethoxazole","brand": "Bactrim/Septra","aka": ["Co-trimoxazole","Bactrim","Septra","TMP-SMX","Septrin"],"cat": "Antibiotics","cls": "Sulfonamide combination","mech": "Sequentially inhibits folate synthesis","dose": "1 DS tab (160/800 mg) PO BID","ind": "UTI, skin infections, MRSA, PCP prophylaxis","contra": "Sulfa allergy, severe renal impairment, pregnancy at term","se": "Rash, hyperkalemia, bone marrow suppression","notes": "Good MRSA coverage; check G6PD","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 29-year-old Ranger presents with a painful, swollen, red boil on his buttock that has been worsening for 3 days. The center is fluctuant and is starting to drain a small amount of pus.","context": "Real-World Context: Skin abscesses are practically an epidemic in military populations — close-quarters living, shared equipment, minor skin trauma, and sweat create perfect conditions for Staphylococcus aureus to set up shop. The critical evolution: community-acquired MRSA (CA-MRSA) has made standard anti-staph antibiotics like Keflex unreliable for skin abscesses. Bactrim fills this gap perfectly — think of it as the “anti-MRSA workhorse” of outpatient medicine. The drug combines two antibiotics (Trimethoprim and Sulfamethoxazole) that attack bacterial folate synthesis at two sequential steps, creating a synergistic kill. But the MOST important treatment is I&D (Incision and Drainage) — no antibiotic can penetrate the walled-off pus cavity effectively. The knife is the cure; the antibiotic prevents the infection from spreading into surrounding tissue. The hydration counseling isn’t optional: Bactrim can crystallize in the renal tubules and cause kidney stones if the patient doesn’t drink enough water.","diagnosis": "The patient has a Cutaneous Abscess. The primary treatment is I&D. Antibiotics are added because of the size and associated cellulitis, and coverage for MRSA is essential.","opqrst": "Onset: 3 days ago. Provocation: Sitting, pressure. Quality: \"Aching, pressure.\" Radiation: None. Severity: 7/10. Time: Worsening.","sample": "Signs/Symptoms: A tender, erythematous, fluctuant abscess. Allergies: NKDA. Medications: None. Past Pertinent History: Has had similar boils before. Events: Skin abscess.","vitals": "Temperature: 99.8°F. Other vitals normal.","exam": "A 3cm abscess is noted on the right buttock. The primary treatment is Incision & Drainage (I&D).","primary": "Bactrim (TMP/SMX) — 1–2 Double Strength (DS) tablets PO twice a day for 5–10 days. Provides excellent coverage for community-acquired MRSA.","alternative": "Doxycycline or Clindamycin are also excellent choices for MRSA coverage.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Trimethoprim/sulfamethoxazole is a useful oral option for which resistant organism?","choices": ["Pseudomonas","MRSA","Anaerobes","Candida"],"answer": 1,"explain": "TMP-SMX provides good MRSA coverage and is used for skin infections and PCP prophylaxis."}]},{"id": 32,"name": "Bacitracin","brand": "Bacitracin","aka": ["Baciguent","Bacitracin Zinc"],"cat": "Topical/Ophthalmic/Otic","cls": "Topical polypeptide antibiotic","mech": "Inhibits bacterial cell wall synthesis","dose": "Apply to affected area 1-3 times daily","ind": "Minor cuts, wounds, burns prophylaxis","contra": "Hypersensitivity","se": "Local irritation, allergic reaction","notes": "Topical use only; do not use near eyes","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "What is an appropriate use of topical bacitracin?","choices": ["Systemic skin infection","Prophylaxis of minor cuts and burns","Eye infections","Deep abscess"],"answer": 1,"explain": "Bacitracin is for topical use on minor cuts, wounds, and burn prophylaxis and should not be used near the eyes."}]},{"id": 33,"name": "Mupirocin","brand": "Bactroban","aka": ["Bactroban","Pseudomonic Acid"],"cat": "Topical/Ophthalmic/Otic","cls": "Topical antibiotic","mech": "Inhibits bacterial protein synthesis","dose": "Apply to affected area TID x 7-14 days","ind": "Impetigo, skin infections, MRSA nasal decolonization","contra": "Hypersensitivity","se": "Local irritation, pruritus","notes": "Good for staph skin infections including MRSA","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "Besides treating impetigo, mupirocin is commonly used for","choices": ["Oral thrush","MRSA nasal decolonization","Otitis externa","Conjunctivitis"],"answer": 1,"explain": "Mupirocin treats staph skin infections including MRSA and is used for nasal decolonization."}]},{"id": 34,"name": "Erythromycin Ophthalmic","brand": "Ilotycin","aka": ["Ilotycin","Erythromycin"],"cat": "Topical/Ophthalmic/Otic","cls": "Macrolide ophthalmic","mech": "Inhibits bacterial protein synthesis","dose": "0.5-inch ribbon to affected eye 2-6 times daily","ind": "Bacterial conjunctivitis, neonatal ophthalmia prophylaxis","contra": "Macrolide allergy","se": "Local irritation, blurred vision","notes": "Safe for neonates; first-line conjunctivitis","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "Erythromycin ophthalmic ointment is notably used for which prophylaxis?","choices": ["Glaucoma prevention","Neonatal ophthalmia prophylaxis","Cataract prevention","Dry eye"],"answer": 1,"explain": "Erythromycin ophthalmic is safe in neonates and used for neonatal ophthalmia prophylaxis and conjunctivitis."}]},{"id": 35,"name": "Gatifloxacin Ophthalmic","brand": "Zymaxid","aka": ["Zymar","Zymaxid","Gatifloxacin"],"cat": "Topical/Ophthalmic/Otic","cls": "Fluoroquinolone ophthalmic","mech": "Inhibits DNA gyrase and topoisomerase IV","dose": "Days 1-2: 1 drop q2h while awake; Days 3-7: 1 drop QID","ind": "Bacterial conjunctivitis","contra": "Fluoroquinolone allergy","se": "Eye irritation, taste disturbance","notes": "Broad spectrum; apply finger pressure to lacrimal sac","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "What technique improves gatifloxacin ophthalmic drops and reduces systemic absorption?","choices": ["Blinking rapidly","Applying finger pressure to the lacrimal sac","Warming the bottle","Lying flat for an hour"],"answer": 1,"explain": "Applying pressure to the lacrimal sac reduces systemic absorption of ophthalmic gatifloxacin."}]},{"id": 36,"name": "Ofloxacin Otic","brand": "Floxin Otic","aka": ["Floxin Otic","Ofloxacin"],"cat": "Topical/Ophthalmic/Otic","cls": "Fluoroquinolone otic","mech": "Inhibits DNA gyrase","dose": "10 drops in affected ear daily x 7 days (externa); BID x 14 days (media)","ind": "Otitis externa, chronic otitis media","contra": "Fluoroquinolone allergy","se": "Local irritation, pruritus","notes": "Warm drops before instillation; safe with perforated TM","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "A useful property of ofloxacin otic drops for ear infections is that they are","choices": ["Contraindicated with any drainage","Safe to use with a perforated tympanic membrane","Only for outer ear cleaning","Effective only orally"],"answer": 1,"explain": "Ofloxacin otic is safe with a perforated tympanic membrane and is warmed before instillation."}]},{"id": 37,"name": "Fluconazole","brand": "Diflucan","aka": ["Diflucan"],"cat": "Antifungals","cls": "Triazole antifungal","mech": "Inhibits fungal cytochrome P450 and ergosterol synthesis","dose": "150 mg PO x1 (vaginal); 100-400 mg daily (systemic)","ind": "Candidiasis (vaginal, oral, systemic), cryptococcal meningitis","contra": "Concurrent QT-prolonging drugs","se": "Nausea, headache, hepatotoxicity, QT prolongation","notes": "Single dose for vaginal candidiasis","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 24-year-old female Air Force analyst, who recently completed a course of antibiotics for a sinus infection, now complains of intense vaginal itching, soreness, and a thick, white, \"cottage cheese-like\" discharge.","context": "Real-World Context: Antibiotic-triggered yeast infections are one of the most predictable side effects in medicine — think of the vaginal flora as a carefully balanced ecosystem, like a coral reef. The normal bacteria (Lactobacillus) act as the reef’s guardians, keeping opportunistic organisms like Candida yeast in check through competition and acid production. Antibiotics (especially broad-spectrum ones like Amoxicillin) carpet-bomb this ecosystem, killing the protective bacteria and leaving the yeast to proliferate unchecked. Fluconazole is an elegant solution: a single 150mg pill that gets absorbed, distributes systemically, and reaches therapeutic levels in vaginal tissue for days. Think of it as a precision strike against the yeast overgrowth. For deployed female service members, this is a common and frustrating problem that directly impacts readiness and comfort. Carrying a few Fluconazole tablets in the medical kit is a simple readiness multiplier. The topical alternatives (Miconazole cream, Clotrimazole suppositories) work equally well but require 1–7 days of messy application — far less practical in a field environment.","diagnosis": "This is a classic presentation of Vulvovaginal Candidiasis (Yeast Infection), commonly triggered by antibiotic use that disrupts the normal vaginal flora.","opqrst": "Onset: Over the past 3 days. Provocation: None. Quality: \"Itching and burning.\" Radiation: Localized. Severity: 7/10. Time: Constant.","sample": "Signs/Symptoms: Vaginal itching (pruritus), soreness, thick white discharge. Allergies: NKDA. Medications: Just finished a course of Amoxicillin. Past Pertinent History: Has had this once before after taking antibiotics. Last Oral Intake: Normal. Events: Symptoms began after antibiotic use.","vitals": "Within normal limits.","exam": "Pelvic exam reveals a red, inflamed vulva and a thick, white, adherent discharge. A sample on a slide (KOH prep) would show yeast hyphae.","primary": "Fluconazole (Diflucan) — 150 mg PO as a single dose. Extremely convenient and effective for uncomplicated yeast infections.","alternative": "Topical Antifungals (e.g., Miconazole, Clotrimazole): Creams or suppositories inserted into the vagina for 1, 3, or 7 days. Equally effective but can be messier and require a longer course of treatment.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What is the standard fluconazole regimen for uncomplicated vaginal candidiasis?","choices": ["150 mg PO once","100 mg daily for 14 days","400 mg IV daily","50 mg weekly"],"answer": 0,"explain": "Vaginal candidiasis is treated with a single 150 mg oral dose of fluconazole."}]},{"id": 38,"name": "Ketoconazole","brand": "Nizoral","aka": ["Nizoral"],"cat": "Antifungals","cls": "Imidazole antifungal","mech": "Inhibits fungal ergosterol synthesis","dose": "Topical: Apply daily-BID; Shampoo: 2x/week","ind": "Tinea infections, seborrheic dermatitis, dandruff","contra": "Hepatic disease (oral)","se": "Local irritation, hepatotoxicity (oral)","notes": "Primarily topical use now; oral has hepatotoxicity","tccc": false,"duty": "limited","scenarios": [{"scenario": "During a MEDCAP in a hot, humid village, a 25-year-old local national man shows a Civil Affairs medic a large, discolored patch on his upper back. It is slightly scaly, not itchy or painful, and has been present for months. He says it is more noticeable in the summer.","context": "Real-World Context: Tinea versicolor is one of the most common skin conditions medics encounter in tropical and humid environments — think of it as a cosmetic hijacking of the skin by a yeast that’s actually part of normal skin flora gone rogue. The Malassezia yeast, which lives harmlessly on everyone’s skin, overgrows in hot, sweaty conditions and produces azelaic acid, which bleaches melanocytes (the pigment-producing cells). The result: patches that tan differently from surrounding skin, creating a “camo pattern” that becomes dramatically visible in summer. The KOH prep revealing “spaghetti and meatballs” (hyphae and yeast clusters) is virtually pathognomonic. Ketoconazole shampoo used as a body wash is the most practical MEDCAP treatment — it’s cheap, easy to demonstrate, and the patient can continue it at home. The key counseling point: the color will NOT normalize immediately even after successful treatment. The yeast is dead, but the melanocyte damage takes weeks to months to resolve. Patients need to understand this or they’ll think the treatment failed.","diagnosis": "This is a classic presentation of Tinea Versicolor, a common, benign superficial fungal infection of the skin caused by Malassezia species.","opqrst": "Not applicable. Patient is asymptomatic.","sample": "Signs/Symptoms: Multiple hypo- and hyper-pigmented, slightly scaly macules coalescing into a large patch on the upper trunk. Allergies: Unknown. Medications: None. Past Pertinent History: Chronic, recurring issue. Last Oral Intake: Normal. Events: Seeking treatment for a cosmetic skin issue.","vitals": "Within normal limits.","exam": "Skin exam reveals the characteristic appearance of the rash. A KOH prep of a skin scraping would show a \"spaghetti and meatballs\" pattern of yeast and hyphae.","primary": "Ketoconazole (Topical) — Apply 2% cream or shampoo to the affected area once daily for 2 weeks. The shampoo can be used as a body wash, left on for 5–10 minutes before rinsing.","alternative": "Selenium Sulfide (Selsun Blue): Can also be used as a lotion or shampoo. Oral Fluconazole or Itraconazole: For extensive or refractory cases, but topical treatment is preferred for safety.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Why is ketoconazole now used primarily topically rather than orally?","choices": ["Oral form causes hearing loss","Oral form carries hepatotoxicity risk","It is inactivated by stomach acid","It only works on the skin"],"answer": 1,"explain": "Oral ketoconazole carries hepatotoxicity risk, so topical use predominates for tinea and seborrheic dermatitis."}]},{"id": 39,"name": "Terbinafine","brand": "Lamisil","aka": ["Lamisil","Terbinafine Hydrochloride"],"cat": "Antifungals","cls": "Allylamine antifungal","mech": "Inhibits squalene epoxidase in fungal cell membrane","dose": "250 mg PO daily x 6-12 weeks; Topical: Apply daily x 1-4 weeks","ind": "Onychomycosis, tinea infections","contra": "Hepatic disease, chronic/active liver disease","se": "GI upset, taste disturbance, hepatotoxicity","notes": "First-line for nail fungus; long treatment course","tccc": false,"duty": "limited","scenarios": [{"scenario": "A medic is home from a rotation and his 16-year-old son, who is on the wrestling team, complains of intensely itchy, peeling skin between his toes. The area is red and has a few small blisters.","context": "Real-World Context: Athlete’s foot is the most common fungal infection on the planet, and wrestling mats, locker rooms, and shared showers are ground zero. The dermatophyte fungi (Trichophyton species) thrive in warm, moist, dark environments — think of the space between toes as a tropical microclimate perfectly designed for fungal colonization. Terbinafine works by inhibiting squalene epoxidase, an enzyme critical for building the fungal cell membrane. Without an intact membrane, the fungus essentially dissolves. Think of it as removing the bricks from a wall — the structure collapses. The key to treatment success isn’t just the cream; it’s breaking the environmental cycle: dry feet thoroughly (especially between toes), change socks daily, alternate shoes to allow drying, and use antifungal powder prophylactically. For wrestlers, this extends to showering immediately after practice and using flip-flops in shared areas. Oral Terbinafine is reserved for toenail fungus (onychomycosis), which topical agents can’t penetrate effectively.","diagnosis": "This is a classic case of Tinea Pedis (Athlete’s Foot), a superficial fungal infection common in athletes.","opqrst": "Onset: Over the past few weeks. Provocation: Wearing shoes. Quality: \"Itchy and burning.\" Radiation: Stays between the toes. Severity: 6/10 itch. Time: Constant.","sample": "Signs/Symptoms: Itching, peeling (maceration), and redness between the 4th and 5th toes. Allergies: NKDA. Medications: None. Past Pertinent History: Spends a lot of time in locker rooms and on wrestling mats. Events: Fungal skin infection.","vitals": "Within normal limits.","exam": "Classic appearance of a fungal infection of the feet.","primary": "Lamisil (Terbinafine) Cream — Apply a thin layer of 1% cream to the affected area and surrounding skin once or twice a day for 1–2 weeks. Keep the feet clean and dry.","alternative": "Clotrimazole (Lotrimin) or Miconazole creams are also very effective OTC options. Oral Terbinafine is reserved for very severe cases or toenail involvement (onychomycosis).","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Terbinafine is considered first-line for which infection?","choices": ["Vaginal candidiasis","Onychomycosis (nail fungus)","Cryptococcal meningitis","Oral thrush"],"answer": 1,"explain": "Terbinafine is first-line for onychomycosis, requiring a long 6-12 week course."}]},{"id": 40,"name": "Atovaquone/Proguanil","brand": "Malarone","aka": ["Malarone"],"cat": "Antimalarials","cls": "Antimalarial combination","mech": "Atovaquone inhibits mitochondrial electron transport; proguanil inhibits dihydrofolate reductase","dose": "Prophylaxis: 1 tab daily (start 1-2 days before, continue 7 days after); Treatment: 4 tabs daily x 3 days","ind": "Malaria prophylaxis and treatment","contra": "Severe renal impairment (prophylaxis)","se": "GI upset, headache, elevated LFTs","notes": "Take with food; well-tolerated prophylaxis option","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "For atovaquone/proguanil malaria prophylaxis, the regimen is continued for how long after leaving the endemic area?","choices": ["1 day","7 days","14 days","28 days"],"answer": 1,"explain": "Malarone prophylaxis is continued for only 7 days after departure, an advantage over other agents."}]},{"id": 41,"name": "Primaquine","brand": "Primaquine","aka": ["Primaquine Phosphate"],"cat": "Antimalarials","cls": "8-aminoquinoline antimalarial","mech": "Active against hepatic stages (hypnozoites) of P. vivax/ovale","dose": "30 mg base PO daily x 14 days after leaving endemic area","ind": "Radical cure of P. vivax/ovale (eliminates liver hypnozoites)","contra": "G6PD deficiency (hemolysis), pregnancy","se": "Hemolytic anemia in G6PD deficiency, GI upset","notes": "MUST screen for G6PD before use; used AFTER initial treatment","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 30-year-old Special Forces operator has just returned from a 6-month deployment in a region where P. vivax malaria is endemic. He was diagnosed and treated for P. vivax malaria while deployed. The medic must now administer treatment to eradicate the dormant liver stages of the parasite.","context": "Real-World Context: P. vivax and P. ovale are the “sleeper agents” of malaria — unlike P. falciparum (which Malarone treats), these species leave dormant forms called hypnozoites hiding in liver cells like enemy combatants in a safe house. Standard antimalarials kill the parasites in the blood but can’t touch the liver stages. Without Primaquine, the hypnozoites can reactivate months or even years later, causing relapsing malaria episodes long after the operator has returned home. Primaquine is the ONLY drug that can reach into the liver and destroy these dormant forms — think of it as the raid team that clears the safe house after the street battle is won. The CRITICAL safety check: G6PD testing before administration. G6PD deficiency is an inherited condition (especially common in populations from malaria-endemic regions — an evolutionary adaptation) where red blood cells lack an enzyme that protects them from oxidative stress. Primaquine generates oxidative metabolites that, in G6PD-deficient patients, trigger massive hemolysis — the red blood cells literally shatter. This can be rapidly fatal. There is NO safe alternative for G6PD-deficient patients; they must accept the risk of relapse.","diagnosis": "The patient requires a Radical Cure for P. vivax or P. ovale malaria. The initial treatment killed the parasites in the blood, but these species leave dormant forms (hypnozoites) in the liver that can reactivate months or years later.","opqrst": "Not applicable. Patient is asymptomatic.","sample": "Signs/Symptoms: None. Feels healthy. Allergies: NKDA. Medications: Completed a course of Coartem a month ago. Past Pertinent History: P. vivax malaria infection. Crucially, G6PD status must be known to be normal. Events: Post-deployment radical cure for malaria.","vitals": "Within normal limits.","exam": "Patient appears healthy.","primary": "Primaquine — 30 mg PO once daily for 14 days. Eradicates the dormant liver-stage parasites.","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What must be screened for before giving primaquine?","choices": ["QT interval","G6PD deficiency","Renal function only","Thyroid function"],"answer": 1,"explain": "Primaquine causes hemolysis in G6PD deficiency, so G6PD must be screened before use."}]},{"id": 42,"name": "Epinephrine","brand": "EpiPen/Adrenalin","aka": ["Adrenaline","EpiPen","Epinephrine Hydrochloride","Epi"],"cat": "Cardiovascular & Emergency","cls": "Alpha/beta adrenergic agonist","mech": "Stimulates α1 (vasoconstriction), β1 (increased HR/contractility), β2 (bronchodilation)","dose": "Anaphylaxis: 0.3-0.5 mg IM (1:1000) q10-15min; Cardiac arrest: 1 mg IV/IO q3-5min","ind": "Anaphylaxis, cardiac arrest, severe asthma, hypotension","contra": "None absolute in life-threatening situations","se": "Tachycardia, hypertension, arrhythmias, anxiety","notes": "FIRST-LINE for anaphylaxis; IM in thigh","tccc": true,"duty": "limited","scenarios": [{"scenario": "A 24-year-old female Ranger is on patrol when her squad disturbs a ground wasp nest. She is stung multiple times on her arms and neck. Within two minutes, she reports a \"tight feeling\" in her throat and is having difficulty breathing. She has a known allergy to wasps.","context": "Real-World Context: Anaphylaxis is a full-body ambush by the immune system — think of it as friendly fire on a catastrophic scale. Mast cells throughout the body simultaneously dump histamine and other inflammatory mediators, causing three simultaneous crises: the airway swells shut (angioedema/bronchospasm), blood vessels dilate massively (dropping blood pressure to shock levels), and capillaries leak fluid into tissues (causing hives and further volume loss). Epinephrine is the only drug that fights on all three fronts simultaneously: it constricts blood vessels (raising BP), relaxes bronchial smooth muscle (opening the airway), and suppresses further mast cell degranulation (stopping the cascade). Think of it as hitting the emergency brake on a runaway immune response. The anterolateral thigh is the preferred injection site because it has a rich blood supply for rapid absorption. Benadryl and steroids are adjuncts that clean up after the fire — they do NOT put it out. Never delay Epinephrine to give Benadryl.","diagnosis": "This casualty is experiencing a severe systemic allergic reaction resulting in Anaphylactic Shock. The primary life threats are airway compromise and cardiovascular collapse.","opqrst": "Onset: Sudden, 2 minutes ago. Provocation: Worsens with every breath. Quality: \"Throat feels like it's closing.\" Radiation: Tightness in throat and chest; diffuse itching. Severity: 9/10 difficulty breathing. Time: Progressively worsening since the stings.","sample": "Signs/Symptoms: Audible wheezing (stridor), widespread hives (urticaria) on neck and arms, swelling of the lips and tongue (angioedema). Allergies: Known wasp venom allergy. Medications: None. Past Pertinent History: None. Last Oral Intake: Water, 15 minutes ago. Events: Multiple wasp stings.","vitals": "Heart Rate: 120 bpm | Blood Pressure: 90/50 mmHg | Respiratory Rate: 28 breaths/min, labored | SpO2: 90% on room air | Temperature: 99.0°F","exam": "Airway assessment for stridor and angioedema. Auscultation of lungs for wheezing. Skin examination for hives. Cardiovascular exam for signs of shock.","primary": "","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario": "A 20-year-old Ranger eats a cookie from a care package, unaware that it contains peanuts, to which he has a severe allergy. Within two minutes, he yells \"I can't breathe,\" his face and lips begin to swell, and he becomes audibly wheezy before collapsing.","context": "Real-World Context: This scenario illustrates the terrifying speed of severe food-triggered anaphylaxis — from \"normal\" to \"dying\" in under two minutes. Unlike insect stings where the allergen dose is small, ingested allergens flood the GI tract and are rapidly absorbed into the bloodstream, triggering a massive, systemic mast cell response. Think of the difference between a match (sting) and gasoline (ingestion). The patient progressing to unresponsive with a BP of 70/40 and SpO2 of 85% is in extremis — this is a \"dead in 10 minutes\" emergency without Epinephrine. The key teaching point: Epinephrine is NEVER wrong in true anaphylaxis. Medics sometimes hesitate, fearing side effects, but the risk of withholding it is death. After the initial dose, be ready for aggressive IV fluid resuscitation (the distributive shock can require 2–4 liters), IV steroids (Solu-Medrol 125mg) to prevent the biphasic reaction that can hit 4–12 hours later, and continuous reassessment.","diagnosis": "The patient is in Anaphylactic Shock, the most severe form of allergic reaction. This is an immediate life threat due to airway compromise and cardiovascular collapse.","opqrst": "Patient is rapidly becoming unresponsive and unable to speak.","sample": "Signs/Symptoms: Angioedema (facial/lip swelling), stridor and wheezing, widespread hives, signs of shock (pale, clammy skin, weak pulse). Allergies: Known severe peanut allergy. Medications: None. Past Pertinent History: Has used an EpiPen before. Last Oral Intake: Peanut-containing cookie. Events: Anaphylactic reaction.","vitals": "Heart Rate: 140 bpm, weak and thready | Blood Pressure: 70/40 mmHg | Respiratory Rate: 30 breaths/min, labored with stridor | SpO2: 85% and falling | Temperature: 98.6°F","exam": "C-A-B-C. Airway is the immediate priority. Patient is in extremis.","primary": "Epinephrine — 0.3–0.5 mg IM into the anterolateral thigh. Use an autoinjector (EpiPen) if available. Repeat every 5–15 minutes as needed. This is the ONLY first-line, life-saving treatment.","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What is the correct epinephrine dose and route for anaphylaxis in an adult?","choices": ["1 mg IV (1:10000)","0.3-0.5 mg IM (1:1000) in the thigh","0.1 mg subcutaneous","2 mg nebulized"],"answer": 1,"explain": "Anaphylaxis is treated first-line with 0.3-0.5 mg IM epinephrine (1:1000) in the thigh."},{"q": "Which epinephrine receptor effect produces the bronchodilation that helps in anaphylaxis and asthma?","choices": ["Alpha-1 stimulation","Beta-1 stimulation","Beta-2 stimulation","Muscarinic blockade"],"answer": 2,"explain": "Epinephrine stimulates beta-2 receptors to cause bronchodilation, alongside alpha-1 vasoconstriction and beta-1 cardiac effects."}]},{"id": 43,"name": "Atropine","brand": "AtroPen","aka": ["Atropine Sulfate","AtroPen"],"cat": "Cardiovascular & Emergency","cls": "Anticholinergic, antimuscarinic","mech": "Competitively blocks acetylcholine at muscarinic receptors","dose": "Bradycardia: 0.5-1 mg IV q3-5min (max 3 mg); Nerve agent: 2-4 mg IM, repeat until secretions dry","ind": "Symptomatic bradycardia, organophosphate/nerve agent poisoning","contra": "Tachycardia, acute angle glaucoma","se": "Tachycardia, dry mouth, urinary retention, hyperthermia","notes": "Nerve agent endpoint: dried secretions (NOT pupil size)","tccc": true,"duty": "","scenarios": [],"quiz": [{"q": "What is the correct clinical endpoint for atropine administration in nerve agent (organophosphate) poisoning?","choices": ["Pupils fully dilated","Heart rate above 100","Drying of secretions","Resolution of muscle fasciculations"],"answer": 2,"explain": "Per the drug notes, the nerve agent endpoint is dried secretions, NOT pupil size."},{"q": "A casualty has symptomatic bradycardia. What is the standard atropine dose and maximum?","choices": ["0.5-1 mg IV q3-5min, max 3 mg","2 mg IV once only, no repeat","0.1 mg IV q1min, max 0.5 mg","5 mg IM, max 10 mg"],"answer": 0,"explain": "For symptomatic bradycardia the dose is 0.5-1 mg IV every 3-5 minutes to a maximum of 3 mg."}]},{"id": 44,"name": "Nitroglycerin","brand": "Nitrostat","aka": ["GTN","Glyceryl Trinitrate","Nitroglycerine","Nitrostat","Trinitrin"],"cat": "Cardiovascular & Emergency","cls": "Antianginal, vasodilator","mech": "Releases nitric oxide causing venous and arterial vasodilation","dose": "0.4 mg SL q5min x 3 doses","ind": "Angina, ACS, hypertensive emergency, acute heart failure","contra": "SBP <90, RV infarct, PDE-5 inhibitor use within 24-48h, severe aortic stenosis","se": "Hypotension, headache, flushing","notes": "Sit patient down; avoid in inferior MI with RV involvement","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "Which of the following is a contraindication to nitroglycerin?","choices": ["Headache","PDE-5 inhibitor (e.g., sildenafil) use within 24-48h","Hypertensive emergency","Stable angina"],"answer": 1,"explain": "Nitroglycerin is contraindicated with recent PDE-5 inhibitor use, SBP under 90, RV infarct, and severe aortic stenosis due to profound hypotension risk."}]},{"id": 45,"name": "Calcium Gluconate","brand": "Calcium Gluconate","aka": [],"cat": "Cardiovascular & Emergency","cls": "Electrolyte replenisher","mech": "Provides ionized calcium for cardiac and neuromuscular function","dose": "1-2 g IV over 10-20 minutes","ind": "Hyperkalemia, hypocalcemia, calcium channel blocker overdose, HF toxicity","contra": "Digoxin toxicity (relative), hypercalcemia","se": "Bradycardia, hypotension, tissue necrosis if extravasated","notes": "Do NOT mix with ceftriaxone; cardiac membrane stabilizer in hyperK","tccc": false,"duty": "nogo","scenarios": [{"scenario": "A 33-year-old Special Forces Medic is managing a local national partner force soldier who sustained multiple gunshot wounds to the abdomen. The casualty has received two units of whole blood via the medic’s field blood bank. Bleeding is slowing, but the medic now notes persistent oozing from IV sites and muscle twitching in the patient’s hands.","context": "Real-World Context: Massive transfusion is a race against the “lethal triad” of trauma: hypothermia, acidosis, and coagulopathy. Calcium Gluconate addresses a hidden fourth threat that emerges during transfusion itself. Stored blood contains citrate as an anticoagulant — it works by binding to calcium, which is essential for the clotting cascade. Think of citrate as a “calcium sponge”: as you pour in units of blood, you’re also pouring in citrate that soaks up the body’s free calcium. Without calcium, clots can’t form (defeating the purpose of the transfusion), muscles twitch and cramp (Chvostek’s sign on the face), and the heart’s electrical system becomes unstable (prolonged QT, potential arrest). The rule of thumb is simple: give 1g of Calcium Gluconate after the first unit and with every subsequent unit. Calcium Gluconate is preferred over Calcium Chloride in the field because it’s far less caustic if the IV infiltrates — Calcium Chloride extravasation can cause tissue necrosis.","diagnosis": "The casualty is developing Hypocalcemia secondary to massive transfusion. The citrate used as an anticoagulant in stored blood binds to the body’s free calcium, rendering it inactive and impairing the clotting cascade and muscle function.","opqrst": "Patient has altered mental status from shock and is unable to communicate effectively.","sample": "Signs/Symptoms: Altered mental status, persistent non-mechanical bleeding, muscle fasciculations/tremors (Chvostek’s sign). Allergies: Unknown. Medications: 2 units of whole blood. Past Pertinent History: Unknown. Events: Multiple GSWs, now receiving massive transfusion.","vitals": "Heart Rate: 130 bpm | Blood Pressure: 80/palpation | Respiratory Rate: 30 breaths/min | SpO2: 92% on O2 | Temperature: 96.5°F","exam": "Re-assess all sources of bleeding. If an EKG is available, check for a prolonged QT interval. Tap on the facial nerve to check for facial muscle twitching (Chvostek’s sign).","primary": "Calcium Gluconate — 1g (10 mL of 10% solution) administered as a slow IV/IO push over 2–3 minutes. Should be given after the first unit of blood and with every subsequent unit.","alternative": "Calcium Chloride — Can also be used, but it is 3x more potent and significantly more caustic to tissues if the IV line is not patent. Calcium Gluconate is generally safer for field use.","avoid": "","dutyStatus": "EMERGENCY USE in the context of massive transfusion or hyperkalemia. Patient is NON-MISSION-CAPABLE (receiving emergency resuscitation).","onsetDuration": "Onset: 1–3 minutes IV. Duration of cardiac protection: 30–60 minutes.","cognitive": "None from the drug itself; the patient’s clinical state determines cognitive function.","field": "Administer 1g IV after the first unit of blood product and with every subsequent unit. Monitor EKG for peaked T waves (hyperkalemia). Incompatible with Ceftriaxone in the same IV line — will form precipitate. Must be pushed slowly to avoid cardiac arrhythmia."}],"quiz": [{"q": "Calcium gluconate should NOT be mixed in the same IV line with which drug because it forms a precipitate?","choices": ["Normal saline","Ceftriaxone","Dextrose","Potassium chloride"],"answer": 1,"explain": "The notes warn not to mix calcium gluconate with ceftriaxone; it also acts as a cardiac membrane stabilizer in hyperkalemia."}]},{"id": 46,"name": "Albuterol","brand": "Proventil/Ventolin","aka": ["Salbutamol","Ventolin","ProAir","Proventil"],"cat": "Respiratory","cls": "Beta2-agonist bronchodilator","mech": "Relaxes bronchial smooth muscle via beta2 receptor stimulation","dose": "MDI: 2 puffs q4-6h PRN or q20min x 3 (acute); Nebulizer: 2.5 mg q20min x 3","ind": "Asthma, bronchospasm, COPD exacerbation, anaphylaxis adjunct","contra": "Hypersensitivity","se": "Tachycardia, tremor, nervousness, hypokalemia","notes": "First-line bronchodilator; can use continuously in severe exacerbations","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "By what mechanism does albuterol relieve bronchospasm?","choices": ["Blocks muscarinic receptors in the airway","Relaxes bronchial smooth muscle via beta2 receptor stimulation","Reduces airway inflammation as a corticosteroid","Thins mucus secretions"],"answer": 1,"explain": "Albuterol is a beta2-agonist that relaxes bronchial smooth muscle, making it the first-line bronchodilator."}]},{"id": 47,"name": "Fluticasone","brand": "Flonase/Flovent","aka": ["Flovent","Flixotide","Fluticasone Propionate"],"cat": "Respiratory","cls": "Inhaled corticosteroid","mech": "Reduces airway inflammation","dose": "Nasal: 1-2 sprays per nostril daily; Inhaled: 88-440 mcg BID","ind": "Allergic rhinitis, asthma maintenance","contra": "Primary treatment of status asthmaticus","se": "Oral candidiasis, hoarseness, epistaxis","notes": "NOT for acute bronchospasm; rinse mouth after inhaled use","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 38-year-old Navy Corpsman suffers from chronic, year-round nasal congestion and sinus pressure due to perennial allergies. It affects his sleep and sense of smell. He has tried oral antihistamines, but they only provide partial relief. He needs a long-term maintenance therapy.","context": "Real-World Context: If antihistamines are the infantry of allergy treatment — quick to deploy, good for acute firefights — then nasal corticosteroids like Fluticasone are the engineering corps: they rebuild the defensive infrastructure. Oral antihistamines block ONE mediator (histamine), but allergic rhinitis involves dozens of inflammatory chemicals. Fluticasone suppresses the entire inflammatory cascade at the source, right inside the nasal mucosa. Think of it as calming down an inflamed, overreacting neighborhood rather than just blocking one troublemaker. The critical patient education point: it’s NOT a rescue spray. It takes 3–7 days of consistent daily use to reach full effect, and stopping it means the inflammation roars back. Many patients give up after 2 days saying “it doesn’t work” — they need to understand it’s building a foundation, not putting out a fire. For operators, the beauty is that the drug stays local in the nasal passages with minimal systemic absorption, so there are virtually no sedation or cognitive effects.","diagnosis": "The patient has Chronic Allergic Rhinitis. When oral antihistamines are insufficient, the first-line treatment for moderate to severe or persistent symptoms is a nasal corticosteroid spray.","opqrst": "Not applicable. This is a chronic condition.","sample": "Signs/Symptoms: Persistent nasal congestion, sinus pressure, post-nasal drip. Allergies: Dust mites, mold. Medications: Cetirizine (Zyrtec) as needed. Past Pertinent History: Chronic allergic rhinitis. Last Oral Intake: Normal. Events: Seeking a more effective daily treatment.","vitals": "Within normal limits.","exam": "Nasal exam shows swollen, pale turbinates and clear mucus.","primary": "Flonase (Fluticasone) — 1–2 sprays in each nostril once daily. Reduces local inflammation in the nasal passages. Can take several days to reach full effect and must be used consistently.","alternative": "Nasonex (Mometasone) or Rhinocort (Budesonide): Other nasal steroid sprays that are equally effective.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Why is inhaled fluticasone inappropriate as a rescue treatment for acute bronchospasm?","choices": ["It causes immediate bronchoconstriction","It is an inhaled corticosteroid for maintenance, not acute attacks","It is only available as an injection","It works only on the heart"],"answer": 1,"explain": "Fluticasone is an inhaled corticosteroid that reduces inflammation over time; it is NOT for acute bronchospasm or status asthmaticus."}]},{"id": 48,"name": "Guaifenesin","brand": "Mucinex","aka": ["Mucinex","Robitussin","Guaiphenesin"],"cat": "Respiratory","cls": "Expectorant","mech": "Increases respiratory tract fluid secretions, thins mucus","dose": "200-400 mg PO q4h or 600-1200 mg extended-release q12h","ind": "Productive cough, chest congestion","contra": "None significant","se": "GI upset, headache, dizziness","notes": "Encourage fluid intake; helps thin secretions","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 29-year-old Ranger is recovering from a chest cold. He has a lingering, \"heavy\" cough that is full of thick mucus he is struggling to cough up and out. This chest congestion is making him feel short of breath with exertion.","context": "Real-World Context: Thick mucus plugging the airways is like traffic congestion in a tunnel — air can’t get through efficiently, and the body’s natural cleaning mechanism (the mucociliary escalator) is overwhelmed. Guaifenesin works by stimulating the secretory glands in the respiratory tract to produce more water, effectively diluting the thick, sticky mucus into something thin enough to cough up. Think of it as adding water to thick honey — it flows and clears much more easily. The critical distinction for medics: a productive cough (wet, mucus-producing) should NOT be suppressed with a cough suppressant like Benzonatate or Dextromethorphan. Suppressing a productive cough is like turning off a sump pump in a flooding basement — the mucus needs to come OUT. Guaifenesin helps it do exactly that. The medication must be taken with a FULL glass of water to work properly (you’re asking it to thin secretions, so you need to give it the raw material). Aggressive hydration is essentially free Guaifenesin.","diagnosis": "The patient has Acute Bronchitis, characterized by chest congestion and a productive cough. The goal of treatment is to make the cough more effective by thinning the mucus.","opqrst": "Onset: Began 4 days ago with a cold. Provocation: Deep breathing, exertion. Quality: \"A wet, junky cough.\" Radiation: Substernal chest fullness. Severity: 5/10 discomfort. Time: Intermittent.","sample": "Signs/Symptoms: Productive cough with thick sputum, chest congestion. No fever. Allergies: NKDA. Medications: None. Past Pertinent History: Recent URI. Last Oral Intake: Normal, encouraged to drink fluids. Events: Lingering chest congestion after a viral illness.","vitals": "Heart Rate: 80 bpm | Blood Pressure: 125/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 99.0°F","exam": "Lungs may have some coarse rhonchi that clear with coughing. No signs of pneumonia.","primary": "Guaifenesin (Mucinex) — 600–1200 mg (extended-release tablet) PO every 12 hours. An expectorant; it thins and loosens mucus in the airways, making it easier to cough up. Must be taken with a full glass of water.","alternative": "No direct alternatives. Primary alternative treatment is aggressive hydration (drinking lots of water). A cough suppressant (like Dextromethorphan) is generally NOT recommended for a productive cough, as you want the patient to clear the mucus.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What is the primary therapeutic action of guaifenesin?","choices": ["Suppresses the cough reflex","Thins mucus by increasing respiratory tract secretions","Constricts nasal blood vessels","Blocks histamine receptors"],"answer": 1,"explain": "Guaifenesin is an expectorant that increases respiratory tract fluid and thins mucus; patients should be encouraged to increase fluid intake."}]},{"id": 49,"name": "Benzonatate","brand": "Tessalon Perles","aka": ["Tessalon","Tessalon Perles"],"cat": "Respiratory","cls": "Antitussive","mech": "Anesthetizes stretch receptors in respiratory passages","dose": "100-200 mg PO TID","ind": "Symptomatic cough relief","contra": "Hypersensitivity","se": "Sedation, headache, dizziness","notes": "Swallow whole; do NOT chew (numbs mouth/throat)","tccc": false,"duty": "go","scenarios": [{"scenario": "A 24-year-old Ranger is recovering from a recent upper respiratory infection. While the fever and sore throat have resolved, he is left with a persistent, dry, hacking cough. The cough is preventing him from sleeping and could compromise noise discipline during an upcoming reconnaissance mission.","context": "Real-World Context: A cough may seem minor, but in SOF operations, noise discipline can be the difference between mission success and compromise. Think of Benzonatate as a “mute button” for the lungs — it works by numbing the stretch receptors in the airways that trigger the cough reflex, like applying lidocaine to a ticklish nerve. Unlike narcotic cough suppressants (codeine, hydrocodone), it doesn’t fog the brain or slow reaction time. A valuable off-label use: for dental injuries in austere environments, the patient can bite the pearl over the affected tooth, releasing the anesthetic fluid directly onto the pain, then spit out the residue. You can also break open a capsule and place the fluid on gauze to pack a dental pocket wound — essentially turning a cough suppressant into a field dental anesthetic.","diagnosis": "The patient has a Post-Viral Cough. The goal is to provide symptomatic relief with a non-sedating cough suppressant to allow for rest and maintain operational readiness.","opqrst": "Onset: Began 5 days ago with a cold. Provocation: Lying down, deep breaths. Quality: \"Dry, hacking cough.\" Radiation: None. Severity: 5/10 annoyance, but significantly disrupting sleep. Time: Intermittent but frequent.","sample": "Signs/Symptoms: Dry, non-productive cough. No fever, shortness of breath, or other symptoms. Allergies: NKDA. Medications: None. Past Pertinent History: Recent URI. Last Oral Intake: Normal. Events: Post-viral cough.","vitals": "Heart Rate: 70 bpm | Blood Pressure: 120/75 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% | Temperature: 98.7°F","exam": "Lungs are clear to auscultation. Throat is non-erythematous.","primary": "Benzonatate (Tessalon Perles) — 100–200 mg PO three times a day as needed. A non-narcotic antitussive that works by anesthetizing stretch receptors in the lungs.","alternative": "Dextromethorphan (Robitussin): Another non-narcotic cough suppressant. Codeine/Hydrocodone: Narcotic options that are very effective but generally avoided unless necessary due to sedative effects and abuse potential.","avoid": "","dutyStatus": "MISSION CAPABLE. Minimal systemic effects at standard doses.","onsetDuration": "Onset: 15–20 min PO. Duration: 3–8 hours.","cognitive": "Minimal. May cause mild dizziness at higher doses.","field": "Capsules MUST be swallowed whole — chewing or dissolving causes rapid oropharyngeal anesthesia and potential choking hazard. Useful for noise discipline scenarios where coughing compromises the mission. Can be bitten and applied over a painful tooth as an off-label dental analgesic."}],"quiz": [{"q": "Why must benzonatate (Tessalon Perles) capsules be swallowed whole and never chewed?","choices": ["Chewing destroys the active drug","Chewing causes oropharyngeal anesthesia and choking risk","It tastes extremely bitter","It must dissolve in the stomach to absorb"],"answer": 1,"explain": "Benzonatate anesthetizes stretch receptors; chewing numbs the mouth and throat, creating a choking hazard, so capsules are swallowed whole."}]},{"id": 50,"name": "Midazolam","brand": "Versed","aka": ["Versed","Dormicum","Hypnovel","Midazolam Hydrochloride"],"cat": "CNS & Neurological","cls": "Benzodiazepine","mech": "Enhances GABA-A receptor activity","dose": "Seizures: 10 mg IM/IN; Sedation: 0.5-2 mg IV; RSI: 0.1-0.3 mg/kg IV","ind": "Status epilepticus, procedural sedation, RSI, nerve agent seizures","contra": "Acute angle glaucoma, shock","se": "Respiratory depression, hypotension, paradoxical agitation","notes": "TCCC seizure drug; water-soluble (good IM/IN absorption); short-acting","tccc": true,"duty": "limited","scenarios": [{"scenario": "A medic is treating a 45-year-old local national who was struck in the head with a rifle butt during an altercation. The man is initially conscious but then loses consciousness and begins a generalized tonic-clonic (grand mal) seizure.","context": "Real-World Context: A seizure after head trauma is like an electrical storm in a brain that’s already damaged — every second it continues, more neurons are dying from the combination of excitotoxicity and hypoxia (the seizing muscles consume massive amounts of oxygen while the disordered breathing can’t keep up). Midazolam is the field medic’s weapon of choice for seizures because it offers THREE rapid delivery routes when a patient is convulsing and you can’t start an IV: intranasal (fastest), IM (most reliable), and IV (most precise). Think of the intranasal route as a shortcut — the nasal mucosa is thin, highly vascular, and delivers drug directly toward the brain, bypassing first-pass metabolism. The key post-seizure actions: recovery position (to protect the airway from aspiration), C-spine precautions (the mechanism suggests potential cervical injury), and continuous neuro monitoring for signs of increased ICP. Do NOT put anything in a seizing patient’s mouth — the jaw muscles can generate 250 pounds of force and will destroy whatever you insert.","diagnosis": "The casualty has a Post-Traumatic Seizure. The priority is to stop the seizure to prevent further brain injury and hypoxia.","opqrst": "Patient is actively seizing and unresponsive.","sample": "Signs/Symptoms: Unresponsive, tonic-clonic movements of all extremities, jaw clenching, urinary incontinence. Visible hematoma and laceration on the side of his head. Allergies: Unknown. Medications: Unknown. Past Pertinent History: Unknown. Last Oral Intake: Unknown. Events: Blunt force trauma to the head.","vitals": "(Difficult to obtain during seizure) Post-ictal: Heart Rate: 115 bpm | Blood Pressure: 150/95 mmHg | Respiratory Rate: 24 breaths/min, sonorous | SpO2: 91% on room air","exam": "Protect the patient from injury during the seizure. Do not place anything in their mouth. C-spine precautions. Assess airway and breathing post-seizure. Assess for other signs of TBI.","primary": "Midazolam (Versed) — 10 mg IM/IN/IV. The intranasal route is often fastest if IV access is not established.","alternative": "Diazepam (Valium): 5–10 mg slow IV push. Note: Diazepam has a shorter duration of action for seizure control compared to Midazolam. Lorazepam is another alternative.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario": "A 25-year-old Ranger is undergoing a painful procedure to reduce a dislocated shoulder. Despite receiving Fentanyl for pain, he is extremely anxious and fighting against the medic’s efforts. The medic needs to provide sedation to relax the patient and his muscles to achieve a successful reduction.","context": "Real-World Context: Shoulder reduction without adequate sedation is a wrestling match that nobody wins — the patient fights, the muscles guard, and the shoulder won’t reduce. Midazolam combined with Fentanyl creates the classic “conscious sedation” cocktail: Fentanyl handles the pain while Midazolam provides anxiolysis (anxiety relief) and, critically, amnesia — the patient won’t remember the procedure. Think of Midazolam as erasing the recording while Fentanyl turns down the volume. The “titrate to effect” approach is key: push 1mg, wait 2 minutes, assess (look for slurred speech, drowsy appearance, relaxed muscles), push another 1mg if needed. This avoids the oversedation that comes from giving the full dose at once. Continuous pulse oximetry monitoring is mandatory because both drugs can suppress breathing. The safety net: Flumazenil (benzodiazepine reversal agent) and Naloxone (opioid reversal agent) should both be drawn up and ready. In the field, Ketamine alone is often the simpler choice — it provides analgesia, amnesia, AND sedation in a single drug with much wider safety margins.","diagnosis": "The patient requires Procedural Sedation and Analgesia (PSA) to tolerate the shoulder reduction. The goal is to provide anxiolysis (anxiety relief) and amnesia for the event.","opqrst": "Not applicable; for procedural sedation.","sample": "Signs/Symptoms: Anterior shoulder dislocation, severe pain, and anxiety. Allergies: NKDA. Medications: Fentanyl 100mcg IV. Past Pertinent History: None. Events: Shoulder dislocation during an obstacle course.","vitals": "(Monitor closely during sedation) Pre-sedation: HR 110, BP 140/85, RR 20, SpO2 99%","exam": "Arm is held in abduction and external rotation. Shoulder contour is squared off.","primary": "Versed (Midazolam) — 1–2 mg slow IV push, titrated to effect (slurred speech, drowsiness). A short-acting benzodiazepine ideal for procedural sedation. Provides anxiolysis and amnesia but NOT pain relief (hence combined with Fentanyl).","alternative": "Ketamine — “Ketofol” (Ketamine + Propofol) is popular in hospitals. In the field, Ketamine alone provides both analgesia and dissociation/sedation — an excellent single-drug choice.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Why is midazolam the preferred TCCC field benzodiazepine for seizures when no IV is available?","choices": ["It is the longest-acting benzodiazepine","It is water-soluble with good IM/IN absorption","It has no respiratory depression risk","It reverses opioid overdose"],"answer": 1,"explain": "Midazolam is water-soluble, giving reliable IM and intranasal absorption, and is short-acting, making it ideal for field seizure control."},{"q": "Which is a recognized adverse effect of midazolam?","choices": ["Hypertension","Respiratory depression","Bradycardia reversal","Diuresis"],"answer": 1,"explain": "Midazolam can cause respiratory depression, hypotension, and paradoxical agitation, so airway and ventilation must be monitored."}]},{"id": 51,"name": "Diazepam","brand": "Valium","aka": ["Valium","Stesolid"],"cat": "CNS & Neurological","cls": "Benzodiazepine","mech": "Enhances GABA-A receptor activity","dose": "Seizures: 5-10 mg IV q10-15min (max 30 mg); Anxiety: 2-10 mg PO/IV; Muscle spasm: 5-10 mg PO TID","ind": "Seizures, anxiety, muscle spasm, alcohol withdrawal","contra": "Acute angle glaucoma, severe respiratory depression, myasthenia gravis","se": "Respiratory depression, sedation, hypotension, dependence","notes": "Rectal gel for field use; longer acting; painful IM","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 42-year-old instructor at the Army SERE school is having a severe anxiety attack before leading a water survival exercise. He has a known phobia related to a past near-drowning incident. He is hyperventilating, trembling, and feels he cannot perform his duties.","context": "Real-World Context: Panic attacks in seasoned operators are more common than anyone admits — especially when specific phobias are triggered by operational scenarios. Think of a panic attack as the amygdala (the brain’s alarm center) hijacking the entire nervous system and sounding a full five-alarm fire when there’s no actual fire. The hyperventilation causes the tingling in his hands and mouth (respiratory alkalosis from blowing off too much CO2), which then feeds back into more panic (“Something’s wrong with my body!”). Diazepam works by amplifying GABA, the brain’s natural “brake pedal,” essentially calming the alarm system down to a manageable level. The critical operational reality: this medication is absolutely grounding. The instructor cannot lead the exercise or perform any duties requiring alertness. Non-pharmacologic interventions (coached breathing, removal from the triggering environment) should always be attempted first. Benzodiazepines are the pharmacologic safety net when those fail. The half-life of Diazepam is long (20–70 hours with active metabolites), so effects can linger well into the next day.","diagnosis": "The patient is experiencing a severe Panic Attack. The immediate goal is to reduce his acute, severe anxiety to a manageable level. This is an anxiolytic (anti-anxiety) use case.","opqrst": "Onset: Began 30 minutes ago when thinking about the exercise. Provocation: Anticipation of the event. Quality: \"Overwhelming panic.\" Radiation: Reports tingling in his hands and around his mouth. Severity: 10/10 anxiety. Time: Worsening.","sample": "Signs/Symptoms: Severe anxiety, hyperventilation, trembling, feeling of dread, paresthesia (tingling) in extremities. Allergies: NKDA. Medications: None. Past Pertinent History: PTSD, known water phobia. Events: Triggered panic attack.","vitals": "Heart Rate: 125 bpm | Blood Pressure: 150/90 mmHg | Respiratory Rate: 30 breaths/min, shallow | SpO2: 100%","exam": "Coach patient to slow their breathing. Rule out other medical causes of his symptoms (e.g., cardiac event), though the history is classic for panic.","primary": "Diazepam (Valium) — 2–5 mg PO. This benzodiazepine will provide rapid anxiolytic effects. Note: This is a highly sedating medication and is grounding for all duties. The patient cannot lead the exercise after taking this.","alternative": "Lorazepam (Ativan) or Alprazolam (Xanax): Other benzodiazepines that work similarly. Non-pharmacologic: Coaching breathing, removing the patient from the stressful environment.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What field-friendly formulation of diazepam is noted for treating seizures outside the hospital?","choices": ["Rectal gel","Transdermal patch","Nasal spray","Inhaler"],"answer": 0,"explain": "Diazepam comes as a rectal gel for field use; it is longer acting than midazolam but painful when given IM."}]},{"id": 52,"name": "Levetiracetam","brand": "Keppra","aka": ["Keppra"],"cat": "CNS & Neurological","cls": "Anticonvulsant","mech": "Binds synaptic vesicle protein SV2A; modulates neurotransmitter release","dose": "TBI prophylaxis: 1500 mg or 20 mg/kg IV loading; Maintenance: 1000 mg q12h x 7 days","ind": "Seizure treatment and TBI prophylaxis","contra": "Hypersensitivity","se": "Somnolence, behavioral changes, dizziness","notes": "Fewer drug interactions; no level monitoring needed","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 28-year-old Special Forces operator with a known history of a seizure disorder (well-controlled on medication) is on a long-duration mission. He realizes he has lost his medication. A medic needs to resupply him with an appropriate anti-seizure drug.","context": "Real-World Context: An operator with a seizure disorder who runs out of medication in the field is a ticking time bomb — abruptly stopping anti-epileptic drugs (AEDs) is one of the most common triggers for breakthrough seizures, and a seizure in the middle of a mission endangers everyone. Keppra (Levetiracetam) has become the preferred AED in military and emergency medicine for good reason: it has minimal drug interactions (critical when the patient might need antibiotics, analgesics, or other field medications), doesn’t require blood level monitoring (unlike older drugs like Dilantin or Valproic Acid), and has a wide therapeutic window (hard to overdose). Think of it as the “low-maintenance” seizure drug — it does its job without demanding constant attention. The critical field principle: NEVER substitute a different AED in the field unless it’s identical to what the patient takes. Switching AEDs requires careful cross-titration that takes weeks and carries a significant risk of triggering seizures during the transition. The medic’s job is to resupply the exact medication, not improvise.","diagnosis": "The patient requires a refill of his maintenance Antiepileptic Drug (AED) to prevent breakthrough seizures. Keppra is a modern AED with a favorable side effect profile.","opqrst": "Not applicable. Patient is asymptomatic and seeking medication refill.","sample": "Signs/Symptoms: None. Allergies: NKDA. Medications: Usually takes Keppra 750mg twice a day. Past Pertinent History: Post-traumatic seizure disorder from a previous TBI. Last Oral Intake: Normal. Events: Lost his personal medication while on mission.","vitals": "Within normal limits.","exam": "Neurological exam is non-focal.","primary": "Keppra (Levetiracetam) — Match his prescribed regimen, e.g., 750 mg PO twice a day. It is critical not to miss doses to maintain a therapeutic level and prevent seizures.","alternative": "There are many other AEDs (e.g., Lamotrigine, Topiramate, Valproic Acid), but in a maintenance situation, it is crucial to replace the patient’s specific medication and dosage. Switching AEDs should not be done in the field unless absolutely necessary.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What is an operational advantage of levetiracetam (Keppra) over older anticonvulsants?","choices": ["It requires frequent blood level monitoring","It has many drug interactions","It needs no serum level monitoring and has fewer interactions","It must be given only intramuscularly"],"answer": 2,"explain": "Levetiracetam has fewer drug interactions and needs no level monitoring, making it low-maintenance for field and TBI prophylaxis use."}]},{"id": 53,"name": "Modafinil","brand": "Provigil","aka": ["Provigil","Modalert","Alertec"],"cat": "CNS & Neurological","cls": "CNS stimulant","mech": "Increases dopamine; exact mechanism unknown","dose": "200 mg PO ~1 hour before work shift","ind": "Fatigue, hypersomnia, narcolepsy, shift work disorder","contra": "Hypersensitivity","se": "Headache, nausea, anxiety, palpitations","notes": "Non-amphetamine wakefulness promoter; may decrease OCP effectiveness","tccc": false,"duty": "limited","scenarios": [{"scenario": "A SOAR pilot is tasked with a critical, 12-hour overnight mission requiring sustained concentration. To ensure he remains alert and can combat fatigue during the flight, the flight surgeon authorizes a \"go pill.\"","context": "Real-World Context: Modafinil is the military’s “go pill” of choice — think of it as a precision instrument for keeping the brain awake versus the blunt hammer of traditional amphetamines (Dexedrine). While amphetamines flood the brain with dopamine and norepinephrine (creating euphoria, jitteriness, and a hard crash), Modafinil works through a more targeted mechanism involving histamine and orexin systems in the hypothalamus, the brain’s wakefulness center. The result is sustained alertness without the “wired” feeling, minimal cardiovascular side effects, and a much gentler offset. Think of amphetamines as redlining an engine versus Modafinil as simply keeping the engine from idling down. The operational context is strict: these are not candy. Use requires explicit flight surgeon authorization, documented in writing, for specific mission-essential tasks. The pilot must have been previously tested on the medication in a non-operational setting to identify any idiosyncratic reactions. Sleep is always preferred over pharmacological alertness — the “go pill” is the last resort when mission requirements make adequate sleep impossible.","diagnosis": "This is an authorized use of a Fatigue Countermeasure to maintain cognitive performance and alertness during a sustained military operation.","opqrst": "Not applicable. This is for performance sustainment.","sample": "Signs/Symptoms: Anticipated fatigue during a long-duration, overnight operation. Allergies: NKDA. Medications: None. Past Pertinent History: Has been approved for and used this medication on previous missions. Last Oral Intake: Pre-mission meal. Events: Authorized use of stimulant for mission performance.","vitals": "Baseline vitals are normal.","exam": "None indicated.","primary": "Provigil (Modafinil) — 200 mg PO taken 1–2 hours before the start of the mission. A eugeroic (wakefulness-promoting agent) that improves alertness with fewer classic stimulant side effects.","alternative": "Dextroamphetamine — Another “go pill” used by the military. A more traditional stimulant.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "How is modafinil best described compared with traditional amphetamine stimulants?","choices": ["A non-amphetamine wakefulness promoter","A short-acting sedative","An amphetamine derivative with high abuse potential","A beta-blocker"],"answer": 0,"explain": "Modafinil is a non-amphetamine wakefulness promoter; note it may also decrease oral contraceptive effectiveness."}]},{"id": 54,"name": "Cyclobenzaprine","brand": "Flexeril","aka": ["Flexeril","Amrix","Cyclobenzaprine Hydrochloride"],"cat": "Muscle Relaxants","cls": "Skeletal muscle relaxant","mech": "Centrally acting; reduces muscle hyperactivity","dose": "5-10 mg PO TID","ind": "Muscle spasm, musculoskeletal pain","contra": "Recent MI, arrhythmias, heart failure, MAOIs","se": "Drowsiness, dry mouth, dizziness","notes": "Short-term use only (2-3 weeks); avoid in elderly","tccc": false,"duty": "nogo","scenarios": [{"scenario": "A 37-year-old SOAR Crew Chief threw his back out while loading heavy equipment. He complains of intense, spasming pain in his lower back. He is \"stuck,\" unable to stand up straight, and any movement is agonizing.","context": "Real-World Context: Back injuries during load operations are practically an occupational hazard for crew chiefs and support personnel who manhandle hundreds of pounds of equipment under time pressure. Think of Flexeril as a “reset button” for muscles locked in a vicious spasm cycle — the muscle seizes, the pain worsens, the body tenses more, and the spasm deepens. In the field, a crew chief who can’t bend or twist is effectively combat-ineffective. The key clinical pearl is that Flexeril is powerfully sedating; expect 6–8 hours of deep, uninterrupted sleep. This is a feature, not a bug — sleep is when muscle healing accelerates — but it means you need to plan: only give it when the patient doesn’t need to be alert or responsive. Pair it with continued NSAIDs for the inflammation underneath.","diagnosis": "The patient is suffering from an Acute Lumbosacral Strain with severe muscle spasm. The goal is to relax the spasming muscles and control the pain.","opqrst": "Onset: Sudden, while lifting. Provocation: Any movement. Quality: \"Spasming and tight.\" Radiation: Across the lower back, no radiation down the legs. Severity: 8/10. Time: Constant.","sample": "Signs/Symptoms: Severe lower back pain, palpable muscle spasm, inability to bend or twist. Allergies: NKDA. Medications: Took 800mg of Ibuprofen with little relief. Past Pertinent History: \"Throws his back out once a year.\" Events: Lifting injury.","vitals": "Heart Rate: 90 bpm | Blood Pressure: 140/85 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 99%","exam": "Palpation of tight, tender paraspinal muscles. Crucially, perform a neurologic exam: Check for leg weakness, numbness (especially in the groin/saddle area), and urinary retention. Their absence points away from a more serious spinal cord issue.","primary": "Flexeril (Cyclobenzaprine) — 5–10 mg PO three times a day. This is a skeletal muscle relaxant. Note: It has significant sedative effects and is grounding for flight/special duties.","alternative": "Diazepam (Valium): 2–5 mg PO. Also an effective muscle relaxant with sedative properties. NSAIDs (like Ibuprofen or Naproxen): Should be continued to manage the underlying inflammation.","avoid": "","dutyStatus": "GROUNDING. The operator is non-mission-capable for 6–8 hours minimum. No weapons handling, driving, or flight.","onsetDuration": "Onset: 1 hour PO. Duration: 12–24 hours (highly sedating for 6–8 hours).","cognitive": "Significant sedation and drowsiness. Impairs reaction time, coordination, and judgment.","field": "Best administered at night before sleep. Patient should be in a safe, secure location. Do not combine with other CNS depressants. Plan for the operator to be out of action until the next day."}],"quiz": [{"q": "Cyclobenzaprine (Flexeril) is contraindicated in patients with which condition?","choices": ["Muscle spasm","Recent myocardial infarction or arrhythmias","Mild headache","Seasonal allergies"],"answer": 1,"explain": "Cyclobenzaprine is contraindicated with recent MI, arrhythmias, heart failure, and MAOI use, and is intended only for short-term use."}]},{"id": 55,"name": "Methocarbamol","brand": "Robaxin","aka": ["Robaxin"],"cat": "Muscle Relaxants","cls": "Skeletal muscle relaxant","mech": "General CNS depression leading to muscle relaxation","dose": "500-1500 mg PO q6-8h x 2-3 days (max 8 g/day); 500-1000 mg IV/IM q8h (max 3 days)","ind": "Muscle spasm, musculoskeletal pain","contra": "CNS depression, severe renal impairment","se": "Dizziness, drowsiness, confusion, sedation","notes": "Can be given IV; less sedating than cyclobenzaprine","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 34-year-old Marine Force Recon member wakes up with a severely stiff neck and is unable to turn his head to the left without excruciating pain. He thinks he \"slept on it wrong.\" The muscle is in a tight spasm.","context": "Real-World Context: Acute torticollis (“wry neck”) is the neck equivalent of throwing out your back — a muscle locks into spasm, usually the sternocleidomastoid or trapezius, and the patient literally cannot turn their head. For a Force Recon operator, this means they can’t scan sectors, check their six, or effectively aim a weapon — they’re tactically compromised. Methocarbamol (Robaxin) is positioned as a slightly lighter-touch muscle relaxant compared to Cyclobenzaprine (Flexeril). Think of Robaxin as a dimmer switch on the spasm signal, while Flexeril is more of an off switch that also turns off the lights (consciousness). Robaxin works centrally in the CNS to reduce spasm without the same degree of sedation as Flexeril, though ALL muscle relaxants are sedating to some degree and are grounding for special duties. The treatment triad for acute spasm is: muscle relaxant (breaks the spasm cycle) + NSAID (attacks the inflammation) + heat application (increases blood flow and tissue pliability). Ice is for acute injury; heat is for spasm.","diagnosis": "The patient is suffering from Acute Torticollis, a common condition involving severe, unilateral neck muscle spasm. The goal is to relax the muscle to relieve pain and restore motion.","opqrst": "Onset: Upon waking this morning. Provocation: Turning his head to the left. Quality: \"A sharp, spasming pain.\" Radiation: From the neck to the top of the shoulder. Severity: 7/10 with movement. Time: Constant.","sample": "Signs/Symptoms: Severe neck pain and spasm, limited range of motion. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Woke from sleep with the pain.","vitals": "Within normal limits.","exam": "Palpation of a tight, tender trapezius muscle. Neurological exam of the upper extremities is normal (ruling out a pinched nerve).","primary": "Robaxin (Methocarbamol) — 750–1500 mg PO three to four times a day. A CNS depressant with sedative and skeletal muscle relaxant properties.","alternative": "Cyclobenzaprine (Flexeril) or Diazepam (Valium): Other effective muscle relaxants. NSAIDs and application of heat can also be helpful.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What advantage does methocarbamol (Robaxin) have over cyclobenzaprine?","choices": ["It is non-sedating entirely","It can be given IV and is less sedating than cyclobenzaprine","It treats arrhythmias","It has no maximum dose"],"answer": 1,"explain": "Methocarbamol can be given IV and is generally less sedating than cyclobenzaprine, though all muscle relaxants cause some sedation."}]},{"id": 56,"name": "Ondansetron","brand": "Zofran","aka": ["Zofran","Ondansetron Hydrochloride"],"cat": "Antiemetics","cls": "5-HT3 receptor antagonist","mech": "Blocks serotonin 5-HT3 receptors in CTZ and vagal afferents","dose": "4-8 mg PO/IV/ODT q4-8h PRN","ind": "Nausea, vomiting, motion sickness, postoperative N/V","contra": "Congenital long QT syndrome","se": "Headache, constipation, QT prolongation","notes": "TCCC antiemetic; ODT dissolves on tongue; less sedating","tccc": true,"duty": "limited","scenarios": [{"scenario": "A 27-year-old male Ranger on a jungle patrol reports 12 hours of severe nausea, vomiting, and abdominal cramping. He is visibly weak, dizzy when he stands, and cannot tolerate oral fluids.","context": "Real-World Context: Ondansetron is the “gold standard” field antiemetic because it stops vomiting without sedating the patient — think of it as pressing the mute button on the brain’s vomiting center without turning off any other functions. It blocks serotonin (5-HT3) receptors in the chemoreceptor trigger zone and vagal afferents from the gut, the two main pathways that trigger the vomiting reflex. The ODT (orally disintegrating tablet) formulation is the field medic’s best friend: it dissolves on the tongue and absorbs through the oral mucosa, so even a patient who is actively vomiting can keep it down. Compare this to Promethazine (Phenergan), which is equally effective at stopping vomiting but knocks the patient unconscious with sedation — operationally useless when you need the Ranger back on his feet. The treatment sequence matters: stop the vomiting first (Zofran), then rehydrate (IV fluids or oral rehydration once tolerated). Treating dehydration while the patient is still vomiting is like filling a bucket with a hole in it.","diagnosis": "The casualty has Gastroenteritis with moderate Dehydration. The treatment priorities are to control the vomiting and then rehydrate the patient.","opqrst": "Onset: 12 hours ago. Provocation: Any attempt to eat or drink provokes vomiting. Quality: Waves of intense nausea with abdominal cramping. Radiation: Abdomen. Severity: 8/10 nausea. Time: Constant nausea with intermittent vomiting.","sample": "Signs/Symptoms: Nausea, vomiting, weakness, dizziness, dry mouth, decreased urine output. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Vomited water 30 minutes ago. Events: Likely infectious gastroenteritis.","vitals": "Heart Rate: 105 bpm | Blood Pressure: 110/70 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 98% on room air | Temperature: 99.5°F","exam": "Abdominal exam for hyperactive bowel sounds and tenderness. Assessment of hydration status. Check for orthostatic hypotension.","primary": "","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "By what mechanism does ondansetron (Zofran) control nausea and vomiting?","choices": ["Blocks dopamine receptors only","Blocks serotonin 5-HT3 receptors in the CTZ and vagal afferents","Stimulates gastric emptying","Blocks histamine H1 receptors"],"answer": 1,"explain": "Ondansetron is a 5-HT3 receptor antagonist acting at the chemoreceptor trigger zone and vagal afferents, and it is less sedating than alternatives."},{"q": "Ondansetron should be used with caution or avoided in patients with which condition?","choices": ["Congenital long QT syndrome","Hypertension","Asthma","Diabetes"],"answer": 0,"explain": "Ondansetron can prolong the QT interval and is contraindicated in congenital long QT syndrome."}]},{"id": 57,"name": "Promethazine","brand": "Phenergan","aka": ["Phenergan","Promethazine Hydrochloride","Promethegan"],"cat": "Antiemetics","cls": "Phenothiazine antihistamine","mech": "Blocks H1 receptors and dopamine receptors in CTZ","dose": "12.5-25 mg PO/IV/IM/PR q4-6h PRN","ind": "Nausea, vomiting, motion sickness, allergic reactions","contra": "Children <2 years, severe CNS depression, coma","se": "Sedation, extrapyramidal symptoms, tissue necrosis (IV)","notes": "Causes significant sedation; deep IM preferred over IV","tccc": false,"duty": "limited","scenarios": [{"scenario": "At a MEDCAP, a 60-year-old local woman is brought in with severe nausea and vomiting from gastroenteritis for the past 12 hours. She is weak and unable to keep down any fluids. The medic needs to stop her vomiting so she can rehydrate.","context": "Real-World Context: Promethazine is the “heavy artillery” of antiemetics — it hits multiple receptor systems (H1 histamine, muscarinic, dopaminergic) to shut down vomiting from virtually any cause. Think of it as a shotgun blast at the vomiting center versus Zofran’s precision rifle shot at the serotonin pathway. This broad receptor blockade is what makes it so effective, but it’s also why it’s so sedating — those same receptors are involved in wakefulness and alertness. In a MEDCAP setting treating a civilian, the sedation is acceptable (she’s going home with family to rest), whereas it would be a dealbreaker for an operational soldier. The deep IM route is specified because Promethazine is caustic to tissue — subcutaneous injection can cause severe tissue necrosis, and IV push carries a risk of severe thrombophlebitis. The family counseling is a real-world MEDCAP necessity: explain that she will be very drowsy, ensure someone will be with her, and confirm she can tolerate oral fluids before she leaves.","diagnosis": "The patient has Gastroenteritis with Moderate Dehydration. An antiemetic is needed to control the vomiting.","opqrst": "Onset: 12 hours ago. Provocation: Any attempt to drink. Quality: \"Waves of nausea.\" Radiation: None. Severity: 9/10 nausea. Time: Constant.","sample": "Signs/Symptoms: Vomiting, nausea, weakness, signs of dehydration. Allergies: Unknown. Medications: None. Past Pertinent History: None. Events: Gastroenteritis.","vitals": "Heart Rate: 105 bpm | Blood Pressure: 100/65 mmHg | Respiratory Rate: 18 breaths/min | Temperature: 99.5°F","exam": "Assess for dehydration (dry mucous membranes, poor skin turgor). Abdomen is soft.","primary": "Promethazine (Phenergan) — 12.5–25 mg deep IM or slow IV push. A potent antiemetic.","alternative": "Ondansetron (Zofran) — 4–8 mg ODT/IV/IM. Often preferred in a military setting because it is non-sedating.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What is a notable drawback of promethazine (Phenergan) for operational personnel?","choices": ["It is non-sedating","It causes significant sedation","It cannot be given IM","It has no antiemetic effect"],"answer": 1,"explain": "Promethazine causes significant sedation; deep IM is preferred over IV because of tissue necrosis risk."}]},{"id": 58,"name": "Scopolamine","brand": "Transderm Scop","aka": ["Hyoscine","Transderm Scop","Scopoderm","Hyoscine Hydrobromide"],"cat": "Antiemetics","cls": "Anticholinergic","mech": "Blocks muscarinic receptors in vestibular system","dose": "Patch: Apply 1 patch behind ear 4h before travel; replace q72h","ind": "Motion sickness prevention","contra": "Angle-closure glaucoma, GI/urinary obstruction","se": "Dry mouth, blurred vision, drowsiness, confusion (elderly)","notes": "Apply 4h before needed; wash hands after handling; do not cut patch","tccc": false,"duty": "limited","scenarios": [{"scenario": "A Special Forces team is scheduled for a 6-hour insertion via a small boat in rough seas. Several team members are prone to severe motion sickness. To prevent this, the team medic provides a prophylactic medication before departure.","context": "Real-World Context: Motion sickness is the vestibular system (inner ear) and the visual system sending conflicting signals to the brain — your eyes say the cabin is still, but your inner ear says you’re pitching and rolling. The brain interprets this mismatch as poisoning (an evolutionary holdover — if your senses don’t agree, you might have eaten a neurotoxin) and triggers nausea and vomiting to expel the “toxin.” Scopolamine blocks muscarinic acetylcholine receptors in the vomiting center and vestibular apparatus, calming the conflicting signals. The transdermal patch is the gold standard for military operations: apply it behind the ear (where skin is thin and absorption is reliable), and it quietly delivers drug for up to 72 hours without pills, injections, or timing issues. Think of it as a “set it and forget it” solution. The 4-hour lead time is critical — it takes that long for the patch to build therapeutic drug levels. Applying it when you’re already green is too late. Side effects (dry mouth, blurry vision, drowsiness) are the anticholinergic triad and are generally tolerable but should be factored into mission planning.","diagnosis": "This is Prophylaxis for Motion Sickness. The goal is to prevent the onset of nausea and vomiting during transit.","opqrst": "Not applicable. This is for prevention.","sample": "Signs/Symptoms: History of severe motion sickness. Allergies: NKDA. Medications: None. Past Pertinent History: Gets sick on boats and turbulent flights. Events: Prophylaxis for an upcoming mission.","vitals": "Within normal limits.","exam": "None indicated.","primary": "Scopolamine (Transderm Scop) — One 1.5 mg patch applied behind the ear at least 4 hours before exposure. Provides effective prevention for up to 72 hours.","alternative": "Meclizine (Dramamine II): 25–50 mg PO taken 1 hour before travel. Less effective but still a good option. Promethazine (Phenergan): Very effective but highly sedating — a poor choice for operational personnel.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "How far in advance should the scopolamine patch be applied before motion sickness exposure?","choices": ["At the first sign of nausea","About 4 hours before travel","24 hours before travel","Immediately upon boarding"],"answer": 1,"explain": "The scopolamine patch is applied behind the ear about 4 hours before travel and replaced every 72 hours; do not cut the patch and wash hands after handling."}]},{"id": 59,"name": "Meclizine","brand": "Antivert/Dramamine","aka": ["Antivert","Bonine","Sea-Legs"],"cat": "Antiemetics","cls": "H1 antihistamine, antivertigo","mech": "Depresses labyrinth excitability via H1/anticholinergic effects","dose": "25-50 mg PO q24h (motion sickness: 1h before travel)","ind": "Motion sickness, vertigo","contra": "Hypersensitivity","se": "Drowsiness (less than diphenhydramine), dry mouth","notes": "Less sedating; long duration allows once daily dosing","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "What dosing advantage does meclizine offer for motion sickness and vertigo?","choices": ["Must be dosed every 2 hours","Long duration allows once-daily dosing and is less sedating","Only works intravenously","Causes more sedation than diphenhydramine"],"answer": 1,"explain": "Meclizine is less sedating than diphenhydramine and its long duration allows convenient once-daily dosing."}]},{"id": 60,"name": "Diphenhydramine","brand": "Benadryl","aka": ["Benadryl","DPH","Diphenhydramine Hydrochloride"],"cat": "Antihistamines","cls": "First-generation H1 antihistamine","mech": "Competitively blocks H1 histamine receptors; anticholinergic effects","dose": "25-50 mg PO/IV/IM q4-6h","ind": "Allergic reactions, anaphylaxis adjunct, insomnia, drug-induced dystonia","contra": "Neonates, narrow-angle glaucoma, urinary retention","se": "Sedation, dry mouth, urinary retention, confusion (elderly)","notes": "Anaphylaxis ADJUNCT (not first-line); highly sedating","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 19-year-old Ranger candidate, on a dare, eats an unknown insect during jungle survival training. Within 10 minutes, he develops intensely itchy, raised red welts (hives) all over his arms and chest. He has no difficulty breathing, but the itching is driving him to distraction.","context": "Real-World Context: Benadryl is the grandfather of antihistamines — crude but effective, like using a sledgehammer where a scalpel might do. It blocks H1 receptors throughout the body, shutting down the itch-hive-redness cycle of an allergic reaction. But unlike newer antihistamines (Zyrtec, Allegra), Benadryl freely crosses the blood-brain barrier, which is why it earns its nickname “the 25mg downer.” However, not every patient gets drowsy — some individuals paradoxically become wired and agitated (an excitatory response), so always ask if they’ve taken it before and how they reacted. Beyond allergies, Benadryl has several off-label uses that are gold for field medics: it works as a sleep aid for personnel with acute insomnia, and injectable Benadryl can serve as a numbing agent in the absence of Lidocaine — a lifesaver when your local anesthetic supply is depleted. The IM route provides faster onset (15–20 min) versus oral (30–45 min) when you need rapid symptom control.","diagnosis": "The patient is having a Moderate Allergic Reaction manifesting as acute urticaria. The goal is to block the histamine release causing the hives and itching.","opqrst": "Onset: 10 minutes ago. Provocation: None. Quality: \"The worst itch of my life.\" Radiation: Spreading across his torso. Severity: 8/10 itch. Time: Worsening.","sample": "Signs/Symptoms: Acute urticaria (hives), severe itching. No signs of anaphylaxis (no wheezing, stridor, or hypotension). Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Unknown insect. Events: Allergic reaction to an unknown substance.","vitals": "Heart Rate: 90 bpm | Blood Pressure: 125/75 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 98.7°F","exam": "Skin exam shows diffuse wheals. Airway and lung exams are clear.","primary": "Diphenhydramine (Benadryl) — 25–50 mg PO or IM. The IM route will provide faster relief from the severe itching. This is a first-generation H1-blocker.","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What is the correct role of diphenhydramine (Benadryl) in anaphylaxis?","choices": ["First-line and replaces epinephrine","An adjunct, not first-line","Contraindicated entirely","The definitive treatment"],"answer": 1,"explain": "Diphenhydramine is an anaphylaxis ADJUNCT, not first-line; it is also highly sedating."}]},{"id": 61,"name": "Cetirizine","brand": "Zyrtec","aka": ["Zyrtec","Reactine","Cetirizine Hydrochloride"],"cat": "Antihistamines","cls": "Second-generation H1 antihistamine","mech": "Selective peripheral H1 receptor antagonist","dose": "10 mg PO daily","ind": "Allergic rhinitis, chronic urticaria","contra": "Hypersensitivity","se": "Drowsiness (mild), dry mouth, headache","notes": "Less sedating than first-gen; once daily","tccc": false,"duty": "go","scenarios": [{"scenario": "A 28-year-old Special Forces operator preparing for a surveillance mission reports that his seasonal allergies are flaring up. He has a constantly running nose, itchy eyes, and is sneezing frequently, which could compromise his team’s stealth and his own focus. He needs a non-drowsy medication.","context": "Real-World Context: An uncontrolled sneeze during a covert surveillance mission is the operational equivalent of setting off a flare gun. Seasonal allergies may seem trivial in garrison, but in the field they’re a genuine tactical liability. Cetirizine is the operator’s preferred antihistamine — think of it as a “silencer” for the immune system’s overreaction to pollen. Unlike first-generation antihistamines (Benadryl/Diphenhydramine), which are notorious for crossing the blood-brain barrier and causing heavy sedation (earning it the nickname “the 25mg downer”), second-generation agents like Cetirizine stay largely in the peripheral tissues where they’re needed. It dries the nose, stops the itch, and quiets the sneezing without dulling the mind or slowing reaction times.","diagnosis": "The patient is experiencing Allergic Rhinitis. The goal is to control symptoms with a second-generation antihistamine that has minimal sedative effects.","opqrst": "Onset: Began this morning, coinciding with high pollen counts. Provocation: Being outdoors. Quality: \"Itchy and runny.\" Radiation: Affects eyes, nose, and throat. Severity: 4/10, but a significant operational concern. Time: Constant.","sample": "Signs/Symptoms: Clear nasal discharge (rhinorrhea), itchy/watery eyes, sneezing. Allergies: Known seasonal pollen allergy. Medications: None. Past Pertinent History: Allergic rhinitis every spring. Last Oral Intake: Normal. Events: Seasonal allergy flare-up.","vitals": "Within normal limits.","exam": "Examination of the nose may show pale, swollen nasal turbinates. Eyes may be red and watery.","primary": "Zyrtec (Cetirizine) — 10 mg PO once daily. A potent, fast-acting, and generally non-drowsy second-generation antihistamine.","alternative": "Allegra (Fexofenadine) or Claritin (Loratadine): Other excellent non-drowsy options. Benadryl (Diphenhydramine): A first-generation antihistamine that is very effective but is not recommended due to its significant sedative effects (“the 25mg downer”).","avoid": "","dutyStatus": "MISSION CAPABLE. Low sedation risk, but some individuals may experience drowsiness.","onsetDuration": "Onset: 1 hour PO. Duration: 24 hours.","cognitive": "Minimal. Slightly higher sedation risk than Allegra or Claritin — may not be preferred for aircrew.","field": "Once-daily dosing is a significant operational advantage. If the operator reports drowsiness, switch to Fexofenadine (Allegra). For aircrew, Fexofenadine is the preferred antihistamine."}],"quiz": [{"q": "How is cetirizine (Zyrtec) classified relative to diphenhydramine?","choices": ["A first-generation, highly sedating antihistamine","A second-generation antihistamine that is less sedating","A corticosteroid","A decongestant"],"answer": 1,"explain": "Cetirizine is a second-generation H1 antihistamine, less sedating than first-generation agents, and dosed once daily."}]},{"id": 62,"name": "Fexofenadine","brand": "Allegra","aka": ["Allegra","Telfast","Fexofenadine Hydrochloride"],"cat": "Antihistamines","cls": "Second-generation H1 antihistamine","mech": "Selective peripheral H1 receptor antagonist","dose": "60 mg PO BID or 180 mg daily","ind": "Allergic rhinitis, chronic urticaria","contra": "Hypersensitivity","se": "Headache, nausea (minimal sedation)","notes": "Least sedating antihistamine; safe in pilots","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 33-year-old SOAR pilot wakes up with itchy, watery eyes and a runny nose due to seasonal allergies. He is scheduled for a mission later in the day and needs an effective medication that is FAA-approved and has the lowest possible risk of causing any sedation or cognitive impairment.","context": "Real-World Context: For pilots, the antihistamine hierarchy matters as much as the medication itself. Think of it as a spectrum of sedation risk: Benadryl is a hard NO (it’s essentially a sleeping pill with antihistamine benefits), Zyrtec is in a gray zone (usually non-sedating but some individuals report drowsiness), and Allegra sits at the safest end — it is specifically recognized by aviation medicine authorities as the least sedating second-generation antihistamine. The pharmacological reason: Fexofenadine has the poorest penetration of the blood-brain barrier of any antihistamine, meaning it stays in the peripheral tissues where allergies happen and doesn’t touch the brain where cognition and reaction time live. For a SOAR pilot flying a helicopter at night with NVGs, even a 5% cognitive impairment could be catastrophic. This makes Fexofenadine the default “mission-safe” antihistamine for any operator who cannot afford the slightest edge taken off their performance.","diagnosis": "The patient has Allergic Rhinitis. The choice of medication is critical due to his flight status, requiring a proven non-sedating antihistamine.","opqrst": "Onset: This morning. Provocation: High pollen environment. Quality: \"Itchy and runny.\" Radiation: Affects eyes and nose. Severity: 3/10, but unacceptable for flight duties. Time: Constant.","sample": "Signs/Symptoms: Allergic rhinitis symptoms. Allergies: Seasonal pollen. Medications: None. Past Pertinent History: Occurs every year. Last Oral Intake: Breakfast. Events: Allergy flare-up.","vitals": "Within normal limits.","exam": "Consistent with mild allergic rhinitis.","primary": "Fexofenadine (Allegra) — 180 mg PO once daily. Known for being one of the least likely to cause drowsiness, making it a preferred choice for pilots and those in critical roles.","alternative": "Loratadine (Claritin): Another acceptable non-sedating option. Cetirizine (Zyrtec): Effective, but slightly higher incidence of drowsiness compared to Allegra and Claritin and may be less preferred for aircrew.","avoid": "Diphenhydramine (Benadryl) is strictly contraindicated due to sedation.","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Why is fexofenadine (Allegra) the preferred antihistamine for pilots and aircrew?","choices": ["It is the most potent decongestant","It is the least sedating antihistamine and safe in pilots","It causes the most sedation","It must be taken every 2 hours"],"answer": 1,"explain": "Fexofenadine is recognized as the least sedating antihistamine, making it the preferred and flight-safe choice for aircrew."}]},{"id": 63,"name": "Loratadine","brand": "Claritin","aka": ["Claritin","Clarityn"],"cat": "Antihistamines","cls": "Second-generation H1 antihistamine","mech": "Selective peripheral H1 receptor antagonist","dose": "10 mg PO daily","ind": "Allergic rhinitis, chronic urticaria","contra": "Hypersensitivity","se": "Headache, dry mouth (minimal sedation)","notes": "Non-sedating; preferred in pregnancy","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 35-year-old Civil Affairs medic is conducting a MEDCAP. She develops mild, but distracting, seasonal allergy symptoms from the local flora, including an itchy nose and sneezing. She needs to take something that will not make her drowsy so she can continue to safely assess and treat patients.","context": "Real-World Context: Loratadine is the “everyman’s non-drowsy antihistamine” — it sits in the sweet spot between effectiveness and accessibility. Think of the second-generation antihistamine lineup as a team: Allegra (Fexofenadine) is the gold standard for zero sedation and flight-approved, Zyrtec (Cetirizine) is the most potent but has the highest drowsiness risk of the three, and Claritin (Loratadine) is the reliable middle ground that’s available everywhere, even in host-nation pharmacies during MEDCAPs. For a medic who needs to stay sharp while assessing patients, any of the three work, but Loratadine’s near-universal OTC availability makes it the easiest to resupply in austere environments. The mechanism is identical across all three: selective peripheral H1-receptor blockade without significant central nervous system penetration. The key teaching point: all second-generation antihistamines are superior to Benadryl for operational use because they don’t cross the blood-brain barrier in significant amounts.","diagnosis": "The patient has mild Allergic Rhinitis. The priority is symptom control with a non-sedating antihistamine to allow her to continue her mission.","opqrst": "Onset: Within an hour of arriving at the village. Provocation: Pollen in the air. Quality: \"Itchy and sneezy.\" Radiation: Localized to nose/eyes. Severity: 3/10. Time: Constant.","sample": "Signs/Symptoms: Allergic rhinitis. Allergies: Known seasonal allergies. Medications: None. Past Pertinent History: Takes allergy pills as needed during the spring. Last Oral Intake: MRE. Events: Allergy flare-up.","vitals": "Within normal limits.","exam": "Mild conjunctival injection (red eyes) and clear nasal discharge.","primary": "Claritin (Loratadine) — 10 mg PO once daily. A second-generation antihistamine well-known for its non-sedating properties, making it a safe choice during operations.","alternative": "Fexofenadine (Allegra) or Cetirizine (Zyrtec). All are good second-generation options.","avoid": "Diphenhydramine (Benadryl) due to its significant sedative effects.","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Which antihistamine is specifically noted as preferred in pregnancy?","choices": ["Diphenhydramine","Loratadine","Cetirizine","Promethazine"],"answer": 1,"explain": "Loratadine is a non-sedating second-generation antihistamine noted as preferred in pregnancy."}]},{"id": 64,"name": "Dexamethasone","brand": "Decadron","aka": ["Decadron","Dexamethasone Sodium Phosphate","Dex"],"cat": "Corticosteroids","cls": "Long-acting glucocorticoid","mech": "Suppresses inflammation and immune response; 36x potency of hydrocortisone","dose": "Croup: 0.6 mg/kg; HACE: 8 mg then 4 mg q6h; Airway edema: 10 mg IV","ind": "Croup, HACE, airway edema, anaphylaxis adjunct, meningitis","contra": "Systemic fungal infections","se": "Hyperglycemia, immunosuppression, adrenal suppression","notes": "Long half-life (36-72h); single dose often sufficient","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 35-year-old Civil Affairs Captain has been operating at 12,000 feet for two days. She presents with a severe headache, nausea, and marked ataxia (stumbling, loss of balance). Her team notes she has become increasingly confused and lethargic.","context": "Real-World Context: High-Altitude Cerebral Edema is the brain swelling from altitude sickness taken to its lethal extreme — think of it as the brain becoming a waterlogged sponge inside a rigid box. At high altitude, low oxygen causes blood vessels in the brain to dilate and leak fluid into brain tissue. Mild cases present as Acute Mountain Sickness (headache, nausea); HACE is when that process spirals into confusion, ataxia, and eventually coma and death. Dexamethasone is the chemical bridge that buys time while you do the only thing that truly saves the patient: descend. It’s a powerful anti-inflammatory steroid that reduces the vasogenic edema (vessel leakage) causing the brain swelling. Think of it as plugging the leaks in the dam while you work to lower the water level (descent). The ataxia test (tandem gait: walking heel-to-toe) is the critical field screening tool — a patient who can’t walk a straight line at altitude is assumed to have HACE until proven otherwise. Acetazolamide works for prevention and mild AMS but is not powerful enough for HACE.","diagnosis": "This casualty is exhibiting classic signs of High-Altitude Cerebral Edema (HACE), a life-threatening emergency. The definitive treatment is immediate descent.","opqrst": "Onset: Gradual over the past 12 hours. Provocation: Exertion and altitude. Quality: \"The worst headache of my life.\" Radiation: Headache is global. Severity: 9/10 headache. Time: Progressively worsening.","sample": "Signs/Symptoms: Ataxia, confusion, lethargy, severe headache, nausea. Allergies: NKDA. Medications: Ibuprofen for headache with no relief. Past Pertinent History: None. Last Oral Intake: Water, 1 hour ago. Events: Rapid ascent to high altitude.","vitals": "Heart Rate: 95 bpm | Blood Pressure: 130/80 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 88% on room air | Temperature: 99.1°F","exam": "Neurological assessment for ataxia (tandem gait test), level of consciousness, and cognitive function. Auscultate lungs for signs of HAPE (crackles).","primary": "Dexamethasone — 8 mg PO/IM/IV once, then 4 mg every 6 hours. Reduces swelling in the brain but does not fix the underlying cause.","alternative": "Acetazolamide can be used for prevention and treatment of milder forms of altitude sickness but is not the primary drug for life-threatening HACE.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario": "A medic is managing a 20-year-old Ranger with suspected bacterial meningitis (high fever, stiff neck, altered mental status). Before or concurrently with the first dose of antibiotics, the medic needs to administer a steroid to reduce the inflammation that causes neurological damage.","context": "Real-World Context: Bacterial meningitis is a race against the clock inside the skull. The bacteria themselves are dangerous, but much of the brain damage comes from the body’s own inflammatory response to the infection — think of it as the immune system’s SWAT team causing collateral damage in a hostage situation. When antibiotics kill the bacteria, they burst open and release their cell wall components, triggering an even MORE intense inflammatory reaction (a paradoxical worsening). Dexamethasone given BEFORE or WITH the first antibiotic dose acts as a “flash suppressor” on this inflammatory explosion, reducing the collateral damage to brain tissue, and most importantly, protecting hearing (meningitis-related hearing loss is the most common permanent sequela). The timing is critical: if Dexamethasone is given hours after antibiotics, it loses much of its protective benefit. In a barracks setting, meningitis can spread like wildfire through close-quarters living, so the medic should also be thinking about prophylaxis for close contacts.","diagnosis": "The patient has suspected Bacterial Meningitis, a life-threatening neurological emergency. Treatment involves immediate high-dose antibiotics. Dexamethasone is given to reduce the risk of hearing loss and other neurological sequelae from the intense inflammation.","opqrst": "Patient is lethargic and confused, unable to give a history.","sample": "Signs/Symptoms: High fever, nuchal rigidity (stiff neck), photophobia, petechial rash, altered mental status. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Rapid onset of severe illness in a barracks setting.","vitals": "Heart Rate: 120 bpm | Blood Pressure: 100/60 mmHg | Respiratory Rate: 24 breaths/min | SpO2: 95% on room air | Temperature: 103.8°F","exam": "Assess for Kernig’s and Brudzinski’s signs (indicators of meningeal irritation). Perform a full neurological exam.","primary": "Decadron (Dexamethasone) — 10 mg IV administered 15–20 minutes before or at the same time as the first dose of antibiotics. Continue for 4 days.","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Dexamethasone is roughly how many times more potent than hydrocortisone?","choices": ["About 5 times","About 36 times","Equal potency","About 100 times"],"answer": 1,"explain": "Dexamethasone has roughly 36x the glucocorticoid potency of hydrocortisone and a long half-life, so a single dose is often sufficient."}]},{"id": 65,"name": "Prednisone","brand": "Deltasone","aka": ["Deltasone"],"cat": "Corticosteroids","cls": "Intermediate-acting glucocorticoid","mech": "Suppresses inflammation and immune response","dose": "40-60 mg PO daily x 5-14 days; Poison ivy: taper 60/40/20 mg over 15 days","ind": "Asthma exacerbation, COPD, severe poison ivy, urticaria","contra": "Systemic fungal infections","se": "Hyperglycemia, fluid retention, psychiatric disturbances","notes": "Oral steroid of choice; requires hepatic conversion to prednisolone","tccc": false,"duty": "limited","scenarios": [{"scenario": "While on patrol, a 22-year-old Ranger brushes up against a large patch of poison ivy. Two days later, he has a severe, blistering rash on his arms and face. The itching is unbearable, and the swelling around his eyes is beginning to affect his vision.","context": "Real-World Context: Severe poison ivy is the immune system waging war against an allergen (urushiol oil) that’s already been absorbed and bonded to skin proteins. Think of it as the body carpet-bombing its own skin to destroy the foreign invader. Topical steroids on a severe case are like trying to fight a forest fire with a garden hose — you need a systemic approach. Prednisone taken orally floods the bloodstream with corticosteroid that suppresses the entire inflammatory cascade throughout the body. The CRITICAL teaching point: the taper. Stopping Prednisone abruptly after more than a few days suppresses the adrenal glands’ natural cortisol production. More importantly for poison ivy, the urushiol-triggered immune reaction lasts 2–3 weeks — if you stop the steroid too early (the classic Medrol Dosepak mistake: only 6 days), the inflammation roars back worse than before because the immune response is still active but the suppression is gone. A proper 14–21 day taper matches the natural timeline of the immune reaction.","diagnosis": "The patient is having a Severe Allergic Contact Dermatitis from poison ivy. A topical steroid is insufficient. The systemic inflammation needs to be suppressed with an oral corticosteroid.","opqrst": "Onset: Began 24 hours ago, rapidly worsened. Provocation: None. Quality: \"The worst itch imaginable.\" Radiation: Spreading. Severity: 9/10 itch. Time: Constant.","sample": "Signs/Symptoms: Vesicular, weeping, erythematous rash in linear streaks. Severe edema, especially on the face. Intense itching. Allergies: NKDA. Medications: Has tried topical hydrocortisone cream with no effect. Past Pertinent History: Known severe reaction to poison ivy. Events: Allergic contact dermatitis.","vitals": "Within normal limits.","exam": "Skin exam reveals classic poison ivy dermatitis. Assess for airway involvement if there is significant facial swelling.","primary": "Prednisone — 40–60 mg PO once daily. A long taper is crucial. A typical course is 14–21 days, slowly decreasing the dose every few days. Stopping the steroid too early will result in a severe rebound flare.","alternative": "Other oral steroids like Methylprednisolone (Medrol Dosepak). An IM injection of a long-acting steroid like Kenalog can also be used.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Why does oral prednisone require hepatic activation?","choices": ["It is destroyed by stomach acid","It must be converted to prednisolone in the liver","It binds calcium first","It is excreted unchanged"],"answer": 1,"explain": "Prednisone is the oral steroid of choice but requires hepatic conversion to its active form, prednisolone."}]},{"id": 66,"name": "Methylprednisolone","brand": "Solu-Medrol","aka": ["Solu-Medrol","Medrol","Depo-Medrol","Methylprednisolone Sodium Succinate"],"cat": "Corticosteroids","cls": "Intermediate-acting glucocorticoid","mech": "Suppresses inflammation; less sodium retention than hydrocortisone","dose": "Anaphylaxis/angioedema: 1-2 mg/kg IV; Asthma: 40-60 mg IV daily","ind": "Anaphylaxis, asthma exacerbation, COPD exacerbation","contra": "Systemic fungal infections","se": "Hyperglycemia, GI upset, psychiatric disturbances","notes": "IV form of choice for acute situations","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 26-year-old Ranger with a known, severe allergy to fire ants is on patrol when he is stung multiple times. His partner immediately administers an EpiPen. The medic arrives 5 minutes later. The Ranger’s breathing has improved, but he is still covered in hives and is anxious.","context": "Real-World Context: Solu-Medrol after Epinephrine is like calling in the reinforcements after the first responders have contained the immediate threat. Epinephrine is the life-saver that stops the acute crisis, but its effects wear off in 15–20 minutes. The real danger that Solu-Medrol addresses is the “biphasic reaction” — a second wave of anaphylaxis that can hit 4–12 hours after the initial event, sometimes even more severe than the first. Think of the immune system as a crowd that was temporarily calmed by Epinephrine but is still angry; Solu-Medrol is the long-acting suppression that prevents the crowd from rioting again. It works by broadly suppressing the inflammatory cascade at the cellular level — blocking cytokine production, reducing immune cell activation, and stabilizing cell membranes so they stop dumping histamine. The onset is slow (4–6 hours for full effect), which is exactly why it MUST be given early: by the time you need it to work, it’s too late to give it. Every anaphylaxis patient should be monitored for at least 6–8 hours after the event for this reason.","diagnosis": "The patient is recovering from Anaphylaxis after appropriate first-line treatment with Epinephrine. The next step is to administer adjunctive medications to prevent a biphasic (late-phase) reaction and help resolve the remaining symptoms.","opqrst": "Onset: 5 minutes ago. Provocation: Fire ant stings. Quality: \"Itchy all over.\" Radiation: Hives are widespread. Severity: 5/10 distress (improved after Epi). Time: Ongoing.","sample": "Signs/Symptoms: Widespread urticaria, mild residual wheezing. Allergies: Fire ants. Medications: Just received 0.3mg of Epinephrine IM. Past Pertinent History: Anaphylaxis. Events: Allergic reaction.","vitals": "Heart Rate: 110 bpm (effect of both allergy and Epi) | Blood Pressure: 110/70 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 96% on room air","exam": "Assess airway, breathing, and circulation. Confirm Epi was given correctly.","primary": "Solu-Medrol (Methylprednisolone) — 125 mg IV/IM. This systemic corticosteroid suppresses the body’s inflammatory response. It does not work immediately but is crucial for preventing a rebound reaction hours later.","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "For acute anaphylaxis or asthma exacerbation, what is methylprednisolone (Solu-Medrol) noted as?","choices": ["The oral steroid of choice","The IV form of choice for acute situations","A topical-only steroid","A short-acting nasal spray"],"answer": 1,"explain": "Methylprednisolone is the IV corticosteroid of choice for acute situations and causes less sodium retention than hydrocortisone."}]},{"id": 67,"name": "Hydrocortisone","brand": "Cortef/Solu-Cortef","aka": ["Solu-Cortef","Cortef","Hydrocortisone Sodium Succinate"],"cat": "Corticosteroids","cls": "Short-acting glucocorticoid","mech": "Replaces physiologic cortisol; mineralocorticoid effects","dose": "Adrenal crisis: 100 mg IV then 50 mg q6-8h; Stress dosing: varies","ind": "Adrenal insufficiency, adrenal crisis, stress dosing","contra": "Systemic fungal infections","se": "Sodium/water retention, hyperglycemia","notes": "Physiologic replacement; has mineralocorticoid activity","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 39-year-old Special Forces Warrant Officer, known to be on long-term prednisone for an autoimmune condition, becomes ill with a stomach bug. He is now profoundly weak, confused, vomiting, and complaining of abdominal pain. His team calls the medic when he becomes hypotensive.","context": "Real-World Context: Adrenal crisis is one of the most deceptive emergencies in medicine — it masquerades as sepsis, dehydration, or a bad stomach virus, but the underlying mechanism is completely different, and the treatment is uniquely specific. Think of cortisol as the body’s “stress hormone battery.” Normally, when the body faces illness or injury, the adrenal glands surge cortisol production to maintain blood pressure, blood sugar, and organ function. A patient on chronic prednisone has had their adrenal glands effectively shut down from disuse — the external steroid told the glands “I’ve got this, you can rest.” When that external supply is suddenly cut off (missed doses due to vomiting), the body faces physiological stress with zero cortisol reserves. Blood pressure crashes, blood sugar plummets, and the patient spirals into shock that will NOT respond to fluids alone. Hydrocortisone is chosen specifically because it provides BOTH glucocorticoid (stress response) AND mineralocorticoid (salt/water retention for blood pressure) effects — it’s the closest thing to what the adrenal gland would naturally produce.","diagnosis": "The casualty is in Acute Adrenal Crisis (Addisonian Crisis). His body, accustomed to external steroids, cannot produce its own cortisol to handle the stress of the illness, leading to cardiovascular collapse.","opqrst": "Patient is lethargic and confused, unable to provide clear history.","sample": "Signs/Symptoms: Profound weakness, confusion, vomiting, abdominal pain, fever, hypotension. Allergies: NKDA. Medications: Takes prednisone daily (has missed doses due to vomiting). Past Pertinent History: Chronic inflammatory condition. Events: Minor illness coupled with missed steroid doses.","vitals": "Heart Rate: 115 bpm | Blood Pressure: 80/50 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 96% | Temperature: 101.5°F","exam": "Assess for signs of severe dehydration. Check blood glucose (may be low). Note that the patient is in shock unresponsive to fluids alone.","primary": "Hydrocortisone (Solu-Cortef) — 100 mg IV/IM push. Provides both the glucocorticoid and mineralocorticoid activity needed to stabilize the patient.","alternative": "Dexamethasone — 4–8 mg IV/IM. Can be used if hydrocortisone is unavailable, but it lacks the mineralocorticoid effects, so the patient’s blood pressure may not respond as well.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Why is hydrocortisone preferred over dexamethasone in adrenal crisis?","choices": ["It is longer acting","It has mineralocorticoid activity for physiologic replacement","It has no glucocorticoid effect","It is non-steroidal"],"answer": 1,"explain": "Hydrocortisone replaces physiologic cortisol and has mineralocorticoid activity, helping support blood pressure in adrenal crisis."}]},{"id": 68,"name": "Fluticasone (Corticosteroid)","brand": "Flonase/Flovent","aka": ["Flovent","Flixotide","Fluticasone Propionate"],"cat": "Corticosteroids","cls": "Inhaled corticosteroid","mech": "Reduces airway and nasal inflammation","dose": "Nasal: 1-2 sprays per nostril daily; Inhaled: 88-440 mcg BID","ind": "Allergic rhinitis, asthma maintenance","contra": "Primary treatment of status asthmaticus","se": "Oral candidiasis, hoarseness, epistaxis","notes": "NOT for acute attacks; takes days-weeks for full effect","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 38-year-old Navy Corpsman suffers from chronic, year-round nasal congestion and sinus pressure due to perennial allergies. It affects his sleep and sense of smell. He has tried oral antihistamines, but they only provide partial relief. He needs a long-term maintenance therapy.","context": "Real-World Context: If antihistamines are the infantry of allergy treatment — quick to deploy, good for acute firefights — then nasal corticosteroids like Fluticasone are the engineering corps: they rebuild the defensive infrastructure. Oral antihistamines block ONE mediator (histamine), but allergic rhinitis involves dozens of inflammatory chemicals. Fluticasone suppresses the entire inflammatory cascade at the source, right inside the nasal mucosa. Think of it as calming down an inflamed, overreacting neighborhood rather than just blocking one troublemaker. The critical patient education point: it’s NOT a rescue spray. It takes 3–7 days of consistent daily use to reach full effect, and stopping it means the inflammation roars back. Many patients give up after 2 days saying “it doesn’t work” — they need to understand it’s building a foundation, not putting out a fire. For operators, the beauty is that the drug stays local in the nasal passages with minimal systemic absorption, so there are virtually no sedation or cognitive effects.","diagnosis": "The patient has Chronic Allergic Rhinitis. When oral antihistamines are insufficient, the first-line treatment for moderate to severe or persistent symptoms is a nasal corticosteroid spray.","opqrst": "Not applicable. This is a chronic condition.","sample": "Signs/Symptoms: Persistent nasal congestion, sinus pressure, post-nasal drip. Allergies: Dust mites, mold. Medications: Cetirizine (Zyrtec) as needed. Past Pertinent History: Chronic allergic rhinitis. Last Oral Intake: Normal. Events: Seeking a more effective daily treatment.","vitals": "Within normal limits.","exam": "Nasal exam shows swollen, pale turbinates and clear mucus.","primary": "Flonase (Fluticasone) — 1–2 sprays in each nostril once daily. Reduces local inflammation in the nasal passages. Can take several days to reach full effect and must be used consistently.","alternative": "Nasonex (Mometasone) or Rhinocort (Budesonide): Other nasal steroid sprays that are equally effective.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What key counseling point applies to inhaled/nasal fluticasone (corticosteroid)?","choices": ["It works instantly for acute attacks","It takes days to weeks for full effect and is not for acute attacks","It must be injected","It replaces rescue inhalers"],"answer": 1,"explain": "Fluticasone is a maintenance inhaled corticosteroid that takes days to weeks for full effect and is NOT for acute attacks."}]},{"id": 69,"name": "Omeprazole","brand": "Prilosec","aka": ["Prilosec","Losec","Omeprazole Magnesium"],"cat": "GI Drugs","cls": "Proton pump inhibitor","mech": "Inhibits gastric H+/K+-ATPase (proton pump)","dose": "20-40 mg PO daily or BID","ind": "GERD, peptic ulcer disease, H. pylori, stress ulcer prophylaxis","contra": "Hypersensitivity","se": "Headache, C. diff risk, B12 deficiency, bone fractures (chronic)","notes": "Take 30-60 min before meals; long-term use concerns","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 48-year-old Special Forces Team Sergeant complains of frequent, burning chest pain and a chronic cough, especially at night. It’s worse after eating spicy food or drinking coffee. Antacids like Tums provide only temporary relief.","context": "Real-World Context: If antacids (Maalox, Tums) are fire extinguishers that neutralize acid already in the stomach, and H2 blockers (Famotidine) are dimmer switches that partially reduce acid production, then Proton Pump Inhibitors like Omeprazole are the “off switch” for the acid pumps themselves. PPIs irreversibly bind to and disable the hydrogen-potassium ATPase pumps on the stomach’s parietal cells — the actual machinery that manufactures stomach acid. Think of it as shutting down the factory rather than mopping up the product. The 30-minutes-before-breakfast timing is critical: PPIs only work on actively pumping acid pumps, and the first meal of the day activates the most pumps. Taking it with food or at bedtime dramatically reduces its effectiveness. The chronic cough in this scenario is a GERD red flag that many medics miss — acid refluxing up to the larynx (laryngopharyngeal reflux) causes a chronic irritative cough that mimics respiratory disease.","diagnosis": "The patient has chronic Gastroesophageal Reflux Disease (GERD). The goal is to reduce stomach acid production to allow the esophagus to heal and control symptoms long-term.","opqrst": "Onset: Chronic, for years, but worsening. Provocation: Lying down, certain foods. Quality: \"Burning.\" Radiation: Up into the throat. Severity: 5/10. Time: Most prominent after meals and at night.","sample": "Signs/Symptoms: Heartburn, regurgitation, chronic cough. Allergies: NKDA. Medications: Tums as needed. Past Pertinent History: None. Last Oral Intake: Dinner 2 hours ago. Events: Chronic reflux.","vitals": "Within normal limits.","exam": "Abdominal exam is benign. No signs of an acute cardiac event.","primary": "Prilosec (Omeprazole) — 20 mg PO once daily, taken 30 minutes before the first meal of the day. A Proton Pump Inhibitor (PPI) that provides powerful, long-lasting acid suppression.","alternative": "Other PPIs (e.g., Aciphex, Protonix, Nexium): All work similarly. H2 Blockers (e.g., Famotidine): Can also be used but are generally less potent than PPIs.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "When should omeprazole (Prilosec) be taken for maximum effectiveness?","choices": ["At bedtime with food","30-60 minutes before meals","Only with antacids","Any time, timing does not matter"],"answer": 1,"explain": "Omeprazole, a proton pump inhibitor, should be taken 30-60 minutes before meals; chronic use carries B12 deficiency and fracture concerns."}]},{"id": 70,"name": "Rabeprazole","brand": "Aciphex","aka": ["Aciphex","Pariet","Rabeprazole Sodium"],"cat": "GI Drugs","cls": "Proton pump inhibitor","mech": "Inhibits gastric proton pump","dose": "20 mg PO daily","ind": "GERD, peptic ulcer disease","contra": "Hypersensitivity","se": "Similar to omeprazole","notes": "Alternative PPI; similar efficacy","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 42-year-old SARC medic complains of a chronic burning pain behind his sternum, which is diagnosed as GERD. He has tried lifestyle modifications and H2 blockers like famotidine with only partial success.","context": "Real-World Context: When H2 blockers fail to control GERD, it’s like trying to hold back a river with sandbags — they help, but the water keeps coming. Rabeprazole represents the escalation to a PPI, which fundamentally changes the approach from partially blocking acid production to nearly eliminating it. All PPIs (Omeprazole, Rabeprazole, Pantoprazole, etc.) work through the same mechanism, so the choice often comes down to formulary availability and cost rather than clinical superiority. Think of them as different brands of the same tool. Rabeprazole has a slightly faster onset of acid suppression compared to some other PPIs, which can matter for symptom relief in the first few days. The clinical teaching point: GERD isn’t just about comfort. Chronic, untreated acid exposure to the esophagus causes Barrett’s esophagus (precancerous cellular changes), strictures (scar narrowing), and erosive esophagitis. Long-term PPI use has its own risks (bone density loss, magnesium depletion, C. diff risk), so the goal is the lowest effective dose for the shortest necessary duration.","diagnosis": "The patient has GERD refractory to H2-blocker therapy. The standard of care is to escalate to a Proton Pump Inhibitor (PPI).","opqrst": "Onset: Chronic, for several years. Provocation: Large meals, caffeine. Quality: \"Burning.\" Radiation: None. Severity: 5/10. Time: Intermittent.","sample": "Signs/Symptoms: Heartburn, dyspepsia. Allergies: NKDA. Medications: Famotidine (partially effective). Past Pertinent History: Diagnosed GERD. Last Oral Intake: Normal. Events: Seeking more effective long-term treatment.","vitals": "Within normal limits.","exam": "Benign.","primary": "Aciphex (Rabeprazole) — 20 mg PO once daily. Like other PPIs, it provides superior and more sustained acid suppression compared to H2 blockers.","alternative": "Any other PPI: Omeprazole (Prilosec), Lansoprazole (Prevacid), Pantoprazole (Protonix), or Esomeprazole (Nexium). The choice often comes down to cost or formulary availability.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "How does rabeprazole (Aciphex) compare to omeprazole?","choices": ["It is a different drug class","It is an alternative PPI with similar efficacy","It is an antacid","It is an H2 blocker"],"answer": 1,"explain": "Rabeprazole is another proton pump inhibitor with efficacy similar to omeprazole, often chosen by formulary availability."}]},{"id": 71,"name": "Cimetidine","brand": "Tagamet","aka": ["Tagamet"],"cat": "GI Drugs","cls": "H2 receptor antagonist","mech": "Competitively inhibits histamine at gastric H2 receptors","dose": "200-800 mg PO BID-QID","ind": "GERD, peptic ulcer, heartburn","contra": "Hypersensitivity","se": "Headache, dizziness, drug interactions (CYP450)","notes": "Many drug interactions; ranitidine preferred when available","tccc": false,"duty": "go","scenarios": [{"scenario": "A 36-year-old attached support individual develops multiple large, itchy welts (hives) on his arms and torso after eating a local shellfish dish for the first time. He has no difficulty breathing or swelling of the throat. The medic has already given him Benadryl.","context": "Real-World Context: Most medics think of H2 blockers like Cimetidine purely as heartburn drugs, but they have a hidden talent. Histamine operates through two receptor types — H1 receptors (which Benadryl blocks) control itching, swelling, and bronchoconstriction, while H2 receptors (which Cimetidine blocks) are found on blood vessels and contribute to the flushing and vascular dilation of allergic reactions. Think of treating urticaria like turning off a two-faucet sink: Benadryl closes the H1 faucet, and Cimetidine closes the H2 faucet. Together, they shut down the histamine flood more completely than either alone. The critical assessment here is continuously monitoring for progression to anaphylaxis — any throat tightness, voice changes, wheezing, or hemodynamic instability demands Epinephrine immediately.","diagnosis": "The patient has Acute Urticaria from a food allergy. Treatment involves blocking the effects of histamine. While H1 blockers (like Benadryl) are the primary treatment, adding an H2 blocker can have an additive effect.","opqrst": "Onset: 15 minutes after eating. Provocation: None. Quality: \"Intensely itchy.\" Radiation: Appearing on arms, chest, and back. Severity: 6/10 itch. Time: Spreading.","sample": "Signs/Symptoms: Urticaria (hives). No shortness of breath, wheezing, or throat tightness. Allergies: Newly discovered shellfish allergy. Medications: Just received 50mg of Diphenhydramine (Benadryl). Past Pertinent History: None. Last Oral Intake: Shellfish 15 minutes ago. Events: Mild to moderate allergic reaction.","vitals": "Heart Rate: 85 bpm | Blood Pressure: 130/75 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam": "Skin exam shows characteristic raised, red, blanching wheals. Lung and throat exams are clear, with no signs of anaphylaxis.","primary": "Diphenhydramine (Benadryl) — 25–50 mg PO/IM/IV. (Already given).","alternative": "Famotidine (Pepcid): 20 mg PO/IV. Often preferred over Cimetidine due to fewer drug interactions.","avoid": "","dutyStatus": "FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration": "Onset: 1 hour PO, faster IV. Duration: 4–8 hours.","cognitive": "None at standard doses.","field": "H2-blocker used as an adjunct to H1-blockers (Benadryl, Zyrtec) for refractory hives — the dual-blockade approach. Can inhibit cytochrome P450 enzymes, affecting metabolism of other drugs. Famotidine (Pepcid) is often preferred for fewer drug interactions."}],"quiz": [{"q": "What is a notable drawback of cimetidine (Tagamet) compared with other H2 blockers?","choices": ["It has no acid-suppressing effect","It has many drug interactions via CYP450 inhibition","It must be given IV only","It causes severe sedation"],"answer": 1,"explain": "Cimetidine inhibits CYP450 enzymes causing many drug interactions; famotidine is preferred when available."}]},{"id": 72,"name": "Aluminum Hydroxide/Magnesium Hydroxide","brand": "Maalox","aka": ["Maalox","Mylanta"],"cat": "GI Drugs","cls": "Antacid","mech": "Neutralizes gastric acid; increases gastric pH","dose": "10-20 mL PO PRN; max 80 mL/day","ind": "Heartburn, dyspepsia, GERD symptom relief","contra": "Severe renal impairment","se": "Diarrhea (Mg), constipation (Al), electrolyte imbalances","notes": "Combination balances diarrhea/constipation effects; immediate relief","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "Why is the aluminum hydroxide and magnesium hydroxide combination (Maalox) used together?","choices": ["To increase sedation","The combination balances diarrhea and constipation effects","Magnesium neutralizes aluminum toxicity","To prolong onset of relief"],"answer": 1,"explain": "Magnesium tends to cause diarrhea and aluminum tends to cause constipation, so the combination balances these effects while giving immediate acid relief."}]},{"id": 73,"name": "Bismuth Subsalicylate","brand": "Pepto-Bismol","aka": ["Pepto-Bismol","Kaopectate"],"cat": "GI Drugs","cls": "Antidiarrheal, antisecretory","mech": "Antisecretory; mild antimicrobial; forms protective coating","dose": "524 mg (30 mL or 2 tabs) q30-60min PRN (max 8 doses/24h)","ind": "Travelers diarrhea, dyspepsia, H. pylori adjunct","contra": "Aspirin allergy, children with viral illness, anticoagulants","se": "Black stool/tongue (harmless), tinnitus","notes": "Contains salicylate; black stool/tongue is normal","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "Bismuth subsalicylate (Pepto-Bismol) is contraindicated in which patient because it contains salicylate?","choices": ["A patient with a headache","A patient with aspirin allergy","A patient with mild dehydration","A patient on acetaminophen"],"answer": 1,"explain": "Bismuth subsalicylate contains salicylate, so it is contraindicated in aspirin allergy, in children with viral illness, and with anticoagulants; harmless black stool/tongue is expected."}]},{"id": 74,"name": "Loperamide","brand": "Imodium","aka": ["Imodium","Loperamide Hydrochloride"],"cat": "GI Drugs","cls": "Antidiarrheal","mech": "Peripheral opioid agonist; slows GI motility","dose": "4 mg PO initially, then 2 mg after each loose stool (max 16 mg/day)","ind": "Acute diarrhea, travelers diarrhea","contra": "Bloody diarrhea, fever, bacterial enterocolitis, C. diff","se": "Constipation, abdominal cramps","notes": "AVOID in invasive diarrhea (bloody/febrile)","tccc": false,"duty": "limited","scenarios": [{"scenario": "An Air Force Combat Controller is on day two of a mission and develops bothersome, but not severe, diarrhea. He has no fever, no blood in his stool, and no significant abdominal pain. He needs to control the symptoms to remain effective.","context": "Real-World Context: Loperamide is the tactical “cork” for the gut — it works by activating opioid receptors in the intestinal wall (the same receptors that make constipation a side effect of every opioid). This slows peristalsis dramatically, giving the intestines time to absorb water and firm up the stool. Think of it as switching the bowel from “rapids” mode to “lazy river.” For an operator on a mission where bathroom breaks are impossible or operationally dangerous, Loperamide provides hours of symptom-free function. The critical safety guardrail: NEVER use Loperamide if the patient has a high fever, bloody stool (dysentery), or signs of severe infection. In invasive bacterial diarrhea (Shigella, Salmonella, C. diff), slowing gut motility traps the bacteria and their toxins inside, potentially causing toxic megacolon — a life-threatening condition. Loperamide is for “nuisance” diarrhea only; anything with red flags (fever, blood, severe pain) requires antibiotics, not a plug.","diagnosis": "The patient has mild, uncomplicated Traveler’s Diarrhea. The goal is symptomatic control to maintain operational status.","opqrst": "Onset: This morning. Provocation: None. Quality: \"Watery.\" Radiation: None. Severity: 3/10 annoyance. Time: Intermittent episodes.","sample": "Signs/Symptoms: Watery diarrhea, 3–4 episodes. No other symptoms. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Mild, non-infectious appearing traveler’s diarrhea.","vitals": "Within normal limits.","exam": "Abdomen is soft, non-tender, with normal bowel sounds.","primary": "Imodium (Loperamide) — 4 mg PO initially, followed by 2 mg after each subsequent loose stool. Do not exceed 8 mg in 24 hours in a field setting. Works by slowing down gut motility.","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "When should loperamide (Imodium) be AVOIDED?","choices": ["Mild watery traveler's diarrhea","Bloody or febrile (invasive) diarrhea","Diarrhea without fever","Non-bloody loose stools"],"answer": 1,"explain": "Loperamide slows gut motility and must be avoided in invasive diarrhea (bloody or febrile) and C. diff, where it can cause toxic megacolon."}]},{"id": 75,"name": "Docusate","brand": "Colace","aka": ["Colace","Docusate Sodium","DSS","Dioctyl Sodium Sulfosuccinate"],"cat": "GI Drugs","cls": "Stool softener","mech": "Surfactant that allows water penetration into stool","dose": "100-300 mg PO daily","ind": "Constipation prevention, avoiding straining","contra": "Intestinal obstruction","se": "Diarrhea, abdominal cramps","notes": "Prevents constipation; not for acute treatment","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "What is the intended role of docusate (Colace)?","choices": ["Acute treatment of severe constipation","A stool softener for constipation prevention and avoiding straining","A stimulant laxative for rapid evacuation","An antidiarrheal"],"answer": 1,"explain": "Docusate is a surfactant stool softener used to prevent constipation and avoid straining; it is not for acute treatment."}]},{"id": 76,"name": "Bisacodyl","brand": "Dulcolax","aka": ["Dulcolax"],"cat": "GI Drugs","cls": "Stimulant laxative","mech": "Stimulates intestinal peristalsis","dose": "5-15 mg PO or 10 mg PR","ind": "Constipation, bowel prep","contra": "Intestinal obstruction, acute abdominal conditions","se": "Abdominal cramps, diarrhea, electrolyte imbalances","notes": "Works in 6-12h PO, 15-60 min PR; avoid chronic use","tccc": false,"duty": "go","scenarios": [{"scenario": "A 29-year-old Ranger is 5 days post-op from a minor knee surgery for a training injury. He was prescribed Percocet for pain. He now complains of abdominal bloating and has not had a bowel movement in four days, which is causing him significant discomfort.","context": "Real-World Context: Opioid-induced constipation is as predictable as sunrise — if you prescribe narcotics, constipation WILL follow. Think of opioids as hitting the “pause button” on the gut’s natural peristalsis; the bowel essentially stops moving. This is so common that best practice is to prescribe a stool softener (Docusate/Colace) prophylactically with every opioid prescription, before the problem starts. Bisacodyl is the “kickstart” when prevention has failed — it directly stimulates the colonic nerve plexus to force peristalsis back into gear. Given at bedtime, expect results by morning. The step-up ladder goes: stool softeners first (prevention), then oral stimulant laxatives (Bisacodyl), then osmotic agents (Miralax), and finally suppositories or enemas as the heavy artillery.","diagnosis": "The patient has Opioid-Induced Constipation, a very common side effect of narcotic pain medication. The goal is to stimulate a bowel movement to relieve discomfort.","opqrst": "Onset: Gradual abdominal discomfort over 2 days. Provocation: None. Quality: \"Bloated and crampy.\" Radiation: Diffuse in the lower abdomen. Severity: 4/10. Time: Constant.","sample": "Signs/Symptoms: Inability to have a bowel movement, bloating, mild cramping. Allergies: NKDA. Medications: Percocet (Oxycodone/Acetaminophen). Past Pertinent History: Knee surgery 5 days ago. Last Oral Intake: Normal, with good fluid intake. Events: Opioid-induced constipation.","vitals": "Heart Rate: 75 bpm | Blood Pressure: 125/80 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 100% | Temperature: 98.6°F","exam": "Abdominal exam reveals mild distention and decreased bowel sounds, but no significant tenderness or signs of an acute abdomen.","primary": "Bisacodyl (Dulcolax) — 5–15 mg PO for an overnight effect. This is a stimulant laxative.","alternative": "Docusate Sodium (Colace): A stool softener that can be taken prophylactically with opioids. Polyethylene Glycol (Miralax): An osmotic laxative that pulls water into the colon. Suppositories or Enemas: For faster relief if oral agents fail.","avoid": "","dutyStatus": "MISSION CAPABLE with planning. The operator will need reliable bathroom access for several hours.","onsetDuration": "Onset: PO 6–12 hours (take at night for morning effect). Rectal: 15–60 min.","cognitive": "None.","field": "Time administration to coincide with base access or a secure location. Avoid during active patrols or operations where facilities are unavailable. Abdominal cramping is expected and should not be confused with a pathological abdominal process."}],"quiz": [{"q": "How long does oral bisacodyl (Dulcolax) typically take to work?","choices": ["15-60 minutes","6-12 hours","3-5 days","Immediately"],"answer": 1,"explain": "Oral bisacodyl, a stimulant laxative, works in 6-12 hours (15-60 minutes rectally); chronic use should be avoided."}]},{"id": 77,"name": "Polyethylene Glycol","brand": "Miralax","aka": ["MiraLAX","PEG 3350","Movicol","Macrogol"],"cat": "GI Drugs","cls": "Osmotic laxative","mech": "Causes water retention in stool","dose": "17 g (1 heaping tbsp) in 4-8 oz liquid daily","ind": "Constipation","contra": "Bowel obstruction","se": "Bloating, diarrhea, flatulence","notes": "Well tolerated; can take days for full effect","tccc": false,"duty": "limited","scenarios": [{"scenario": "A Navy Corpsman is home on leave. His 5-year-old son has been complaining of a tummy ache and has not had a bowel movement in three days. He is passing small, hard stools with difficulty and some crying. His mother says he has been avoiding using the toilet.","context": "Real-World Context: Childhood constipation creates a vicious cycle: hard stool causes pain, pain causes withholding, withholding causes harder stool. Think of it as a child’s brain learning “pooping = pain” and hitting the brakes on the urge to go. Miralax breaks this cycle gently by working as an osmotic laxative — it’s a large, inert polymer molecule that passes through the GI tract without being absorbed, pulling water into the colon by osmosis. Think of it as a sponge traveling through the intestine, soaking up water and delivering it to the stool. The result: soft, painless bowel movements that teach the child’s brain “pooping = no big deal.” Unlike stimulant laxatives (Bisacodyl), which force the colon to contract, Miralax doesn’t cause cramping and is considered safe for daily use in children, making it the pediatric gastroenterologist’s go-to. The dose is weight-based (~0.4g/kg/day), mixed in any liquid, and is tasteless and odorless — a major advantage for getting a 5-year-old to take it.","diagnosis": "The child has Functional Childhood Constipation. The goal is to soften the stool to make it easy and painless to pass, breaking the cycle of painful defecation and stool withholding.","opqrst": "Onset: Over the past 3 days. Provocation: Trying to pass stool. Quality: \"My tummy hurts.\" Radiation: Lower abdomen. Severity: 4/10. Time: Intermittent, crampy.","sample": "Signs/Symptoms: Infrequent, hard stools; straining; abdominal discomfort. Allergies: NKDA. Medications: None. Past Pertinent History: Tends toward constipation. Last Oral Intake: Normal, appetite slightly decreased. Events: Childhood constipation.","vitals": "Within normal limits.","exam": "Abdomen is soft, with some mild lower abdominal fullness, but no significant tenderness or masses.","primary": "Miralax (Polyethylene Glycol 3350) — ~0.4 g/kg/day. For a 5-year-old, typically one-half to one full capful mixed in a full glass of water or juice once daily. A gentle osmotic laxative safe for children.","alternative": "Dietary Changes: Increasing fiber and fluids. Glycerin Suppository: For more immediate relief of impacted stool in the rectum.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "By what mechanism does polyethylene glycol (Miralax) relieve constipation?","choices": ["Stimulates intestinal peristalsis directly","Causes water retention in stool by osmosis","Coats the GI tract","Slows gut motility"],"answer": 1,"explain": "Polyethylene glycol is an osmotic laxative that causes water retention in stool; it is well tolerated but may take days for full effect."}]},{"id": 78,"name": "Oxymetazoline","brand": "Afrin","aka": ["Afrin","Vicks Sinex","Oxymetazoline Hydrochloride"],"cat": "ENT & Decongestants","cls": "Alpha-adrenergic agonist (nasal)","mech": "Vasoconstriction of nasal mucosa","dose": "2-3 sprays per nostril q10-12h (MAX 3 DAYS)","ind": "Nasal congestion, epistaxis","contra": "MAOIs","se": "Rebound congestion (rhinitis medicamentosa), burning","notes": "LIMIT TO 3 DAYS to avoid rebound; can use for epistaxis","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 24-year-old Ranger has developed severe nasal congestion from a cold. His squad is scheduled to conduct a military free-fall (MFF) operation in two hours. He is completely unable to breathe through his nose, which will prevent him from equalizing pressure during the jump.","context": "Real-World Context: Afrin is the “nuclear option” of nasal decongestion — a topical alpha-adrenergic agonist that constricts the swollen blood vessels in the nasal turbinates within minutes, transforming a completely blocked airway into a clear one. Think of it as deflating balloons that are blocking a hallway. For a paratrooper, diver, or free-fall operator, the inability to equalize sinus and middle ear pressure isn’t just uncomfortable — it can cause a sinus squeeze (excruciating sinus pain and hemorrhage) or tympanic membrane rupture (ruptured eardrum). Afrin provides the rapid, reliable decongestion needed to clear for the operation. The THREE-DAY RULE is absolute: beyond 72 hours, the nasal mucosa develops tachyphylaxis (tolerance) and begins to swell WORSE than the original congestion when the spray wears off — a condition called Rhinitis Medicamentosa. The patient becomes dependent on the spray in a vicious cycle. This is a rescue medication for operational necessity, not a daily treatment.","diagnosis": "The patient has Severe Nasal Congestion secondary to a viral URI, which is disqualifying for diving or airborne operations. The goal is rapid, temporary relief.","opqrst": "Onset: Over the past 12 hours. Provocation: None. Quality: \"Totally stuffed up.\" Radiation: None. Severity: 10/10 congestion. Time: Constant.","sample": "Signs/Symptoms: Severe nasal congestion, sinus pressure. Allergies: NKDA. Medications: None. Last Oral Intake: Water. Events: Common cold.","vitals": "Within normal limits.","exam": "Nasal examination shows swollen, red turbinates completely blocking the nasal passages.","primary": "Afrin (Oxymetazoline) — 1–2 sprays in each nostril. A potent topical vasoconstrictor that provides rapid and profound decongestion.","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What is the critical usage limit for oxymetazoline (Afrin) nasal spray?","choices": ["Limit to 3 days to avoid rebound congestion","Use for up to 30 days","Only one dose ever","No time limit"],"answer": 0,"explain": "Oxymetazoline must be limited to 3 days to avoid rebound congestion (rhinitis medicamentosa); it can also be used for epistaxis."}]},{"id": 79,"name": "Pseudoephedrine","brand": "Sudafed","aka": ["Sudafed","Pseudoephedrine Hydrochloride","PSE"],"cat": "ENT & Decongestants","cls": "Alpha/beta-adrenergic agonist","mech": "Vasoconstriction of respiratory mucosa; bronchial relaxation","dose": "60 mg PO q4-6h or 120 mg ER q12h (max 240 mg/day)","ind": "Nasal congestion, rhinitis, sinusitis","contra": "MAOIs within 2 weeks, severe HTN, CAD, glaucoma","se": "Tachycardia, hypertension, insomnia, nervousness","notes": "May need ID to purchase; avoid in HTN/cardiac disease","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 30-year-old Air Force pilot is suffering from sinus congestion from a minor cold. He complains of a feeling of fullness and pressure in his ears and is having trouble clearing them. He is scheduled for a flight.","context": "Real-World Context: Eustachian tube dysfunction is the bane of aviators and divers — the tube that connects the middle ear to the back of the throat is supposed to open with swallowing or yawning to equalize pressure, but swollen mucosa from a cold can glue it shut. Think of it as a pressure-relief valve that’s jammed. At altitude, external pressure drops while middle ear pressure stays the same, creating a painful vacuum that can rupture the eardrum. Pseudoephedrine is a systemic decongestant that constricts blood vessels throughout the nasal and sinus mucosa, including around the Eustachian tube opening. Unlike Afrin (which is topical and only reaches the anterior nose), Sudafed gets into the bloodstream and reduces swelling everywhere, including the deep tissues around the Eustachian tube that sprays can’t reach. The stimulant properties (it’s chemically related to amphetamine) are both a benefit (no drowsiness) and a consideration (elevated heart rate and blood pressure). It’s FAA-acceptable for flight in limited doses, but the flight surgeon should be informed.","diagnosis": "The patient has Eustachian Tube Dysfunction secondary to viral URI. The goal is to decongest the tissues around the Eustachian tube opening.","opqrst": "Onset: 24 hours ago. Provocation: None. Quality: \"Fullness and pressure.\" Radiation: None. Severity: 4/10. Time: Constant.","sample": "Signs/Symptoms: Eustachian tube dysfunction, sinus and ear pressure. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Common cold.","vitals": "Within normal limits.","exam": "Otoscopy may show a retracted eardrum. Nasal exam shows mild congestion.","primary": "Sudafed (Pseudoephedrine) — 30–60 mg PO. A systemic decongestant effective for relieving ear and sinus pressure.","alternative": "A topical decongestant spray like Afrin could also be used, but Sudafed provides longer-lasting systemic relief.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Pseudoephedrine (Sudafed) is contraindicated or used with caution in which patients?","choices": ["Patients with nasal congestion","Patients with severe hypertension or coronary artery disease","Patients with a cold","Patients with sinusitis"],"answer": 1,"explain": "As a sympathomimetic, pseudoephedrine is contraindicated with MAOIs and avoided in severe HTN, CAD, and glaucoma; it can cause tachycardia and insomnia."}]},{"id": 80,"name": "Naphazoline","brand": "Clear Eyes","aka": ["Clear Eyes","Naphcon","Naphazoline Hydrochloride"],"cat": "ENT & Decongestants","cls": "Alpha-adrenergic agonist (ophthalmic)","mech": "Vasoconstriction of conjunctival arterioles","dose": "1-2 drops in affected eye up to QID (max 72 hours)","ind": "Eye redness, irritation, dry eyes","contra": "Narrow-angle glaucoma, ocular trauma","se": "Rebound redness with prolonged use, mydriasis","notes": "Remove contacts before use; limit to 72 hours","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "What adverse effect results from prolonged use of naphazoline (Clear Eyes) ophthalmic drops?","choices": ["Permanent blindness","Rebound redness","Hearing loss","Increased tear production"],"answer": 1,"explain": "Naphazoline causes vasoconstriction of conjunctival arterioles; prolonged use leads to rebound redness, so use is limited to 72 hours and contacts removed first."}]},{"id": 81,"name": "Rizatriptan","brand": "Maxalt","aka": ["Maxalt","Rizatriptan Benzoate"],"cat": "Antimigraine","cls": "5-HT1B/1D agonist (triptan)","mech": "Causes cranial vasoconstriction; inhibits trigeminal nerve activation","dose": "5-10 mg PO (may repeat after 2h; max 30 mg/24h)","ind": "Acute migraine treatment","contra": "Ischemic heart disease, uncontrolled HTN, hemiplegic migraine, MAOIs, ergotamines","se": "Chest tightness, paresthesias, dizziness, somnolence","notes": "NOT for prevention; take at onset; ODT available","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 29-year-old female intelligence analyst presents with a severe, unilateral, throbbing headache that began an hour ago. She sees a visual aura (flashing lights) before the headache starts, is nauseous, and is extremely sensitive to the lights in the room.","context": "Real-World Context: Migraines aren’t just bad headaches — they’re a neurological event where the trigeminovascular system goes haywire, causing blood vessels in the brain to dilate and inflame while the brainstem’s pain-processing centers amplify every signal. Think of it as the brain’s alarm system stuck in a feedback loop, turning a whisper into a scream. Triptans like Rizatriptan are “migraine-specific” medications — they activate serotonin (5-HT1B/1D) receptors that constrict dilated cranial blood vessels, inhibit the release of inflammatory neuropeptides, and block pain transmission in the trigeminal nerve. The ODT (orally disintegrating tablet) is a game-changer for migraineurs with nausea: it dissolves on the tongue and doesn’t require swallowing water, which can trigger vomiting during an attack. The aura in this case (flashing lights, called scintillating scotoma) is a cortical spreading depression — a wave of electrical excitation followed by silence that spreads across the visual cortex like a ripple in a pond. It’s the migraine’s “warning shot” and actually provides a treatment window: taking the triptan during the aura, before the headache fully develops, is most effective.","diagnosis": "The patient is having an Acute Migraine with Aura. The goal is abortive therapy to stop the headache. Triptans are specifically designed for this.","opqrst": "Onset: 1 hour ago. Provocation: Light and sound. Quality: \"Throbbing, pulsating.\" Radiation: Stays on the left side of her head. Severity: 9/10. Time: Constant and worsening.","sample": "Signs/Symptoms: Unilateral throbbing headache, visual aura, photophobia, phonophobia, nausea. Allergies: NKDA. Medications: None. Past Pertinent History: Diagnosed with migraines. Last Oral Intake: Hasn’t eaten due to nausea. Events: Classic migraine attack.","vitals": "Within normal limits, may have slightly elevated BP from pain.","exam": "Neurological exam is non-focal. Patient prefers to be in a dark, quiet room.","primary": "Maxalt (Rizatriptan) — 10 mg PO or ODT (orally disintegrating tablet). The ODT form is useful for patients with nausea. A second dose can be taken after 2 hours if needed.","alternative": "Imitrex (Sumatriptan): Another very effective triptan. NSAIDs (Naproxen, Ibuprofen): Can be effective for milder migraines. Antiemetics (Zofran, Compazine): For associated nausea.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "How should rizatriptan (Maxalt) be used relative to a migraine attack?","choices": ["Taken daily for prevention","Taken at the onset of an attack, not for prevention","Taken only after 24 hours of headache","Taken to prevent aura long-term"],"answer": 1,"explain": "Rizatriptan is an abortive triptan taken at migraine onset, NOT for prevention; an ODT form is available."}]},{"id": 82,"name": "Sumatriptan","brand": "Imitrex","aka": ["Imitrex","Imigran","Sumatriptan Succinate"],"cat": "Antimigraine","cls": "5-HT1B/1D agonist (triptan)","mech": "Causes cranial vasoconstriction; inhibits trigeminal nerve activation","dose": "25-100 mg PO; 4-6 mg SQ; 5-20 mg intranasal","ind": "Acute migraine treatment, cluster headache","contra": "Ischemic heart disease, uncontrolled HTN, MAOIs, ergotamines","se": "Chest tightness, injection site reactions, paresthesias","notes": "Multiple routes available; SQ works fastest","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 38-year-old warrant officer suffers from severe, debilitating migraines. He presents having had a migraine for the past two hours, accompanied by severe nausea and vomiting. He has already thrown up the oral migraine pill he tried to take. He needs rapid relief.","context": "Real-World Context: When a migraine patient is vomiting up their oral medication, you need to bypass the GI tract entirely — and Sumatriptan SQ injection is the fastest triptan delivery in existence. Think of it as an emergency escape hatch: the subcutaneous route delivers the drug directly into the bloodstream, bypassing the shut-down stomach, with peak levels in 12 minutes versus 60–90 for oral triptans. Relief often begins within 10–15 minutes. Status migrainosus (a migraine lasting >72 hours or one refractory to treatment) is a recognized medical emergency that can lead to permanent neurological changes if untreated. The “migraine cocktail” mentioned as an alternative is a hospital staple: IV Metoclopramide (Reglan) is actually one of the most effective migraine abortives, working through dopamine receptor blockade — not just as an antiemetic, but as a direct headache treatment. Combined with IV Benadryl (to prevent the akathisia/restlessness that Reglan can cause) and IV Ketorolac (for the inflammatory component), it’s a powerful three-pronged attack.","diagnosis": "The patient has Status Migrainosus with an inability to tolerate oral medication. A non-oral route is required.","opqrst": "Onset: 2 hours ago. Provocation: Light. Quality: \"Pounding.\" Radiation: Right temporal region. Severity: 10/10. Time: Constant.","sample": "Signs/Symptoms: Severe migraine, nausea, vomiting. Allergies: NKDA. Medications: Vomited his oral medication. Past Pertinent History: Severe migraines. Last Oral Intake: Vomited 15 minutes ago. Events: Migraine refractory to oral medication.","vitals": "Within normal limits.","exam": "Patient appears in distress, shielding eyes from light.","primary": "Imitrex (Sumatriptan) Injection — 6 mg administered as a subcutaneous (SQ) injection. Bypasses the GI tract, providing rapid relief (often within 10–15 minutes).","alternative": "Ketorolac 30–60mg IM/IV. IV Antiemetics such as Metoclopramide (Reglan) — most often used in hospital settings for migraines — often given with IV Diphenhydramine (Benadryl) to prevent side effects. This “migraine cocktail” is very effective.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Which route of sumatriptan (Imitrex) provides the fastest onset for a vomiting migraine patient?","choices": ["Oral tablet","Subcutaneous (SQ) injection","Rectal suppository","Transdermal patch"],"answer": 1,"explain": "Sumatriptan is available oral, SQ, and intranasal; the SQ route works fastest and bypasses the GI tract."}]},{"id": 83,"name": "Acetazolamide","brand": "Diamox","aka": ["Diamox"],"cat": "Altitude & Environmental","cls": "Carbonic anhydrase inhibitor","mech": "Causes metabolic acidosis stimulating hyperventilation; reduces CSF production","dose": "Prevention: 125 mg q12h (start 1-2 days before); Treatment/HACE: 250 mg q12h","ind": "AMS prevention and treatment, HACE, HAPE","contra": "Sulfonamide allergy, severe renal/hepatic disease, hypokalemia","se": "Paresthesias, polyuria, photosensitivity, hypokalemia","notes": "Continue until acclimatized or descent; sulfa allergy cross-reactivity","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "Acetazolamide (Diamox) should be used cautiously or avoided in patients with which allergy?","choices": ["Penicillin allergy","Sulfonamide (sulfa) allergy","Shellfish allergy","Latex allergy"],"answer": 1,"explain": "Acetazolamide is a carbonic anhydrase inhibitor with sulfonamide cross-reactivity, so it is contraindicated in sulfa allergy and severe renal/hepatic disease."}]},{"id": 84,"name": "Sodium Chloride 0.9%","brand": "Normal Saline","aka": ["Normal Saline","NS","0.9% Saline","Isotonic Saline","NaCl 0.9%"],"cat": "IV Fluids & Electrolytes","cls": "Isotonic crystalloid","mech": "Expands extracellular fluid volume","dose": "500-1000 mL IV bolus; maintenance varies","ind": "Fluid resuscitation, dehydration, medication dilution","contra": "Fluid overload, hypernatremia","se": "Hyperchloremic acidosis (large volumes), fluid overload","notes": "Standard resuscitation fluid; preferred in TBI","tccc": true,"duty": "","scenarios": [],"quiz": [{"q": "Why is 0.9% sodium chloride (normal saline) specifically preferred in traumatic brain injury?","choices": ["It is hypotonic and reduces swelling","It is an isotonic crystalloid preferred in TBI","It contains glucose for the brain","It lowers sodium levels"],"answer": 1,"explain": "Normal saline is an isotonic crystalloid that is the standard resuscitation fluid and is preferred in TBI."},{"q": "What adverse effect can result from large-volume normal saline administration?","choices": ["Hyperchloremic acidosis","Severe hypoglycemia","Hypothermia from the fluid","Hypernatremia correction"],"answer": 0,"explain": "Large volumes of normal saline can cause hyperchloremic acidosis as well as fluid overload."}]},{"id": 85,"name": "Sodium Chloride 3%","brand": "Hypertonic Saline","aka": ["Hypertonic Saline","3% Saline","HTS"],"cat": "IV Fluids & Electrolytes","cls": "Hypertonic crystalloid","mech": "Creates osmotic gradient drawing fluid intravascularly; reduces cerebral edema","dose": "TBI/herniation: 250 mL IV over 10-20 min; Severe hyponatremia: 100-150 mL IV","ind": "Cerebral edema, TBI with herniation, severe hyponatremia","contra": "Hypernatremia","se": "Central pontine myelinolysis, fluid overload","notes": "TCCC option for TBI; max Na correction 8-12 mEq/L/day","tccc": true,"duty": "","scenarios": [],"quiz": [{"q": "A TBI casualty shows signs of herniation. What is the appropriate dose of 3% hypertonic saline?","choices": ["250 mL IV over 10-20 min","30 mL IV push over 1 min","1000 mL IV wide open","10 mL IV over 5 min"],"answer": 0,"explain": "For TBI with herniation, 3% saline is given as 250 mL IV over 10-20 minutes."},{"q": "When correcting severe hyponatremia with hypertonic saline, what is the maximum recommended rate of sodium correction to avoid harm?","choices": ["8-12 mEq/L per day","30-40 mEq/L per day","2-3 mEq/L per hour indefinitely","There is no upper limit"],"answer": 0,"explain": "Sodium should be corrected no faster than 8-12 mEq/L per day to avoid central pontine myelinolysis."}]},{"id": 86,"name": "Lactated Ringer's","brand": "LR","aka": ["LR","Ringer's Lactate","Hartmann's Solution","RL","Compound Sodium Lactate"],"cat": "IV Fluids & Electrolytes","cls": "Isotonic crystalloid","mech": "Volume replacement with electrolytes; lactate converts to bicarbonate","dose": "500-1000 mL IV; Sepsis: 30 mL/kg","ind": "Fluid replacement, hypovolemia, burns, sepsis","contra": "Severe hepatic disease (cannot metabolize lactate)","se": "Fluid overload if excessive","notes": "Physiologically balanced; NS preferred in TBI","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "Why is Lactated Ringer's used cautiously in patients with severe hepatic disease?","choices": ["The liver cannot metabolize the lactate","It contains too much glucose","It causes hyperkalemia in all patients","It is hypertonic and worsens edema"],"answer": 0,"explain": "LR is contraindicated in severe hepatic disease because the failing liver cannot convert lactate to bicarbonate."}]},{"id": 87,"name": "Dextrose 50%","brand": "D50W","aka": ["D50","D50W","50% Dextrose","Glucose 50%"],"cat": "IV Fluids & Electrolytes","cls": "Hypertonic glucose solution","mech": "Provides rapid glucose; 25g glucose per 50 mL ampule","dose": "25-50 mL (12.5-25 g) IV push","ind": "Hypoglycemia, altered mental status of unknown etiology","contra": "Hyperglycemia","se": "Hyperglycemia, tissue necrosis if extravasated","notes": "Verify IV patency; follow with snack when awake","tccc": false,"duty": "","scenarios": [],"quiz": [{"q": "How much glucose is contained in a standard 50 mL ampule of Dextrose 50%?","choices": ["25 g","12.5 g","50 g","5 g"],"answer": 0,"explain": "D50W provides 25 g of glucose per 50 mL ampule (0.5 g per mL)."}]},{"id": 88,"name": "Tranexamic Acid (TXA)","brand": "Cyklokapron","aka": ["Cyklokapron","Lysteda"],"cat": "Hemostatic Agents","cls": "Antifibrinolytic","mech": "Inhibits plasminogen activation, preventing fibrin breakdown","dose": "1 g IV over 10 min (within 3h of injury), then 1 g over 8h; or 1 g IV x1","ind": "Hemorrhagic shock, trauma with significant bleeding, postpartum hemorrhage","contra": "Active intravascular clotting, hypersensitivity","se": "Nausea, vomiting, diarrhea, thromboembolic events (rare)","notes": "TCCC: Give within 3 HOURS of injury for mortality benefit; ineffective >3h","tccc": true,"duty": "limited","scenarios": [{"scenario": "A 31-year-old male Ranger sustains a high-velocity gunshot wound to the right upper thigh, near the groin. A tourniquet is applied high and tight, but the casualty is pale, confused, and has a weak radial pulse, indicating hemorrhagic shock. The bleeding appears to originate from a junctional area not fully controlled by the tourniquet.","context": "Real-World Context: TXA is the invisible partner to tourniquets and blood products in hemorrhage control — think of it as the “clot glue” that reinforces the body’s own repair work. When you bleed, your body forms clots to seal the damage. But simultaneously, a system called fibrinolysis starts dissolving those clots — normally a good thing (prevents unwanted clots from blocking healthy vessels), but in massive hemorrhage, it becomes a traitor that tears apart the very clots you’re desperately trying to build. TXA blocks plasmin, the enzyme that dissolves clots, essentially telling the body “stop tearing down what you’re building.” The CRASH-2 trial — the landmark study — showed TXA reduces death from bleeding by about one-third when given within 3 hours of injury. After 3 hours, the benefit disappears and may actually cause harm. A junctional wound near the groin is one of the deadliest anatomic locations because tourniquets can’t fully control it, making TXA and wound packing with hemostatic gauze even more critical. The full resuscitation package here: TXA + Whole Blood + Calcium Gluconate (for citrate binding) + Ketamine (for shock-safe pain control).","diagnosis": "This casualty is in Hemorrhagic Shock due to a penetrating GSW with junctional hemorrhage. Priorities are to control bleeding and begin immediate blood-based resuscitation.","opqrst": "Patient is confused and agitated, unable to provide a clear history.","sample": "Signs/Symptoms: Altered mental status, pale and cool skin, profuse bleeding from a GSW to the right groin. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Unknown. Events: Sustained GSW during a firefight.","vitals": "Heart Rate: 130 bpm | Blood Pressure: 85/50 mmHg | Respiratory Rate: 24 breaths/min | SpO2: 94% on room air | Temperature: 97.0°F","exam": "Complete MARCH assessment. Confirm tourniquet placement and effectiveness. Perform a head-to-toe blood sweep for other injuries. Assess for signs of shock.","primary": "Blood Products — Resuscitate with Whole Blood. If not available, use plasma and red blood cells in a 1:1 ratio. Goal: palpable radial pulse or systolic BP of 90–100 mmHg.","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What is the key TCCC timing rule for giving tranexamic acid after injury?","choices": ["Give within 3 hours of injury; it is ineffective after 3 hours","Give only after 6 hours have passed","Timing does not matter for TXA","Give within 30 seconds or not at all"],"answer": 0,"explain": "TXA provides a mortality benefit only when given within 3 hours of injury and is ineffective or harmful after that window."},{"q": "By what mechanism does tranexamic acid help control hemorrhage?","choices": ["It inhibits plasminogen activation, preventing fibrin breakdown","It directly activates platelets","It replaces clotting factors","It constricts blood vessels"],"answer": 0,"explain": "TXA is an antifibrinolytic that inhibits plasminogen activation, preventing the breakdown of formed fibrin clots."}]},{"id": 89,"name": "Melatonin","brand": "Various OTC","aka": ["N-Acetyl-5-Methoxytryptamine","Circadin"],"cat": "Sleep Aids","cls": "Hormone, sleep aid","mech": "Binds melatonin receptors regulating circadian rhythm","dose": "0.3-5 mg PO 30-60 min before bedtime","ind": "Insomnia, jet lag, circadian rhythm disorders","contra": "Hypersensitivity","se": "Drowsiness, headache, vivid dreams","notes": "Lower doses (0.3-1 mg) often more effective","tccc": false,"duty": "limited","scenarios": [{"scenario": "A SOAR pilot and crew have just flown across 8 time zones for a mission. To help reset their sleep schedules and combat jet lag, the flight medic recommends a supplement to help them fall asleep at the appropriate local time.","context": "Real-World Context: Jet lag is a mismatch between the body’s internal clock and the external environment — think of it as your brain insisting it’s noon while the world around you says midnight. The suprachiasmatic nucleus (the brain’s master clock) uses light exposure and melatonin levels to synchronize the sleep-wake cycle. Supplemental melatonin is like manually setting a clock that’s stuck on the wrong time zone. It doesn’t knock you out the way a sleeping pill does; instead, it tells your brain “it’s nighttime now, start the shutdown sequence.” This makes it far gentler than prescription hypnotics (Ambien, Lunesta), with virtually no hangover or “no-go pill” restrictions — though some individuals do experience next-day grogginess. For military applications, the timing is everything: take it 30–60 minutes before the DESIRED bedtime in the new time zone, not your old bedtime. Combined with strategic light exposure (bright light in the morning, darkness in the evening), melatonin can accelerate circadian adaptation from the usual 1 day per time zone crossed to roughly half that.","diagnosis": "The crew is experiencing Jet Lag (Circadian Dysrhythmia). The goal is to promote sleep at the new local bedtime to accelerate acclimatization.","opqrst": "Not applicable. This is for sleep cycle regulation.","sample": "Signs/Symptoms: Anticipated difficulty sleeping due to circadian rhythm disruption (jet lag). Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Transmeridian flight.","vitals": "Within normal limits.","exam": "None indicated.","primary": "Melatonin — 3–5 mg PO, taken 30–60 minutes before desired bedtime. A hormone the body naturally produces to regulate sleep. Supplementing it can help reset the internal clock.","alternative": "Prescription hypnotics (Eszopiclone, Zolpidem): More powerful but have greater side effect potential. Melatonin is a gentler first step.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Which melatonin dosing observation is reflected in its formulary notes?","choices": ["Lower doses of 0.3-1 mg are often more effective","Doses above 20 mg are required for any effect","It must be given intravenously","It works best taken at noon"],"answer": 0,"explain": "Lower melatonin doses (0.3-1 mg) are often more effective than larger doses for sleep regulation."}]},{"id": 90,"name": "Eszopiclone","brand": "Lunesta","aka": ["Lunesta"],"cat": "Sleep Aids","cls": "Non-benzodiazepine hypnotic","mech": "Binds GABA-A receptors","dose": "1-3 mg PO immediately before bedtime","ind": "Insomnia","contra": "History of complex sleep behaviors","se": "Metallic taste, drowsiness, complex sleep behaviors","notes": "Take only with 7-8h sleep time; start 1 mg in elderly","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 45-year-old intelligence analyst is deployed to a high-stress environment and is having significant trouble sleeping. He lies awake for hours, and the lack of sleep is affecting his cognitive performance and analytical ability. He has tried melatonin and good sleep hygiene with no success.","context": "Real-World Context: Sleep deprivation is the silent readiness killer in deployed environments — an intelligence analyst running on 3 hours of fragmented sleep is making decisions with the cognitive equivalent of a blood alcohol level of 0.08%. Think of Eszopiclone as a “precision sleep switch” — it’s a non-benzodiazepine “Z-drug” that binds selectively to the GABA-A receptor subtype most involved in sleep initiation, without the broad, sloppy sedation of a benzodiazepine or Benadryl. It helps both with falling asleep (sleep-onset insomnia) and staying asleep (sleep-maintenance insomnia). The critical operational caveat: ALL hypnotic sleep aids are “no-go pills” — the patient is grounded from any special duties the following day. There is also a real risk of complex sleep behaviors (sleepwalking, sleep-driving, sleep-eating), which in a deployed environment with weapons and vehicles is a serious safety concern. The medication should be used for the shortest possible duration to re-establish a sleep pattern, not as a nightly crutch. The common metallic/bitter taste the morning after is a known side effect that patients should be warned about.","diagnosis": "The patient is suffering from Insomnia. When non-pharmacologic methods fail, a short-term course of a hypnotic medication may be indicated to restore a proper sleep-wake cycle.","opqrst": "Not applicable. This is a chronic issue.","sample": "Signs/Symptoms: Difficulty initiating sleep (sleep-onset insomnia), daytime fatigue, difficulty concentrating. Allergies: NKDA. Medications: Melatonin (ineffective). Past Pertinent History: None. Last Oral Intake: Normal. Events: Insomnia related to stress and operational tempo.","vitals": "Within normal limits.","exam": "None indicated. This is a diagnosis based on history.","primary": "Eszopiclone (Lunesta) — 1–3 mg PO at bedtime. A non-benzodiazepine “Z-drug” effective for sleep-onset and sleep-maintenance insomnia.","alternative": "Zolpidem (Ambien): Another common Z-drug. Trazodone: An antidepressant often used in low doses for its sedative side effects.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Before taking eszopiclone (Lunesta), a patient should ensure they have how much available sleep time?","choices": ["7-8 hours","2-3 hours","12 hours minimum","Sleep time is irrelevant"],"answer": 0,"explain": "Eszopiclone should only be taken when 7-8 hours of sleep time are available to avoid next-day impairment."}]},{"id": 91,"name": "Zolpidem","brand": "Ambien","aka": ["Ambien","Stilnox","Zolpidem Tartrate"],"cat": "Sleep Aids","cls": "Non-benzodiazepine hypnotic","mech": "Binds GABA-A receptors selectively","dose": "5-10 mg (men) or 5 mg (women) PO immediately before bed","ind": "Insomnia","contra": "History of complex sleep behaviors","se": "Drowsiness, dizziness, complex sleep behaviors, amnesia","notes": "Lower dose for women; take only with 7-8h sleep time","tccc": false,"duty": "limited","scenarios": [{"scenario": "An Air Force drone operator has been switched to the night shift. He is struggling to adjust and cannot fall asleep during the day, leading to significant fatigue during his shift. He needs a short-term solution to help him initiate sleep.","context": "Real-World Context: Shift work sleep disorder is the modern military’s circadian nightmare — the body’s master clock is screaming “stay awake!” while the duty schedule demands sleep. Zolpidem (Ambien) is designed as a “precision sleep initiator” — it selectively binds to the alpha-1 subunit of the GABA-A receptor, the specific subunit most responsible for sedation, with minimal binding to the subunits responsible for anxiolysis, muscle relaxation, and anticonvulsant effects. Think of it as a key that only fits the “sleep” lock on the GABA receptor. This selectivity gives it a faster onset and shorter duration than benzodiazepines, making it ideal for sleep-onset insomnia without excessive next-day hangover. The critical warnings are real: anterograde amnesia (doing things after taking it with no memory the next day) and complex sleep behaviors (sleepwalking, sleep-driving, sleep-eating) have been documented. In a military environment with weapons and vehicles, these aren’t amusing anecdotes — they’re safety hazards. The “no-go pill” designation means the operator is grounded from all duties for a minimum of 8 hours after taking it.","diagnosis": "The patient has Shift Work Sleep Disorder. The goal is to use a hypnotic agent to help initiate sleep at an unnatural time.","opqrst": "Not applicable.","sample": "Signs/Symptoms: Inability to fall asleep during the day, daytime fatigue, poor concentration. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Shift work sleep disorder.","vitals": "Within normal limits.","exam": "None indicated.","primary": "Ambien (Zolpidem) — 5–10 mg PO immediately before going to bed. Rapid onset and short half-life, ideal for helping someone fall asleep without excessive next-day grogginess.","alternative": "Eszopiclone (Lunesta): Another common “Z-drug.” Melatonin: Can also help shift the circadian rhythm.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "How does the recommended zolpidem (Ambien) dose differ by sex?","choices": ["Women receive a lower dose (5 mg) than men (5-10 mg)","Women require a higher dose than men","Dosing is identical for both","Only men should take zolpidem"],"answer": 0,"explain": "Women are dosed at 5 mg while men may take 5-10 mg, because women clear zolpidem more slowly."}]},{"id": 92,"name": "Albuterol / Ipratropium (DuoNeb)","brand": "DuoNeb / Combivent","aka": ["Combivent","Salbutamol/Ipratropium"],"cat": "Respiratory","cls": "Bronchodilator (beta-2 agonist + anticholinergic)","mech": "Albuterol stimulates beta-2 receptors to relax bronchial smooth muscle while ipratropium blocks muscarinic receptors, together opening constricted airways through two complementary pathways.","dose": "Nebulized: one unit-dose vial (2.5 mg albuterol / 0.5 mg ipratropium) over 5-15 min, repeat q20min x3 for acute bronchospasm; MDI 2 puffs of each agent. Add IM epinephrine 0.3-0.5 mg for severe refractory attacks.","ind": "Acute asthma exacerbation, status asthmaticus, COPD bronchospasm, exercise- or cold-air-induced bronchoconstriction.","contra": "Hypersensitivity to albuterol, ipratropium, or atropine derivatives (soy/peanut allergy with older MDI formulations); use caution in tachyarrhythmias and severe coronary disease.","se": "Tachycardia, palpitations, tremor, anxiety, dry mouth, headache, hypokalemia with repeated dosing, paradoxical bronchospasm.","notes": "A silent chest means minimal air movement and is more ominous than loud wheezing; combining both agents attacks bronchospasm from two mechanisms and IM epinephrine is the field rescue for the deteriorating asthmatic.","tccc": false,"duty": "go","scenarios": [{"scenario": "An 18-year-old Ranger candidate with a known history of asthma is doing a strenuous ruck march in a cold, dry environment. He begins wheezing and using his prescribed rescue inhaler with no relief. He is now tripoding, using all his accessory muscles to breathe, and can only speak in one-word sentences.","context": "Real-World Context: Cold, dry air is like sandpaper on reactive airways — it strips away the warm, moist blanket that protects bronchial tissue, triggering massive bronchoconstriction. A “silent chest” on auscultation is the most dangerous finding: it doesn’t mean the wheezing stopped, it means air is barely moving at all. Think of the bronchioles as garden hoses that have kinked shut; Albuterol unkinks them from one direction (beta-agonist relaxation), while Ipratropium unkinks them from another (anticholinergic drying and relaxation). Using both is like attacking the problem from two flanks simultaneously. The addition of IM Epinephrine in severe cases is the “nuclear option” — it’s the same drug and dose used for anaphylaxis because the airway emergency is equally life-threatening.","diagnosis": "This casualty is in Status Asthmaticus, a severe asthma attack that does not respond to initial treatment and can be fatal.","opqrst": "Onset: Gradual worsening over 30 minutes. Provocation: Exercise, cold air. Quality: \"Can't get air in.\" Radiation: Chest tightness. Severity: 10/10 difficulty breathing. Time: Unrelenting.","sample": "Signs/Symptoms: Severe dyspnea, audible wheezing, accessory muscle use, inability to speak full sentences, anxiety. Allergies: NKDA. Medications: Albuterol MDI (ineffective). Past Pertinent History: Asthma. Last Oral Intake: Water. Events: Strenuous exercise in cold air.","vitals": "Heart Rate: 125 bpm | Blood Pressure: 130/85 mmHg | Respiratory Rate: 32 breaths/min, labored | SpO2: 90% | Temperature: 98.6°F","exam": "Auscultate lungs: may hear diffuse wheezing or a \"silent chest\" if air movement is minimal (an ominous sign). Assess work of breathing and mental status.","primary": "Albuterol/Ipratropium (DuoNeb) — Administered via continuous nebulization. Provides a beta-agonist (Albuterol) and an anticholinergic (Ipratropium) to maximize bronchodilation.","alternative": "","avoid": "","dutyStatus": "MISSION CAPABLE with monitoring. May cause temporary tremor and tachycardia.","onsetDuration": "Onset: 5–15 min inhaled. Duration: 4–6 hours.","cognitive": "None. May cause jitteriness from beta-agonist stimulation but no cognitive impairment.","field": "Nebulizer requires power source or compressed gas. MDI with spacer is the field-preferred delivery method. Protect inhalers from extreme temperatures. A patient requiring continuous nebulization is NOT fit for combat operations."}],"quiz": [{"q": "DuoNeb combines albuterol and ipratropium. How do these two agents complement each other?","choices": ["Albuterol is a beta-2 agonist and ipratropium is an anticholinergic, opening airways via two pathways","Both are beta-2 agonists for double potency","Albuterol blocks histamine and ipratropium blocks acid","Both are anticholinergics"],"answer": 0,"explain": "Albuterol relaxes smooth muscle via beta-2 receptors while ipratropium blocks muscarinic receptors, attacking bronchospasm through two mechanisms."}]},{"id": 93,"name": "Amoxicillin","brand": "Amoxil / Moxatag","aka": ["Amoxil","Amoxicillin Trihydrate","Moxatag"],"cat": "Antibiotics","cls": "Aminopenicillin antibiotic","mech": "Binds penicillin-binding proteins to inhibit bacterial cell-wall synthesis, causing lysis of dividing organisms.","dose": "Adults 500 mg PO q8h or 875 mg PO q12h; strep pharyngitis 500 mg PO BID x10 days (or 1 g daily). Higher doses (1 g TID) for otitis/pneumonia.","ind": "Streptococcal pharyngitis, otitis media, sinusitis, community-acquired pneumonia, uncomplicated UTI, dental infections, H. pylori regimens.","contra": "Penicillin or cephalosporin allergy; caution with mononucleosis (rash) and renal impairment.","se": "Diarrhea, nausea, rash, candidiasis, hypersensitivity reactions up to anaphylaxis, C. difficile colitis.","notes": "Workhorse first-line agent for empiric strep throat in austere settings; treat to prevent rheumatic fever and use Centor criteria when lab confirmation is unavailable.","tccc": false,"duty": "go","scenarios": [{"scenario": "A 34-year-old Civil Affairs sergeant working in a crowded refugee camp develops a severe sore throat, fever, and headache. He has difficulty swallowing, and on examination, his tonsils are swollen and covered in white spots.","context": "Real-World Context: Refugee camps and crowded humanitarian environments are petri dishes for respiratory infections — think of them as the medical equivalent of kindling piled next to a fire. Strep throat left untreated isn’t just a sore throat; it’s a ticking time bomb for rheumatic fever, which can permanently damage heart valves weeks later. Amoxicillin is the “workhorse antibiotic” of primary care — cheap, well-tolerated, and devastatingly effective against Streptococcus. In a deployed setting where lab confirmation may be impossible, the Centor criteria (fever, exudates, tender lymph nodes, no cough) become your clinical compass for deciding to treat empirically.","diagnosis": "This is a classic presentation of Streptococcal Pharyngitis (Strep Throat). Treatment with antibiotics is necessary to resolve the infection and prevent rheumatic fever.","opqrst": "Onset: 2 days ago. Provocation: Swallowing is extremely painful. Quality: \"Like swallowing razor blades.\" Radiation: Pain radiates to his ears. Severity: 8/10. Time: Constant and worsening.","sample": "Signs/Symptoms: Severe sore throat, fever, headache, swollen tonsils with exudates, tender anterior cervical lymph nodes. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Working in close quarters with a displaced population.","vitals": "Heart Rate: 95 bpm | Blood Pressure: 130/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% | Temperature: 101.8°F","exam": "Examine the throat for tonsillar swelling and exudates. Palpate the neck for tender lymph nodes. A rapid strep test, if available, would be positive.","primary": "Amoxicillin — 875 mg PO twice a day for 10 days. A very effective and common first-line treatment.","alternative": "Penicillin VK — 500 mg PO twice a day for 10 days. The classic treatment. Azithromycin: 500 mg on day 1, then 250 mg for 4 days. Used if the patient has a penicillin allergy.","avoid": "","dutyStatus": "FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration": "Onset: Therapeutic levels within 1–2 hours. Full course: 10 days.","cognitive": "None.","field": "Requires refrigeration for liquid formulations (not field-practical). Tablets/capsules are stable at room temperature. Compliance is a concern with TID dosing on extended operations. Always assess for penicillin allergy before administering."}],"quiz": [{"q": "Amoxicillin is a workhorse first-line agent for which infection in austere settings?","choices": ["Streptococcal pharyngitis","Pseudomonas wound infection","Malaria","Fungal candidiasis"],"answer": 0,"explain": "Amoxicillin is the first-line empiric agent for strep pharyngitis, treating to prevent rheumatic fever."}]},{"id": 94,"name": "Augmentin (Amoxicillin/Clavulanate)","brand": "Augmentin","aka": ["Co-amoxiclav","Amoxicillin/Clavulanate","Clavulin"],"cat": "Antibiotics","cls": "Aminopenicillin + beta-lactamase inhibitor antibiotic","mech": "Amoxicillin inhibits cell-wall synthesis while clavulanate neutralizes bacterial beta-lactamase enzymes, restoring activity against resistant aerobes and anaerobes.","dose": "Adults 875/125 mg PO q12h or 500/125 mg PO q8h; bite wounds 875/125 mg PO BID x5-7 days (treatment) or prophylaxis x3-5 days.","ind": "Human and animal bite wounds, sinusitis, otitis media, respiratory tract infections, and skin or soft-tissue infections requiring anaerobic coverage.","contra": "Penicillin allergy, prior amoxicillin-clavulanate cholestatic jaundice or hepatic dysfunction; caution in renal impairment.","se": "Diarrhea (dose-related from clavulanate), nausea, rash, candidiasis, rare hepatotoxicity, C. difficile colitis.","notes": "Drug of choice for fight-bite and other polymicrobial wounds because clavulanate covers mouth flora like Eikenella; never close these wounds primarily, leave them open to drain.","tccc": false,"duty": "go","scenarios": [{"scenario": "A 27-year-old Ranger sustains a human bite wound to his hand while grappling during hand-to-hand combat training. The wound broke the skin over his knuckles. The medic has irrigated the wound, but due to the high risk of infection, decides to start antibiotics.","context": "Real-World Context: A “fight bite” over the knuckles is one of the most dangerous wound types in medicine — think of it as a syringe full of oral bacteria injected directly into the tendon sheath and joint capsule. The human mouth harbors a cocktail of aerobes and anaerobes that standard antibiotics miss. Augmentin is the perfect counter because it’s essentially Amoxicillin with a bodyguard (Clavulanate) — the Clavulanate neutralizes the beta-lactamase enzymes that bacteria use to defeat the antibiotic, like a shield-breaker before the main assault. These wounds should NEVER be closed primarily; leave them open to drain and heal by secondary intention. The hand is also the highest-risk location because tendons and joint spaces sit just millimeters below the skin.","diagnosis": "The patient has a Human Bite Wound, which is considered a contaminated wound at high risk for polymicrobial infection, including both aerobic and anaerobic bacteria.","opqrst": "Onset: 1 hour ago. Provocation: Pressure on the wound. Quality: \"Aching and sore.\" Radiation: Localized to the hand. Severity: 4/10. Time: Constant since the incident.","sample": "Signs/Symptoms: 2cm laceration over the 3rd metacarpophalangeal joint (knuckle). Mild swelling and erythema. Allergies: NKDA. Medications: None. Past Pertinent History: Up to date on tetanus. Last Oral Intake: Lunch, 2 hours ago. Events: Human bite during training.","vitals": "Heart Rate: 80 bpm | Blood Pressure: 128/74 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.9°F","exam": "Thoroughly irrigate the wound. Assess for tendon or joint capsule involvement. Check neurovascular status of the fingers.","primary": "Augmentin (Amoxicillin/Clavulanate) — 875 mg PO twice a day for 7–10 days. First-line treatment as it provides excellent coverage against common oral flora pathogens.","alternative": "A combination of Clindamycin (for anaerobes and gram-positives) PLUS either Ciprofloxacin or Trimethoprim-Sulfamethoxazole (for gram-negatives).","avoid": "","dutyStatus": "FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration": "Onset: 1–2 hours PO. Full course: 5–10 days.","cognitive": "None.","field": "Higher rate of GI side effects (diarrhea, nausea) than Amoxicillin alone due to clavulanate. Take with food to reduce GI upset. Human bite wounds in the field are a MEDEVAC priority regardless of antibiotic availability due to high infection risk."}],"quiz": [{"q": "Why is Augmentin the drug of choice for a human fight-bite wound over plain amoxicillin?","choices": ["Clavulanate covers beta-lactamase-producing mouth flora like Eikenella","It is cheaper than amoxicillin","It only needs a single dose","It avoids all GI side effects"],"answer": 0,"explain": "The clavulanate component neutralizes beta-lactamase, extending coverage to polymicrobial mouth flora such as Eikenella."}]},{"id": 95,"name": "Aluminum Hydroxide (Maalox)","brand": "Maalox / Amphojel","aka": ["Aluminum Hydroxide Gel"],"cat": "GI Drugs","cls": "Antacid","mech": "Aluminum hydroxide chemically neutralizes existing gastric acid on contact, raising intraluminal pH and reducing pepsin activity.","dose": "Adults 5-30 mL or 1-2 tablets PO as needed, typically 1 hour after meals and at bedtime, up to QID.","ind": "Heartburn, acid indigestion, GERD symptom relief, and as a phosphate binder in renal failure.","contra": "Severe renal impairment (aluminum accumulation), bowel obstruction; caution with hypophosphatemia.","se": "Constipation, hypophosphatemia, chalky taste; aluminum toxicity with chronic use in renal failure.","notes": "Fastest-acting but shortest-lived acid relief; always confirm chest burning is positional and food-related, not exertional cardiac pain, before treating as simple GERD.","tccc": false,"duty": "go","scenarios": [{"scenario": "A 22-year-old Ranger, after consuming his third MRE of the day, complains of a burning sensation in his chest and a sour taste in his mouth. He says it gets worse when he lies down. He has no other complaints and is otherwise healthy.","context": "Real-World Context: MREs are calorie-dense survival fuel, but they’re also infamous for causing GI distress — think of them as nutritional bricks that trade digestive comfort for shelf stability. The high sodium, preservatives, and low fiber content are a recipe for acid reflux, especially when a soldier eats three in a day and then lies down for rest. Maalox works like a fire extinguisher — it chemically neutralizes the acid already in the stomach on contact, providing almost immediate relief. It’s the fastest-acting option available but also the shortest-lived. The critical clinical step here is ruling out a cardiac event: in any patient with “chest burning,” confirm it’s positional (worse lying down) and food-related, not exertional, before dismissing it as heartburn.","diagnosis": "The patient is experiencing simple Gastroesophageal Reflux Disease (GERD), or heartburn/indigestion, a common complaint. The goal is to neutralize stomach acid for symptomatic relief.","opqrst": "Onset: 30 minutes after eating. Provocation: Lying down. Quality: \"Burning.\" Radiation: Stays in the center of his chest. Severity: 4/10. Time: Intermittent.","sample": "Signs/Symptoms: Burning epigastric/substernal pain, sour taste. Allergies: NKDA. Medications: None. Past Pertinent History: Reports this happens \"sometimes after MREs.\" Last Oral Intake: MRE 30 minutes ago. Events: Simple indigestion.","vitals": "Heart Rate: 76 bpm | Blood Pressure: 124/78 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 100% on room air | Temperature: 98.6°F","exam": "Abdominal exam is benign, with no tenderness to palpation. Crucially, confirm the pain is not exertional and there are no other signs of a cardiac event.","primary": "Maalox (or similar antacid) — 30 mL PO. Should provide rapid relief.","alternative": "Calcium Carbonate (Tums): Chewable tablets, easy to carry and administer. H2 Blockers (e.g., Famotidine): A longer-acting option if symptoms are recurrent.","avoid": "","dutyStatus": "FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration": "Onset: Minutes (immediate acid neutralization). Duration: 1–2 hours.","cognitive": "None.","field": "Liquid formulations are bulky and heavy for field carry. Chewable tablets are more practical. Can interfere with absorption of other medications — separate dosing by 2 hours. MRE-heavy diets are a known trigger for reflux in the field."}],"quiz": [{"q": "What is a characteristic side effect of aluminum hydroxide (Maalox)?","choices": ["Constipation","Severe diarrhea","Hyperkalemia","Drowsiness"],"answer": 0,"explain": "Aluminum hydroxide commonly causes constipation, in contrast to magnesium-based antacids which cause diarrhea."}]},{"id": 96,"name": "ATNAA (Atropine/Pralidoxime Autoinjector)","brand": "ATNAA / DuoDote","aka": ["DuoDote","Atropine/Pralidoxime","2-PAM","Pralidoxime Chloride"],"cat": "CBRN & Antidotes","cls": "Nerve-agent antidote autoinjector (anticholinergic + oxime)","mech": "Atropine blocks muscarinic acetylcholine receptors to dry secretions and restore heart rate while pralidoxime (2-PAM) reactivates acetylcholinesterase by stripping the organophosphate off the enzyme before aging.","dose": "One autoinjector IM (2.1 mg atropine / 600 mg pralidoxime) for mild-moderate symptoms; severe exposure give 3 autoinjectors IM immediately, plus a CANA (diazepam 10 mg) for seizures. Repeat atropine until secretions dry.","ind": "Organophosphate nerve-agent or pesticide poisoning producing cholinergic crisis.","contra": "No absolute contraindication in confirmed nerve-agent poisoning (life-threatening); caution otherwise in cardiac disease and renal impairment.","se": "Tachycardia, dry mouth, blurred vision, urinary retention, hypertension, dizziness; injection-site pain.","notes": "CBRN field antidote; recognize the DUMBELS or SLUDGE cholinergic toxidrome and dose to drying of secretions, give 2-PAM early before enzyme aging makes the bond permanent.","tccc": false,"duty": "nogo","scenarios": [{"scenario": "A Civil Affairs team is meeting with local leaders when there is a sudden chemical attack. A 38-year-old sergeant begins complaining of a runny nose and tight chest, then rapidly develops confusion, profuse sweating, and muscle twitching before collapsing and seizing.","context": "Real-World Context: Nerve agents are the nightmare scenario of chemical warfare — they essentially drown the nervous system in its own signaling chemical (acetylcholine). Think of the nervous system as a phone network: acetylcholine is the call signal, and acetylcholinesterase is what hangs up the call. Nerve agents destroy the hang-up mechanism, so every nerve fires continuously and simultaneously — every muscle contracts, every gland secretes, every organ overloads. The mnemonic DUMBBELLS captures this chaos: Defecation, Urination, Miosis, Bronchorrhea, Bradycardia, Emesis, Lacrimation, Lethargy, Salivation. The ATNAA is a two-drug counterpunch: Atropine is the “shut-off valve” that blocks acetylcholine at the receptor, drying secretions and restoring heart rate. Pralidoxime (2-PAM) is the “lock-picker” that can actually pry the nerve agent off the enzyme and restore normal function — but only if given before the bond becomes permanent (“aging”), which happens within minutes to hours depending on the agent. Speed is everything.","diagnosis": "This is a classic presentation of Nerve Agent Poisoning. The agent causes a cholinergic crisis. Treatment must be administered immediately.","opqrst": "Patient is unresponsive and seizing.","sample": "Signs/Symptoms: DUMBBELLS: Defecation, Urination, Miosis (pinpoint pupils), Bronchorrhea, Bradycardia, Emesis, Lacrimation, Lethargy, Salivation. Plus muscle twitching (fasciculations) and seizures. Allergies: Unknown. Medications: None. Events: Known or suspected chemical agent attack.","vitals": "Heart Rate: 45 bpm | Blood Pressure: 105/70 mmHg | Respiratory Rate: 8 breaths/min, gurgling | SpO2: 80% and dropping","exam": "Decontaminate the casualty immediately. Airway assessment: copious secretions are the primary threat. Neurological assessment: seizing, unresponsive.","primary": "ATNAA Autoinjector — Contains Atropine (2mg) and Pralidoxime Chloride (600mg). Give IM into the lateral thigh. Repeat every 5–10 minutes until secretions dry up and breathing improves.","alternative": "In a mass-casualty event, treatment is protocol-driven with the autoinjectors. There are no practical field alternatives. The key is rapid administration of the pre-packaged antidotes.","avoid": "","dutyStatus": "EMERGENCY USE ONLY. After nerve agent exposure and treatment, the operator is NON-MISSION-CAPABLE and requires immediate MEDEVAC.","onsetDuration": "Onset: Atropine within 1–4 minutes IM. Pralidoxime within 15–30 minutes.","cognitive": "Atropine causes blurred vision, dry mouth, tachycardia, and potential confusion. The nerve agent exposure itself causes severe cognitive impairment.","field": "Every warfighter carries their own ATNAA. Self-aid/buddy-aid with autoinjectors is trained at all levels. Mark treated casualties. Up to 3 ATNAAs can be administered. Pralidoxime is time-sensitive — it only works within the first hours before the nerve agent bond ‘ages’ and becomes irreversible."}],"quiz": [{"q": "An ATNAA/DuoDote autoinjector treats nerve-agent poisoning. What is the dosing endpoint for atropine?","choices": ["Repeat atropine until secretions dry","Stop after exactly one dose regardless of symptoms","Titrate to a heart rate below 50","Continue until the pupils dilate fully"],"answer": 0,"explain": "Atropine is repeated until secretions (the primary airway threat) dry up."}]},{"id": 97,"name": "Malarone (Atovaquone/Proguanil)","brand": "Malarone","aka": ["Atovaquone/Proguanil"],"cat": "Antimalarials","cls": "Antimalarial (mitochondrial inhibitor + antifolate)","mech": "Atovaquone collapses the parasite mitochondrial electron-transport membrane potential while proguanil inhibits dihydrofolate reductase, together killing Plasmodium blood stages.","dose": "Prophylaxis: 1 adult tablet (250/100 mg) PO daily with fatty food, starting 1-2 days before travel through 7 days after leaving. Treatment: 4 adult tablets PO once daily x3 days.","ind": "Prophylaxis and treatment of uncomplicated Plasmodium falciparum malaria, including chloroquine-resistant strains.","contra": "Severe renal impairment (CrCl below 30 for prophylaxis), known hypersensitivity.","se": "Abdominal pain, nausea, vomiting, headache, diarrhea, vivid dreams, elevated transaminases.","notes": "Must be taken with fatty food or milk for absorption of atovaquone; severe or cerebral malaria requires IV artesunate and urgent evacuation, not oral therapy.","tccc": false,"duty": "go","scenarios": [{"scenario": "A 29-year-old Special Forces Communications Sergeant, operating in a known malaria-endemic region of Africa, presents with a high fever, severe chills, and a crushing headache. He admits he forgot to take his prophylaxis for the past week. His symptoms started yesterday and are now severe.","context": "Real-World Context: Malaria kills more people worldwide than bullets — it’s the invisible enemy that has felled more armies throughout history than any human adversary. The Plasmodium parasite, delivered by the Anopheles mosquito, hijacks red blood cells and uses them as factories to replicate, eventually bursting them open in waves that cause the characteristic cyclical fevers and chills. Think of the fever “paroxysms” as synchronized explosions of millions of red blood cells. Malarone works by poisoning the parasite’s mitochondria — it cuts off the energy supply to the malaria factory. The critical detail in this scenario: the medication must be taken with fatty food or milk because Atovaquone is fat-soluble and won’t absorb properly on an empty stomach. In severe or cerebral malaria (confusion, seizures), the game changes entirely to IV Artesunate and immediate evacuation.","diagnosis": "The patient has Malaria. The goal is to treat the active infection. Malarone can be used for both prophylaxis and treatment.","opqrst": "Onset: Symptoms began yesterday, becoming severe today. Provocation: None. Quality: \"Bone-shaking\" chills, \"pounding\" headache. Radiation: Global headache and body aches. Severity: 9/10. Time: Comes in waves (paroxysms) of fever and chills.","sample": "Signs/Symptoms: High fever, rigors (shaking chills), headache, myalgia, nausea. Allergies: NKDA. Medications: Missed doses of Malarone prophylaxis. Past Pertinent History: None. Events: Multiple mosquito bites while on patrol in an endemic area.","vitals": "Heart Rate: 120 bpm | Blood Pressure: 110/70 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 96% | Temperature: 104.5°F","exam": "Perform a rapid malaria test (e.g., BinaxNOW) if available. Assess for signs of severe malaria (confusion, seizures, respiratory distress).","primary": "Malarone (Atovaquone/Proguanil) — Treatment Dose: Four tablets PO once daily for 3 days. Must be taken with a fatty meal or milk for proper absorption.","alternative": "Coartem (Artemether/Lumefantrine) — Another excellent first-line oral treatment. The dosing is more complex, typically four tablets given at 0, 8, 24, 36, 48, and 60 hours.","avoid": "","dutyStatus": "FULLY MISSION CAPABLE. No duty restrictions. FDA-approved for prophylaxis during deployment.","onsetDuration": "Prophylaxis: Begin 1–2 days before travel, daily during, 7 days after. Treatment: 3-day course.","cognitive": "None. No neuropsychiatric side effects (unlike Mefloquine/Lariam).","field": "Must be taken with food or a milky drink for adequate absorption. Daily dosing requires discipline on extended deployments. No G6PD testing required (unlike Primaquine). Lightweight and temperature-stable, making it ideal for field carry."}],"quiz": [{"q": "Malarone (atovaquone/proguanil) absorption depends on what when dosed?","choices": ["Taking it with fatty food or milk","Taking it on a completely empty stomach","Crushing the tablet into water only","Avoiding all fat for 4 hours"],"answer": 0,"explain": "Atovaquone is fat-soluble and must be taken with fatty food or milk for adequate absorption."}]},{"id": 98,"name": "Hypertonic Saline (3% or 5%)","brand": "(generic)","aka": ["HTS","3% Saline","5% Saline"],"cat": "IV Fluids & Electrolytes","cls": "Hyperosmolar crystalloid","mech": "Creates an osmotic gradient across the intact blood-brain barrier that draws water out of swollen brain tissue into the vasculature, lowering intracranial pressure.","dose": "3% saline 250 mL IV bolus (or 5 mL/kg) over 10-20 min for herniation; alternatively 23.4% saline 30 mL IV via central line. Repeat to target while monitoring serum sodium.","ind": "Traumatic brain injury with raised intracranial pressure, signs of herniation, and symptomatic cerebral edema.","contra": "Hyponatremia corrected too rapidly (osmotic demyelination risk), hypernatremia, congestive heart failure with volume overload.","se": "Hypernatremia, hyperchloremic acidosis, phlebitis with peripheral infusion, volume overload, rebound edema.","notes": "Preferred over mannitol in the hypotensive trauma patient because it expands intravascular volume rather than causing diuresis; pair with head-of-bed elevation to 30 degrees in a talk-and-deteriorate TBI.","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 26-year-old SOAR pilot is extracted from a helicopter that made a hard landing. He had a brief loss of consciousness but was initially awake and talking (GCS 14). Over the past hour, a medic notes the pilot is becoming increasingly lethargic, his right pupil is now dilated and non-reactive, and his vitals are changing.","context": "Real-World Context: A \"talk and deteriorate\" patient is one of the most dangerous presentations in trauma — it means an epidural or subdural hematoma is expanding inside the skull, and the brain is literally being squeezed out of its compartment. Think of the skull as a rigid box with no room to expand; as blood pools inside, pressure rises until the brain herniates downward through the foramen magnum, compressing the brainstem. Cushing’s Triad (hypertension, bradycardia, irregular respirations) is the body’s desperate last-ditch attempt to maintain perfusion to the brainstem — it’s a pre-terminal sign. Hypertonic saline works by osmotic magic: it’s essentially super-concentrated salt water that, when injected IV, creates a powerful gradient pulling water OUT of swollen brain cells and INTO the bloodstream. Think of it as wringing out a waterlogged sponge. Unlike Mannitol, it doesn’t cause hypotension and actually helps expand blood volume. Head elevation to 30 degrees is a free intervention that helps venous drainage from the brain.","diagnosis": "The casualty is suffering from a Traumatic Brain Injury (TBI) and is now exhibiting signs of Cerebral Herniation, where rising intracranial pressure (ICP) is compressing the brainstem. This is a dire emergency.","opqrst": "Patient is now difficult to rouse and not communicating, GCS is deteriorating.","sample": "Signs/Symptoms: Deteriorating mental status, unilateral fixed and dilated pupil (\"blown pupil\"), possible posturing. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Unknown. Events: Helicopter crash with head injury, now showing signs of herniation.","vitals": "Heart Rate: 50 bpm (bradycardia) | Blood Pressure: 180/100 mmHg (hypertension) | Respiratory Rate: 12 breaths/min and irregular (Cheyne-Stokes). This triad of vitals is known as Cushing’s Triad.","exam": "Frequent neurological exams (GCS, pupil checks). Elevate the patient’s head to 30 degrees. Avoid hypoxia and hypercarbia (maintain normal ventilation).","primary": "Hypertonic Saline (3% or 5%) — Administer a 250 mL IV/IO bolus. Works by creating an osmotic gradient, pulling water out of the swollen brain tissue and into the bloodstream.","alternative": "Mannitol — An osmotic diuretic that also reduces ICP. Less commonly used in the field today due to risks of hypotension and rebound edema. Hypertonic saline is generally preferred.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Why is hypertonic saline often preferred over mannitol in the hypotensive trauma patient with raised ICP?","choices": ["It expands intravascular volume rather than causing diuresis","It works without crossing the blood-brain barrier issue","It is the only agent that lowers ICP at all","It causes profound diuresis to dehydrate the brain"],"answer": 0,"explain": "Unlike mannitol, hypertonic saline expands intravascular volume rather than inducing diuresis, making it safer in hypotensive trauma."}]},{"id": 99,"name": "Fentanyl Citrate — OTFC (Lozenge)","brand": "Actiq (OTFC)","aka": ["Actiq","Oral Transmucosal Fentanyl Citrate"],"cat": "Analgesics & Pain Management","cls": "Opioid analgesic (synthetic)","mech": "Potent mu-opioid receptor agonist that blocks ascending pain transmission and alters central pain perception, absorbed transmucosally through the cheek.","dose": "800 mcg oral transmucosal lozenge swabbed against the cheek; may repeat 800 mcg once after 15 min if pain persists. Monitor for respiratory depression.","ind": "Moderate to severe pain in the conscious casualty who is not in hemorrhagic or respiratory shock (TCCC Triple-Option Analgesia, second tier).","contra": "Hemorrhagic shock, respiratory distress or compromise, decreased level of consciousness, known opioid hypersensitivity.","se": "Respiratory depression, sedation, nausea, vomiting, pruritus, hypotension (less than morphine due to minimal histamine release).","notes": "TCCC analgesia option for the conscious non-shock casualty; tape the lozenge stick to the finger so it falls from the mouth if oversedation occurs, and keep naloxone ready.","tccc": true,"duty": "limited","scenarios": [{"scenario": "A 28-year-old Navy Corpsman suffers a closed femur fracture during a fast-roping insertion. The leg has been splinted. He is conscious and alert, with no signs of shock, but his pain is severe and uncontrolled by the CWMP given 30 minutes prior.","context": "Real-World Context: A femur fracture generates some of the most intense pain a human can experience — the femur is the largest bone in the body, surrounded by thick muscle that goes into spasm, creating a vicious cycle of fracture movement and pain. Think of the TCCC Triple-Option Analgesia as a ladder: Rung 1 is the Combat Wound Medication Pack (CWMP: Meloxicam + Tylenol), Rung 2 is Fentanyl OTFC for conscious casualties NOT in shock, and Rung 3 is Ketamine for any pain that remains uncontrolled. The oral transmucosal lozenge is ingenious field medicine — it absorbs through the cheek mucosa, bypassing the GI tract for faster, more predictable absorption than a pill. Taping the lozenge stick to the patient’s finger is a critical safety measure: if the patient becomes oversedated, the lozenge falls out of the mouth when the hand drops. Unlike morphine, Fentanyl has minimal histamine release and thus less blood pressure drop — crucial for trauma patients on the edge of shock.","diagnosis": "The casualty has severe pain from a long bone fracture but is not in hemorrhagic shock. This is the second option in the TCCC \"Triple-Option Analgesia\" strategy.","opqrst": "Onset: Sudden, during a hard landing. Provocation: Any movement of the leg. Quality: \"Deep, intense, bone-breaking pain.\" Radiation: Radiates up and down the entire right leg. Severity: 10/10. Time: Constant since the injury.","sample": "Signs/Symptoms: Deformity and swelling of the right thigh, severe pain. Allergies: NKDA. Medications: Meloxicam and Acetaminophen 30 mins ago. Past Pertinent History: None. Last Oral Intake: Breakfast 3 hours ago. Events: Fast-rope accident.","vitals": "Heart Rate: 110 bpm, strong radial pulse | Blood Pressure: 140/90 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam": "Confirm distal pulses, sensation, and motor function in the injured leg. Assess for signs of shock (absent).","primary": "","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario": "A 28-year-old Ranger has sustained severe burns (2nd and 3rd degree) to both of his arms after a fuel canister exploded. He is in excruciating, severe pain, and the medic needs to perform painful wound debridement and dressing changes. The patient is hemodynamically stable.","context": "Real-World Context: Burn pain is uniquely brutal — it combines continuous baseline pain with agonizing procedural pain during every dressing change. Think of burn wound care as salt on an open wound, except that wound covers both arms. IV Fentanyl is chosen here over the lozenge because the medic needs precise, rapid dose titration for the procedure: push a small dose, wait 60 seconds, assess, repeat. This “low and slow” IV approach is like turning a dial rather than flipping a switch. Fentanyl’s advantages over morphine in burns are significant: faster onset (2–3 minutes IV vs. 15–20 for morphine), shorter duration (allowing quicker recovery post-procedure), minimal histamine release (important because histamine causes vasodilation and can worsen hypotension in burn patients who are already losing massive amounts of fluid through damaged skin), and no active metabolites that accumulate in renal impairment (common in severe burns). For truly agonizing procedures, combining Fentanyl with low-dose Ketamine creates a synergistic “procedural sedation” that provides both pain relief and dissociation.","diagnosis": "The patient has severe pain from thermal burns. Potent, rapid-onset analgesia is required, especially for procedural pain like wound care. This fits the TCCC \"Triple-Option Analgesia\" for a casualty with severe pain who is not in shock.","opqrst": "Onset: Sudden, with the explosion. Provocation: Any touch or movement of his arms. Quality: \"The worst burning pain imaginable.\" Radiation: Throughout both arms. Severity: 10/10. Time: Constant.","sample": "Signs/Symptoms: Severe pain, partial and full-thickness burns on both upper extremities. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Flash burn from fuel explosion.","vitals": "Heart Rate: 120 bpm | Blood Pressure: 140/90 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 98% on room air | Temperature: 99.0°F","exam": "Full MARCH-PAWS assessment. Estimate TBSA of the burn. Secure IV/IO access in a non-burned area.","primary": "Fentanyl IV/IO — 50–100 mcg slow IV/IO push over 1–2 minutes. Repeat every 30–60 minutes as needed. Ideal for its rapid onset, potency, and minimal effect on blood pressure compared to morphine.","alternative": "Oral Transmucosal Fentanyl Citrate (OTFC): 800 mcg lozenge. Good option if IV access is difficult, but slower onset. Ketamine: Can be used as an adjunct or alternative, especially if a dissociative state is desired for the procedure.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "In which casualty is the OTFC fentanyl lozenge contraindicated under TCCC analgesia?","choices": ["The casualty in hemorrhagic or respiratory shock","The conscious casualty with an isolated extremity wound","Any casualty with mild pain","The casualty with a normal blood pressure"],"answer": 0,"explain": "OTFC is reserved for the conscious non-shock casualty and is contraindicated in hemorrhagic or respiratory shock."},{"q": "What is a recommended field safety technique when administering the fentanyl OTFC lozenge?","choices": ["Tape the lozenge stick to the finger so it falls out if oversedation occurs","Have the casualty swallow it whole quickly","Give it only with a full glass of water","Crush it and place it under the tongue"],"answer": 0,"explain": "Taping the stick to the finger lets the lozenge fall from the mouth if the casualty becomes oversedated, and naloxone is kept ready."}]},{"id": 100,"name": "Docusate Sodium (Colace)","brand": "Colace","aka": ["DSS","Dioctyl Sodium Sulfosuccinate"],"cat": "GI Drugs","cls": "Stool softener (surfactant laxative)","mech": "Anionic surfactant that lowers stool surface tension, allowing water and fat to penetrate and soften the stool.","dose": "Adults 100 mg PO BID (range 50-300 mg/day) for opioid-induced or functional constipation.","ind": "Prevention and treatment of constipation, especially opioid-induced constipation and when straining must be avoided.","contra": "Bowel obstruction, acute abdomen, undiagnosed abdominal pain.","se": "Mild abdominal cramping, diarrhea, throat irritation with liquid form; minimal systemic effects.","notes": "Start a bowel regimen with every opioid prescription since opioid-induced constipation is a certainty; escalate by adding a stimulant like bisacodyl or an osmotic like polyethylene glycol if needed.","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 32-year-old Civil Affairs officer is recovering from a complex tibia fracture and has been taking opioid pain medication (Percocet) for the past week. He knows from past experience that this medication constipates him, and he wants to take a preventative measure rather than waiting for the problem to become severe.","context": "Real-World Context: If Bisacodyl is the kickstart for constipation that’s already happened, Docusate is the preventive armor you put on before the battle begins. Think of it as an insurance policy against the guaranteed bowel shutdown that opioids cause. Docusate is a surfactant — it works like dish soap, reducing the surface tension of the stool so that water can penetrate and soften it from the inside out. It doesn’t force the gut to move (like a stimulant laxative); it simply ensures that when the gut does move, the stool passes without strain or pain. The golden rule that every medic should internalize: ANY time you prescribe an opioid, automatically prescribe Docusate alongside it. Don’t wait for the patient to complain. Opioid-induced constipation isn’t a possibility, it’s a certainty — the only question is how severe it gets before you intervene. If Docusate alone isn’t enough, escalate by adding Bisacodyl or Miralax on top, creating a layered bowel regimen.","diagnosis": "The patient is at high risk for Opioid-Induced Constipation. The goal is to start a bowel regimen to prevent severe constipation from developing.","opqrst": "Not applicable. Patient is asymptomatic but requesting prophylactic treatment.","sample": "Signs/Symptoms: None. Patient is comfortable. Allergies: NKDA. Medications: Percocet (Oxycodone/Acetaminophen) as needed for pain. Past Pertinent History: Tibia fracture, history of opioid-induced constipation. Last Oral Intake: Normal. Events: Taking a prophylactic approach to a known medication side effect.","vitals": "Within normal limits.","exam": "Abdominal exam is benign.","primary": "Docusate Sodium (Colace) — 100 mg PO twice a day. A stool softener; works by allowing more water to be absorbed by the stool, making it softer and easier to pass. Ideal for prevention.","alternative": "If constipation still develops, a stimulant laxative like Bisacodyl (Dulcolax) or an osmotic laxative like Polyethylene Glycol (Miralax) can be added.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Why should docusate sodium (Colace) be started with every opioid prescription?","choices": ["Opioid-induced constipation is a near certainty","Opioids cause diarrhea that docusate prevents","Docusate boosts opioid analgesia","It prevents opioid respiratory depression"],"answer": 0,"explain": "Opioid-induced constipation is essentially guaranteed, so a bowel regimen should accompany every opioid."}]},{"id": 101,"name": "Lidocaine with Epinephrine","brand": "Xylocaine with Epinephrine","aka": ["Lignocaine with Adrenaline","Xylocaine with Epinephrine","Lidocaine/Epinephrine"],"cat": "Local Anesthetics","cls": "Local anesthetic with vasoconstrictor","mech": "Lidocaine blocks neuronal sodium channels to halt pain conduction while added epinephrine causes local vasoconstriction that prolongs the block, reduces bleeding, and slows systemic absorption.","dose": "Infiltrate 1-2% lidocaine with 1:100000 epinephrine to effect; max 7 mg/kg (about 490 mg in a 70 kg adult).","ind": "Local anesthesia for laceration repair and minor surgical procedures, particularly where field bleeding control aids visualization.","contra": "Never use in end-artery regions: fingers, toes, nose, ears, or penis; amide-anesthetic allergy; caution in severe cardiovascular disease.","se": "Local burning on injection, CNS toxicity (perioral numbness, seizures) and cardiotoxicity if intravascular, tachycardia or hypertension from epinephrine.","notes": "The epinephrine extends numbing from about 1 hour to 2 hours and reduces bleeding so wound edges are visible; always aspirate before injecting and avoid end-arterial sites to prevent ischemic necrosis.","tccc": false,"duty": "limited","scenarios": [{"scenario": "A Navy Corpsman needs to suture a 5cm long, moderately bleeding laceration on a Marine’s forearm. To provide pain control and help stop the bleeding so he can see the wound edges clearly, he chooses a local anesthetic with a vasoconstrictor.","context": "Real-World Context: Lidocaine with Epinephrine is a “two-for-one deal” that solves two problems simultaneously in wound repair. Lidocaine blocks sodium channels in nerve fibers, preventing pain signals from reaching the brain — think of it as cutting the phone line between the wound and the brain. The Epinephrine (the same drug used for anaphylaxis, but at a much lower dose mixed into the solution) constricts local blood vessels, which does three things: it slows bleeding so the medic can see what they’re doing, it keeps the Lidocaine concentrated at the injection site longer (extending the numbing effect from ~1 hour to ~2 hours), and it reduces systemic absorption of the Lidocaine (improving the safety margin). The absolute contraindication — never on fingers, toes, nose, ears, or penis — exists because these are supplied by end-arteries with no collateral circulation. Vasoconstriction could cause ischemia and tissue death. The max dose with Epi is 7 mg/kg vs. 4.5 mg/kg without.","diagnosis": "The patient requires Wound Repair via suturing. Effective local anesthesia is essential for the procedure.","opqrst": "Onset: 15 minutes ago, from a training accident. Provocation: Touch. Quality: \"Sharp pain.\" Radiation: Localized. Severity: 5/10. Time: Constant.","sample": "Signs/Symptoms: 5cm linear laceration with steady oozing of blood. Allergies: NKDA. Medications: None. Past Pertinent History: Tetanus up to date. Last Oral Intake: Normal. Events: Cut on a piece of metal.","vitals": "Within normal limits.","exam": "Irrigate the wound. Assess distal neurovascular status before injecting anesthetic.","primary": "Lidocaine 1% with Epinephrine — Inject subcutaneously into the wound edges. Lidocaine blocks nerve conduction for pain; Epinephrine constricts local blood vessels, decreases bleeding, and prolongs the anesthetic’s duration.","alternative": "Lidocaine without Epinephrine — Use if the injury is to a finger, toe, nose, ear, or penis, where vasoconstriction could compromise blood flow.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "Where must lidocaine WITH epinephrine never be used?","choices": ["End-artery regions such as fingers, toes, nose, ears, or penis","The forearm","The scalp","The thigh"],"answer": 0,"explain": "Epinephrine causes vasoconstriction that can produce ischemic necrosis in end-artery regions, so it is avoided in fingers, toes, nose, ears, and penis."}]},{"id": 102,"name": "Lidocaine 1% (Wound Debridement)","brand": "Xylocaine","aka": ["Lignocaine","Xylocaine","Lidocaine Hydrochloride"],"cat": "Local Anesthetics","cls": "Local anesthetic (amide)","mech": "Reversibly blocks neuronal sodium channels, preventing depolarization and conduction of pain signals from the wound.","dose": "Infiltrate 1% lidocaine (10 mg/mL) to effect; max 4.5 mg/kg without epinephrine (about 315 mg in a 70 kg adult). Onset within minutes, duration 1-2 hours.","ind": "Local anesthesia for wound debridement, irrigation, and suturing, especially in end-artery areas where epinephrine is contraindicated.","contra": "Amide-anesthetic hypersensitivity; caution in severe hepatic impairment, heart block, and hypotension.","se": "Injection-site burning, and with overdose or intravascular injection: perioral numbness, tinnitus, seizures, and cardiac depression.","notes": "Use plain lidocaine in fingers, toes, nose, ears, and penis; bupivacaine lasts 4-8 hours but is more cardiotoxic, so calculate the weight-based max dose before infiltrating large wounds.","tccc": false,"duty": "limited","scenarios": [{"scenario": "A Ranger medic needs to thoroughly clean and debride a complex 8cm laceration on a fellow Ranger’s forearm, which is contaminated with dirt and debris from a fall. The procedure will be painful.","context": "Real-World Context: Wound debridement in the field is like cleaning a trench that’s been overrun — you have to get every piece of debris out, or infection will set in and the wound will never heal properly. Without anesthesia, the patient will flinch, pull away, and the medic won’t be able to do a thorough job. This scenario presents the clinical decision between Lidocaine with and without Epinephrine — and the answer depends entirely on anatomy. On the forearm (good collateral blood supply), Lidocaine WITH Epi is preferred because it controls bleeding and extends numbing time for the longer debridement procedure. The alternative, Bupivacaine, offers a much longer duration of anesthesia (4–8 hours vs. 1–2 hours) but takes longer to kick in and is more dangerous if accidentally injected into a blood vessel (cardiotoxicity). The max dose calculations are critical: for a 70kg patient, Lidocaine with Epi maxes out at 490mg (7mg/kg), and Lidocaine alone at 315mg (4.5mg/kg).","diagnosis": "The casualty requires a Wound Debridement and Irrigation procedure, which necessitates local anesthesia for pain control.","opqrst": "Onset: 30 minutes ago. Provocation: Touch. Quality: \"Sharp pain.\" Radiation: Localized to the wound. Severity: 6/10 at rest, 9/10 with cleaning. Time: Constant.","sample": "Signs/Symptoms: 8cm jagged laceration with embedded debris on the forearm. Allergies: NKDA. Medications: None. Past Pertinent History: Up to date on tetanus. Last Oral Intake: 1 hour ago. Events: Fell onto sharp rocks.","vitals": "Heart Rate: 85 bpm | Blood Pressure: 130/75 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam": "Assess and document distal neurovascular status (pulses, sensation, motor function) before the procedure. Explore the wound for depth and foreign bodies.","primary": "","alternative": "Bupivacaine — Provides a much longer duration of anesthesia than Lidocaine but has a slower onset. Good option for post-procedure pain control but is more cardiotoxic if injected intravascularly.","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "What is the maximum dose of plain 1% lidocaine (without epinephrine)?","choices": ["About 4.5 mg/kg","About 7 mg/kg","About 20 mg/kg","There is no maximum"],"answer": 0,"explain": "Plain lidocaine has a max dose of roughly 4.5 mg/kg (about 315 mg in a 70 kg adult)."}]},{"id": 103,"name": "Normal Saline / Lactated Ringer’s — Crush Syndrome","brand": "(generic)","aka": ["NS","LR","Ringer's Lactate","Hartmann's Solution"],"cat": "IV Fluids & Electrolytes","cls": "Isotonic crystalloid IV fluid","mech": "Expands intravascular and extracellular volume to dilute circulating toxins and maintain renal perfusion and urine output, flushing myoglobin through the kidneys.","dose": "1-2 L NS or LR IV ideally before extrication, then maintain high urine output (1-2 mL/kg/hr); target large daily volumes with electrolyte monitoring. Add sodium bicarbonate to alkalinize urine and calcium gluconate for cardiac membrane stabilization in hyperkalemia.","ind": "Crush syndrome and rhabdomyolysis resuscitation to prevent hyperkalemic arrest and myoglobinuric acute kidney injury; general volume resuscitation.","contra": "Use caution with LR in significant hyperkalemia (contains potassium); avoid volume overload in heart failure and oliguric renal failure.","se": "Volume overload and pulmonary edema, electrolyte disturbances, hyperchloremic acidosis with large-volume NS.","notes": "Begin aggressive fluids before releasing the crushing weight to dilute the toxic bolus; calcium gluconate protects the heart from hyperkalemia while bicarbonate alkalinizes urine to reduce myoglobin precipitation.","tccc": false,"duty": "limited","scenarios": [{"scenario": "A 30-year-old SARC medic is trapped by his lower body under a collapsed concrete wall for 90 minutes. Upon extraction, he is conscious but his legs are massively swollen, pale, and he complains of severe pain and numbness.","context": "Real-World Context: Crush syndrome is one of the most treacherous injuries in medicine — the patient looks relatively stable while trapped, then deteriorates catastrophically the moment pressure is released. Think of the crushed muscle as a toxic time bomb: while compressed, the damaged cells are leaking potassium, myoglobin, phosphorus, and lactic acid, but those toxins are trapped locally by the compression. The moment you extract the patient, that toxic bolus floods the central circulation like opening the gates of a dam. Hyperkalemia (sky-high potassium) can cause fatal cardiac arrhythmia within minutes. Myoglobin clogs the kidneys like sludge in a filter, causing acute renal failure. The treatment is a RACE against the release: ideally, you start aggressive IV fluid resuscitation (1–2 liters of NS or LR) BEFORE extraction, diluting the toxin bolus before it hits the heart and kidneys. Sodium Bicarbonate alkalinizes the urine (myoglobin is less toxic in alkaline conditions and precipitates less in the renal tubules). Calcium Gluconate is the cardiac membrane stabilizer — it doesn’t fix the potassium level but protects the heart from its lethal electrical effects while you work on the underlying cause. Ketamine is chosen for pain because it has no renal excretion concerns — NSAIDs are absolutely contraindicated as they’d destroy the already-threatened kidneys.","diagnosis": "This casualty is at high risk for Crush Syndrome and Rhabdomyolysis. When the pressure is released, toxins (potassium, myoglobin) will flood the system, potentially causing kidney failure and fatal cardiac arrhythmias.","opqrst": "Onset: Constant since being crushed. Provocation: Any movement. Quality: \"Crushing pressure and numbness.\" Radiation: Throughout both legs. Severity: 10/10. Time: Constant.","sample": "Signs/Symptoms: Massively swollen, pale, and firm lower extremities; weak/absent distal pulses. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Water 2 hours ago. Events: Trapped under debris for 90 minutes.","vitals": "Heart Rate: 120 bpm | Blood Pressure: 100/70 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 97% on room air | Temperature: 97.9°F","exam": "Full trauma assessment. Assess neuromuscular status of lower extremities (pulses, sensation, motor function). Monitor EKG for signs of hyperkalemia (peaked T waves).","primary": "IV Fluids (NS or LR) — Before release, if possible, begin aggressive IV fluid resuscitation with Normal Saline or Lactated Ringer’s. Administer 1–2 Liters.","alternative": "","avoid": "","dutyStatus": "Assess per clinical scenario and drug side effect profile.","onsetDuration": "","cognitive": "Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field": "Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz": [{"q": "In crush syndrome, when is the ideal time to begin IV fluid resuscitation?","choices": ["Before extrication, to dilute the toxic bolus released on freeing the limb","Only after the patient reaches the hospital","After urine output has stopped completely","Fluids should be withheld entirely"],"answer": 0,"explain": "Aggressive fluids are started before releasing the crushing weight to dilute the hyperkalemic and myoglobin bolus."}]},{"id": 104,"name": "Artesunate","brand": "Artesunate for Injection","aka": ["IV artesunate","AS"],"cat": "Antimalarials","cls": "Artemisinin derivative (endoperoxide)","mech": "Generates free radicals that damage parasite proteins and membranes, rapidly killing all asexual blood-stage Plasmodium.","dose": "2.4 mg/kg IV at 0, 12, 24 h then daily; follow with full oral antimalarial course once tolerating PO.","ind": "First-line for severe/complicated malaria (especially P. falciparum) including cerebral malaria and high parasitemia.","contra": "Known artemisinin hypersensitivity; no absolute contraindication in life-threatening malaria.","se": "Post-artesunate delayed hemolysis (monitor Hgb weekly x4), reticulocytopenia, transient transaminitis.","notes": "The CDC stocks IV artesunate as first-line for severe malaria in the US; carry or know your nearest source on deployment. Always finish with a full oral regimen to prevent recrudescence.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "Artesunate is the first-line agent for which condition?","choices": ["Severe or complicated malaria including cerebral malaria","Uncomplicated traveler's diarrhea","Pinworm infection","Bacterial pharyngitis"],"answer": 0,"explain": "IV artesunate is first-line for severe and complicated malaria, including cerebral malaria and high parasitemia."}]},{"id": 105,"name": "Artemether/Lumefantrine","brand": "Coartem","aka": ["AL","Riamet"],"cat": "Antimalarials","cls": "Artemisinin combination therapy (ACT)","mech": "Artemether rapidly clears parasitemia via free-radical damage while lumefantrine provides longer-acting blood-stage kill to prevent recrudescence.","dose": "Adult (over 35 kg): 4 tabs (80/480 mg) per dose at 0, 8, 24, 36, 48, 60 h (6 doses over 3 days); take with fatty food.","ind": "First-line treatment of uncomplicated P. falciparum malaria; oral follow-on after IV artesunate.","contra": "Hypersensitivity; caution with QT-prolonging drugs and known long-QT.","se": "Headache, dizziness, anorexia, QT prolongation, palpitations.","notes": "Absorption depends heavily on fat intake - give with milk or a high-fat ration to ensure cure. Workhorse ACT throughout Africa and Asia.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Absorption of artemether/lumefantrine (Coartem) depends heavily on what?","choices": ["Fat intake, so it should be given with milk or a high-fat ration","Taking it on an empty stomach","Avoiding all dairy","Crushing it in plain water"],"answer": 0,"explain": "Lumefantrine absorption is fat-dependent, so Coartem must be given with fatty food to ensure a cure."}]},{"id": 106,"name": "Tafenoquine","brand": "Krintafel / Arakoda","aka": ["TQ","SB-252263"],"cat": "Antimalarials","cls": "8-aminoquinoline (long-acting)","mech": "Disrupts parasite mitochondrial function to kill liver hypnozoites, providing radical cure of relapsing malaria.","dose": "Radical cure (Krintafel): 300 mg single dose with food alongside an ACT. Prophylaxis (Arakoda): 200 mg daily x3 loading, then 200 mg weekly.","ind": "Radical cure of P. vivax relapse; weekly malaria chemoprophylaxis.","contra": "G6PD deficiency (test first - risk of severe hemolysis), pregnancy, breastfeeding G6PD-unknown infant, psychotic disorders.","se": "Hemolysis in G6PD-deficient, methemoglobinemia, vomiting, headache, decreased hemoglobin.","notes": "Single-dose convenience makes it attractive for SOF but MANDATORY quantitative G6PD test first. Once-weekly prophylaxis improves adherence over daily agents.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "What mandatory test must be done before giving tafenoquine?","choices": ["A quantitative G6PD test","A pregnancy test only","A liver biopsy","An EKG for QT interval"],"answer": 0,"explain": "Tafenoquine, an 8-aminoquinoline, requires a mandatory quantitative G6PD test because it causes severe hemolysis in G6PD-deficient patients."}]},{"id": 107,"name": "Mefloquine","brand": "Lariam","aka": ["MQ","Mephaquin"],"cat": "Antimalarials","cls": "Quinoline-methanol antimalarial","mech": "Interferes with parasite heme detoxification in the food vacuole, killing blood-stage Plasmodium.","dose": "Prophylaxis: 250 mg PO weekly, start 2 weeks prior. Treatment: 750 mg then 500 mg 6-12 h later.","ind": "Malaria prophylaxis and treatment in chloroquine-resistant areas.","contra": "History of seizures, psychiatric disorders (depression, anxiety, psychosis), cardiac conduction abnormalities.","se": "Vivid dreams, anxiety, insomnia, depression, dizziness, rare neuropsychiatric reactions (boxed warning).","notes": "Neuropsychiatric boxed warning makes it a poor choice for operators - the US military deprioritized it for aircrew and SOF; doxycycline or atovaquone/proguanil are preferred.","tccc": false,"duty": "nogo","scenarios": [],"quiz": [{"q": "Why is mefloquine (Lariam) a poor antimalarial choice for SOF operators and aircrew?","choices": ["It carries a neuropsychiatric boxed warning","It must be given IV only","It requires daily dosing","It is ineffective against P. falciparum"],"answer": 0,"explain": "Mefloquine's neuropsychiatric boxed warning led the US military to deprioritize it for aircrew and SOF in favor of doxycycline or atovaquone/proguanil."}]},{"id": 108,"name": "Chloroquine","brand": "Aralen","aka": ["CQ","chloroquine phosphate"],"cat": "Antimalarials","cls": "4-aminoquinoline antimalarial","mech": "Accumulates in the parasite food vacuole and blocks heme polymerization, causing toxic heme buildup.","dose": "Treatment: 1 g (600 mg base) then 500 mg at 6, 24, 48 h. Prophylaxis: 500 mg (300 mg base) weekly.","ind": "Treatment/prophylaxis of chloroquine-sensitive malaria; also used for amebic liver abscess.","contra": "Retinal/visual field changes, known resistance areas, caution with G6PD deficiency and psoriasis.","se": "Pruritus (common in dark-skinned patients), GI upset, retinopathy with chronic use, QT prolongation.","notes": "Widespread resistance limits utility - confirm local susceptibility before relying on it. Narrow therapeutic index; overdose is rapidly cardiotoxic and frequently fatal.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "What largely limits the modern utility of chloroquine for malaria?","choices": ["Widespread resistance","It cannot be given orally","It has no antimalarial activity","It requires refrigeration"],"answer": 0,"explain": "Widespread resistance limits chloroquine, so local susceptibility must be confirmed before relying on it."}]},{"id": 109,"name": "Quinine","brand": "Qualaquin","aka": ["quinine sulfate","cinchona alkaloid"],"cat": "Antimalarials","cls": "Cinchona alkaloid antimalarial","mech": "Inhibits parasite heme detoxification and nucleic acid synthesis to kill blood-stage Plasmodium.","dose": "Oral: 648 mg (quinine sulfate) PO q8h x3-7 days, usually with doxycycline or clindamycin.","ind": "Uncomplicated chloroquine-resistant P. falciparum when ACTs unavailable; backup for severe malaria with a partner drug.","contra": "G6PD deficiency, prior quinine-induced thrombocytopenia/HUS, long-QT, myasthenia gravis, optic neuritis.","se": "Cinchonism (tinnitus, headache, nausea, visual disturbance), hypoglycemia, QT prolongation, hemolysis.","notes": "Cinchonism is expected and not a reason to stop unless severe. Causes hyperinsulinemic hypoglycemia - watch glucose, especially in pregnancy.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "Cinchonism is an expected effect of quinine. Which cluster of symptoms describes it?","choices": ["Tinnitus, headache, nausea, and visual disturbance","Chest pain and limb paralysis","Bloody diarrhea and fever","Skin blistering and hair loss"],"answer": 0,"explain": "Cinchonism (tinnitus, headache, nausea, visual disturbance) is expected with quinine and is not a reason to stop unless severe."}]},{"id": 110,"name": "Praziquantel","brand": "Biltricide","aka": ["PZQ"],"cat": "Antiparasitics","cls": "Anthelmintic (isoquinoline)","mech": "Increases cell-membrane permeability to calcium, causing tetanic contraction and tegument disruption in flukes and tapeworms.","dose": "Schistosomiasis: 40 mg/kg single dose (or split). Tapeworm: 5-25 mg/kg single dose depending on species.","ind": "Schistosomiasis, liver/lung flukes, and tapeworm (cestode) infections.","contra": "Ocular cysticercosis, hypersensitivity; caution in neurocysticercosis (cover with steroids).","se": "Abdominal pain, dizziness, headache, malaise; transient worsening in heavy worm burden.","notes": "Top antiparasitic to know for freshwater exposure (rivers, lakes) in endemic Africa - schistosomiasis is a classic SOF dive/swim hazard. In neurocysticercosis give corticosteroids to blunt inflammatory reaction.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Praziquantel is the agent to know for which freshwater-exposure hazard common in SOF dive/swim operations?","choices": ["Schistosomiasis","Malaria","Influenza","Tetanus"],"answer": 0,"explain": "Praziquantel treats schistosomiasis, a classic hazard of freshwater exposure in endemic regions."}]},{"id": 111,"name": "Albendazole","brand": "Albenza","aka": ["ABZ"],"cat": "Antiparasitics","cls": "Benzimidazole anthelmintic","mech": "Binds parasite beta-tubulin, blocking microtubule formation and glucose uptake, starving the worm.","dose": "Soil-transmitted helminths: 400 mg single dose. Neurocysticercosis/hydatid: 400 mg BID with food x8-30 days.","ind": "Hookworm, roundworm, whipworm, pinworm, neurocysticercosis, hydatid disease, strongyloides.","contra": "Pregnancy (first trimester), hypersensitivity; monitor LFTs and CBC on prolonged courses.","se": "Abdominal pain, nausea, reversible transaminitis, headache, rare marrow suppression with long use.","notes": "Take with a fatty meal for systemic tissue infections to boost absorption. Single 400 mg dose deworms most soil-transmitted helminths - handy for indigenous force health.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "For systemic tissue infections, albendazole absorption is improved by what?","choices": ["Taking it with a fatty meal","Taking it on an empty stomach","Avoiding all fat","Dissolving it in alcohol"],"answer": 0,"explain": "Albendazole should be taken with a fatty meal to boost absorption for systemic tissue infections."}]},{"id": 112,"name": "Mebendazole","brand": "Vermox","aka": ["MBZ"],"cat": "Antiparasitics","cls": "Benzimidazole anthelmintic","mech": "Binds nematode beta-tubulin to inhibit microtubule synthesis and glucose absorption.","dose": "Pinworm: 100 mg single dose, repeat in 2 weeks. Other STH: 100 mg BID x3 days or 500 mg once.","ind": "Pinworm, roundworm, hookworm, whipworm infections.","contra": "Hypersensitivity; avoid in first-trimester pregnancy.","se": "Mild abdominal pain, diarrhea, rare hepatotoxicity at high/prolonged doses.","notes": "Similar niche to albendazole but poorer tissue penetration - reserve for luminal nematodes. Repeat dose for pinworm to catch the next egg cycle.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "When treating pinworm with mebendazole, why is a repeat dose given in 2 weeks?","choices": ["To catch the next egg-hatching cycle","Because the first dose is always defective","To prevent an allergic reaction","To reverse hepatotoxicity"],"answer": 0,"explain": "A repeat dose in 2 weeks targets newly hatched worms from the next egg cycle."}]},{"id": 113,"name": "Ivermectin","brand": "Stromectol","aka": ["IVM","Mectizan"],"cat": "Antiparasitics","cls": "Avermectin antiparasitic","mech": "Binds glutamate-gated chloride channels in invertebrate nerve/muscle, causing paralysis and death of the parasite.","dose": "Strongyloides: 200 mcg/kg PO daily x1-2 days. Scabies: 200 mcg/kg, repeat in 1-2 weeks. Onchocerciasis: 150 mcg/kg.","ind": "Strongyloidiasis, onchocerciasis (river blindness), scabies, lice, cutaneous larva migrans.","contra": "Hypersensitivity; caution with Loa loa coinfection (risk of fatal encephalopathy).","se": "Pruritus, dizziness, Mazzotti reaction in onchocerciasis (fever, rash, edema).","notes": "Screen for Loa loa before treating in Central/West Africa - high microfilarial loads can cause fatal encephalopathy. Take on an empty stomach.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Before treating with ivermectin in Central or West Africa, what coinfection must be screened for?","choices": ["Loa loa","Malaria","Tuberculosis","Hepatitis B"],"answer": 0,"explain": "High Loa loa microfilarial loads can cause fatal encephalopathy after ivermectin, so screening is required first."}]},{"id": 114,"name": "Nitazoxanide","brand": "Alinia","aka": ["NTZ"],"cat": "Antiparasitics","cls": "Thiazolide antiparasitic/antiprotozoal","mech": "Inhibits pyruvate:ferredoxin oxidoreductase (PFOR), disrupting anaerobic energy metabolism in protozoa and some bacteria/viruses.","dose": "500 mg PO BID with food x3 days.","ind": "Cryptosporidiosis and giardiasis; off-label for various protozoal/helminthic diarrheas.","contra": "Hypersensitivity.","se": "Abdominal pain, diarrhea, headache, greenish-yellow urine discoloration (harmless).","notes": "One of the few agents with activity against Cryptosporidium - useful for persistent traveler's diarrhea unresponsive to standard therapy. Always give with food.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Nitazoxanide is notable for activity against which pathogen causing persistent traveler's diarrhea?","choices": ["Cryptosporidium","Influenza virus","Staphylococcus aureus","Plasmodium falciparum"],"answer": 0,"explain": "Nitazoxanide is one of the few agents active against Cryptosporidium, useful for persistent diarrhea unresponsive to standard therapy."}]},{"id": 115,"name": "Tinidazole","brand": "Tindamax","aka": ["TNZ"],"cat": "Antiparasitics","cls": "Nitroimidazole antiprotozoal/antibacterial","mech": "Forms reactive nitro radicals that damage parasite/anaerobe DNA after intracellular reduction.","dose": "Giardiasis/amebiasis: 2 g PO single dose (amebic liver abscess: 2 g daily x3-5 days). Trichomoniasis: 2 g once.","ind": "Giardiasis, amebiasis, trichomoniasis, bacterial vaginosis.","contra": "First-trimester pregnancy, hypersensitivity to nitroimidazoles, alcohol use (disulfiram reaction).","se": "Metallic taste, nausea, headache; disulfiram-like reaction with alcohol.","notes": "Single-dose convenience beats a metronidazole course for compliance in the field. Absolutely no alcohol during and for 3 days after.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What must patients absolutely avoid while taking tinidazole and for several days after?","choices": ["Alcohol, due to a disulfiram-like reaction","Dairy products","Sunlight exposure","Caffeine"],"answer": 0,"explain": "Tinidazole causes a disulfiram-like reaction with alcohol, which must be avoided during and for 3 days after therapy."}]},{"id": 116,"name": "Oseltamivir","brand": "Tamiflu","aka": ["OTV"],"cat": "Antivirals","cls": "Neuraminidase inhibitor","mech": "Blocks influenza neuraminidase, preventing release of new virions from infected cells and limiting spread.","dose": "Treatment: 75 mg PO BID x5 days (start within 48 h of symptoms). Prophylaxis: 75 mg daily x7-10 days.","ind": "Treatment and post-exposure prophylaxis of influenza A and B, including pandemic strains.","contra": "Hypersensitivity; adjust dose for renal impairment.","se": "Nausea, vomiting, headache, rare neuropsychiatric events in adolescents.","notes": "Stockpiled for pandemic influenza and avian flu response - effective only if started early. Take with food to reduce GI upset and protect a deployed element's combat power.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "For oseltamivir (Tamiflu) to be effective in treating influenza, treatment should start within what window?","choices": ["Within 48 hours of symptom onset","Within 2 weeks of symptom onset","Only after fever resolves","At any time during the illness"],"answer": 0,"explain": "Oseltamivir is effective only if started early, ideally within 48 hours of symptom onset."}]},{"id": 117,"name": "Acyclovir","brand": "Zovirax","aka": ["ACV"],"cat": "Antivirals","cls": "Nucleoside analog antiviral","mech": "Phosphorylated by viral thymidine kinase, then inhibits viral DNA polymerase to terminate herpesvirus DNA chains.","dose": "HSV: 400 mg PO TID x7-10 days. Severe/HSV encephalitis: 10 mg/kg IV q8h. Hydrate well with IV use.","ind": "HSV-1/2 infections, herpes encephalitis, varicella and herpes zoster.","contra": "Hypersensitivity; renal dose adjustment required.","se": "Nausea, headache, crystalluria/nephrotoxicity with inadequate hydration, IV phlebitis.","notes": "Aggressively hydrate before/during IV dosing to prevent crystal nephropathy. Suspected HSV encephalitis is a start-empirically-now diagnosis - do not wait for PCR.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What precaution prevents crystal nephropathy when giving IV acyclovir?","choices": ["Aggressive hydration before and during dosing","Giving it rapidly as a bolus","Withholding all fluids","Co-administering a diuretic"],"answer": 0,"explain": "Aggressive hydration before and during IV acyclovir prevents crystalluria and nephrotoxicity."}]},{"id": 118,"name": "Valacyclovir","brand": "Valtrex","aka": ["VACV","valaciclovir"],"cat": "Antivirals","cls": "Nucleoside analog prodrug","mech": "Prodrug rapidly converted to acyclovir, which inhibits viral DNA polymerase; better oral bioavailability than acyclovir.","dose": "Genital HSV: 1 g PO BID x7-10 days (recurrence 500 mg BID x3 d). Zoster: 1 g TID x7 days.","ind": "Herpes labialis, genital herpes (treatment/suppression), herpes zoster.","contra": "Hypersensitivity to valacyclovir/acyclovir; caution in immunocompromised (TTP/HUS reported at high doses).","se": "Headache, nausea, abdominal pain, rare TTP/HUS in severely immunocompromised.","notes": "Better absorption and simpler dosing than acyclovir make it the practical oral choice in the field. Suppressive dosing keeps recurrent herpes from sidelining an operator.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What practical advantage does valacyclovir have over acyclovir in the field?","choices": ["Better oral bioavailability and simpler dosing","It can be given without any water","It has no side effects at all","It is the only agent active against HSV"],"answer": 0,"explain": "Valacyclovir is a prodrug with better oral absorption and simpler dosing than acyclovir."}]},{"id": 119,"name": "Rabies Immune Globulin","brand": "HyperRAB / Imogam","aka": ["RIG","HRIG"],"cat": "Antivirals","cls": "Passive immunization (human immunoglobulin)","mech": "Provides immediate passive rabies-neutralizing antibodies at the wound while the active vaccine builds active immunity.","dose": "20 IU/kg, infiltrate as much as possible into and around the wound; remainder IM at a site distant from the vaccine.","ind": "Rabies post-exposure prophylaxis in previously unvaccinated patients, given with rabies vaccine.","contra": "None in true exposure (rabies is uniformly fatal); do not give to previously vaccinated patients.","se": "Local pain/soreness, low-grade fever, rare hypersensitivity.","notes": "Infiltrate the bite wound itself - do not give all of it IM. Give at a different site and never the same syringe as the vaccine. A genuine SOF problem given austere animal exposures.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "How should rabies immune globulin be administered for post-exposure prophylaxis?","choices": ["Infiltrate as much as possible into and around the wound, remainder IM at a distant site","Give the entire dose IV","Inject it all into the same site as the vaccine","Give it orally with food"],"answer": 0,"explain": "Rabies immune globulin should be infiltrated into and around the wound, with the remainder given IM at a site distant from the vaccine."}]},{"id": 120,"name": "Tetanus Immune Globulin","brand": "HyperTET","aka": ["TIG"],"cat": "Antivirals","cls": "Passive immunization (human immunoglobulin)","mech": "Neutralizes circulating, unbound tetanospasmin toxin; does not reverse toxin already bound to nerve terminals.","dose": "Prophylaxis: 250 units IM. Treatment of active tetanus: 3000-6000 units IM.","ind": "Tetanus-prone wounds in patients with unknown/incomplete immunization; treatment of clinical tetanus.","contra": "Hypersensitivity to human immunoglobulin (relative; benefit usually outweighs).","se": "Injection-site pain, low-grade fever, rare anaphylaxis.","notes": "Give with tetanus toxoid (different site/syringe) for tetanus-prone wounds when vaccination status is unknown - common in austere trauma. Treats toxin not yet bound to nerves, so give early.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What is the key limitation of tetanus immune globulin regarding the toxin?","choices": ["It neutralizes only unbound toxin, not toxin already bound to nerves","It reverses all neurologic damage instantly","It works only if given orally","It replaces the need for tetanus toxoid"],"answer": 0,"explain": "TIG neutralizes circulating unbound tetanospasmin but cannot reverse toxin already bound to nerve terminals, so it must be given early."}]},{"id": 121,"name": "Pralidoxime","brand": "Protopam","aka": ["2-PAM","2-PAM Cl","pralidoxime chloride"],"cat": "CBRN & Antidotes","cls": "Oxime / cholinesterase reactivator","mech": "Reactivates acetylcholinesterase by cleaving the organophosphate from the enzyme before irreversible aging occurs.","dose": "1-2 g IV/IM, may repeat; or auto-injector 600 mg IM. Pair with atropine. Give before aging.","ind": "Organophosphate/nerve-agent (G- and V-series) poisoning, alongside atropine.","contra": "Hypersensitivity (relative); give regardless in life-threatening exposure.","se": "Hypertension, tachycardia, dizziness, blurred vision, injection-site pain.","notes": "Treats nicotinic (muscle) signs that atropine cannot - always give both. Effectiveness drops sharply once the agent 'ages' (soman ages in minutes), so dose immediately.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Pralidoxime (2-PAM) is always paired with atropine because it treats which signs that atropine cannot?","choices": ["Nicotinic (muscle) signs","Only muscarinic secretions","Cardiac arrhythmias alone","Seizures specifically"],"answer": 0,"explain": "Pralidoxime reactivates acetylcholinesterase to treat nicotinic muscle signs that atropine does not address, so both are given together."}]},{"id": 122,"name": "DuoDote","brand": "DuoDote","aka": ["ATNAA equivalent","atropine/pralidoxime auto-injector"],"cat": "CBRN & Antidotes","cls": "Combination nerve-agent antidote auto-injector","mech": "Atropine blocks muscarinic overstimulation while pralidoxime reactivates acetylcholinesterase against organophosphate nerve agents.","dose": "One auto-injector (2.1 mg atropine + 600 mg pralidoxime) IM into outer thigh; repeat per severity, up to 3 for severe.","ind": "Field treatment of nerve-agent or organophosphate poisoning by first responders/medics.","contra": "None in a true nerve-agent casualty (life-threatening emergency).","se": "Atropine effects (dry mouth, mydriasis, tachycardia), pralidoxime effects (hypertension, blurred vision).","notes": "Single-needle civilian/EMS counterpart to the military ATNAA - same drugs, one stick. Give a benzodiazepine (e.g., diazepam/midazolam) for seizures in severe exposures.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "How does the DuoDote auto-injector differ from the military ATNAA?","choices": ["It delivers the same two drugs through a single needle rather than two","It contains only atropine","It is given orally","It contains a different nerve-agent antidote entirely"],"answer": 0,"explain": "DuoDote is the civilian/EMS single-needle counterpart to the ATNAA, delivering the same atropine plus pralidoxime in one stick."}]},{"id": 123,"name": "Pyridostigmine Bromide","brand": "PB tablets / Mestinon","aka": ["PB","NAPP"],"cat": "CBRN & Antidotes","cls": "Reversible cholinesterase inhibitor (nerve-agent pretreatment)","mech": "Reversibly binds a fraction of acetylcholinesterase, shielding it from irreversible soman binding so enzyme is freed afterward.","dose": "Pretreatment: 30 mg PO q8h, started before anticipated soman (GD) threat; stop at exposure and treat with atropine/2-PAM.","ind": "Pretreatment to improve survival against soman (GD) nerve-agent threat (not a standalone treatment).","contra": "Mechanical GI/urinary obstruction; caution in asthma and bradyarrhythmias.","se": "Abdominal cramps, increased secretions, urinary urgency, mild miosis.","notes": "It is a PRE-treatment, not a treatment - it must be stopped and followed by atropine/2-PAM at exposure. FDA-approved specifically for the soman threat.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What is the correct way to use pyridostigmine bromide against the soman (GD) threat?","choices": ["As a pre-treatment started before exposure, then stopped and followed by atropine/2-PAM at exposure","As the sole treatment given after exposure","As an antidote injected during a seizure","Only after atropine has failed"],"answer": 0,"explain": "Pyridostigmine is a pre-treatment that shields acetylcholinesterase from soman; it is stopped at exposure and followed by atropine and 2-PAM."}]},{"id": 124,"name": "Hydroxocobalamin","brand": "Cyanokit","aka": ["vitamin B12a","OHCob"],"cat": "CBRN & Antidotes","cls": "Cyanide antidote (cobalt chelator)","mech": "Binds cyanide ion to form non-toxic cyanocobalamin (vitamin B12), which is renally excreted.","dose": "5 g IV over 15 min; may repeat 5 g for a total of 10 g depending on severity.","ind": "Known/suspected cyanide poisoning, including smoke inhalation in enclosed-space fires.","contra": "None absolute in life-threatening cyanide toxicity.","se": "Red discoloration of skin/urine, transient hypertension, rash, can interfere with colorimetric labs.","notes": "Preferred over the nitrite/thiosulfate kit because it does not cause methemoglobinemia - safe when carbon-monoxide co-poisoning is likely. Turns everything red, including the patient and lab samples.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Why is hydroxocobalamin (Cyanokit) preferred over the nitrite/thiosulfate kit, especially with concurrent carbon monoxide poisoning?","choices": ["It does not cause methemoglobinemia","It works more slowly and gently","It is the only oral cyanide antidote","It reverses carbon monoxide directly"],"answer": 0,"explain": "Hydroxocobalamin does not induce methemoglobinemia, making it safer than nitrites when carbon monoxide co-poisoning is likely."}]},{"id": 125,"name": "Sodium Thiosulfate","brand": "Nithiodote (with sodium nitrite)","aka": ["STS"],"cat": "CBRN & Antidotes","cls": "Cyanide antidote (sulfur donor)","mech": "Provides sulfur substrate for rhodanese to convert cyanide into less-toxic thiocyanate for renal excretion.","dose": "12.5 g (50 mL of 25%) IV, typically after sodium nitrite in the cyanide antidote kit.","ind": "Cyanide poisoning (component of the nitrite/thiosulfate kit); adjunct to hydroxocobalamin.","contra": "Hypersensitivity (rare); use cautiously in renal impairment.","se": "Nausea, hypotension if infused rapidly, headache.","notes": "Works slower than hydroxocobalamin but can be added to it for refractory cases. Part of the legacy cyanide kit with amyl/sodium nitrite.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "By what mechanism does sodium thiosulfate counteract cyanide?","choices": ["It provides sulfur substrate for rhodanese to convert cyanide to thiocyanate","It binds cyanide to form vitamin B12","It induces methemoglobin to trap cyanide","It blocks cyanide absorption in the gut"],"answer": 0,"explain": "Sodium thiosulfate donates sulfur to the enzyme rhodanese, which converts cyanide to less-toxic thiocyanate for renal excretion."}]},{"id": 126,"name": "Potassium Iodide","brand": "ThyroShield / iOSAT","aka": ["KI","SSKI"],"cat": "CBRN & Antidotes","cls": "Thyroid-blocking agent (radioprotectant)","mech": "Saturates the thyroid with stable iodine, blocking uptake of radioactive iodine-131 and reducing thyroid cancer risk.","dose": "Adult: 130 mg PO once daily during radioiodine exposure risk; ideally within hours before/after release.","ind": "Thyroid protection against radioactive iodine in a nuclear/radiological release.","contra": "Iodine hypersensitivity, dermatitis herpetiformis, hypocomplementemic vasculitis.","se": "Metallic taste, GI upset, rash, sialadenitis, rarely thyroid dysfunction.","notes": "Protects ONLY the thyroid from radioiodine - it is not a general radiation antidote. Timing is everything: most effective just before or within a few hours of exposure.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What does potassium iodide actually protect against in a radiological release?","choices": ["Uptake of radioactive iodine by the thyroid only","All forms of radiation throughout the body","Cyanide from smoke inhalation","Nerve-agent exposure"],"answer": 0,"explain": "Potassium iodide saturates the thyroid with stable iodine, blocking only radioiodine uptake; it is not a general radiation antidote."}]},{"id": 127,"name": "Prussian Blue","brand": "Radiogardase","aka": ["ferric hexacyanoferrate","insoluble Prussian blue"],"cat": "CBRN & Antidotes","cls": "Internal radionuclide decorporation agent","mech": "Binds cesium and thallium in the gut, interrupting enterohepatic recirculation to enhance fecal elimination.","dose": "3 g PO TID (adult); continue for weeks per contamination level and dosimetry.","ind": "Internal contamination with radioactive cesium-137 or thallium.","contra": "Hypersensitivity; caution in GI motility disorders.","se": "Constipation, blue-colored stool, hypokalemia with prolonged use.","notes": "The go-to decorporation agent after a dirty-bomb cesium-137 exposure - it speeds gut elimination, not surface decon. Expect blue stools and monitor potassium.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What is the primary mechanism by which Prussian Blue (Radiogardase) decorporates internal radioactive cesium-137?","choices": ["It chelates cesium in the blood for renal excretion","It binds cesium and thallium in the gut, interrupting enterohepatic recirculation to enhance fecal elimination","It blocks thyroidal uptake of radioactive cesium","It neutralizes external surface contamination on the skin"],"answer": 1,"explain": "Prussian Blue traps cesium and thallium in the gut and interrupts their enterohepatic recirculation, speeding fecal elimination rather than acting on blood or skin."}]},{"id": 128,"name": "Pentetate Calcium/Zinc Trisodium","brand": "Ca-DTPA / Zn-DTPA","aka": ["DTPA","pentetate"],"cat": "CBRN & Antidotes","cls": "Chelating decorporation agent","mech": "Chelates transuranic metals to form stable complexes that are excreted in the urine.","dose": "1 g IV over 3-4 min or by nebulizer; start with Ca-DTPA (day 1), switch to Zn-DTPA for prolonged courses.","ind": "Internal contamination with plutonium, americium, or curium.","contra": "Hypersensitivity; caution in nephrotoxicity and severe hematologic depression.","se": "Nausea, headache, depletion of essential metals (zinc, manganese) with Ca-DTPA over time.","notes": "Use Ca-DTPA first (more potent early), then transition to Zn-DTPA to limit trace-metal depletion. Reserved for transuranic (plutonium-type) internal contamination.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Pentetate calcium/zinc trisodium (Ca-DTPA / Zn-DTPA) is indicated for internal contamination with which class of radionuclides?","choices": ["Radioactive iodine isotopes","Cesium-137 and thallium","Transuranic metals such as plutonium, americium, or curium","Radioactive cobalt and strontium"],"answer": 2,"explain": "DTPA chelates transuranic metals like plutonium, americium, and curium into stable complexes excreted in the urine."}]},{"id": 129,"name": "Physostigmine","brand": "Antilirium","aka": ["eserine"],"cat": "CBRN & Antidotes","cls": "Reversible cholinesterase inhibitor","mech": "Crosses the blood-brain barrier and inhibits acetylcholinesterase, raising acetylcholine to reverse central anticholinergic effects.","dose": "0.5-2 mg slow IV over at least 5 min; have atropine ready for cholinergic crisis.","ind": "Severe anticholinergic toxidrome (e.g., agent BZ/3-quinuclidinyl benzilate, deliriant poisoning).","contra": "Asthma, gangrene, cardiovascular disease, bowel/bladder obstruction, and TCA overdose (asystole risk).","se": "Bradycardia, seizures, salivation, bronchospasm, vomiting if pushed too fast.","notes": "Antidote for the incapacitating agent BZ and severe antimuscarinic delirium - the rare anticholinesterase that crosses into the CNS. Avoid in TCA overdose (can precipitate asystole).","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "Physostigmine is contraindicated in which overdose because it can precipitate asystole?","choices": ["Tricyclic antidepressant (TCA) overdose","Benzodiazepine overdose","Opioid overdose","Beta-blocker overdose"],"answer": 0,"explain": "Physostigmine is contraindicated in TCA overdose because it carries an asystole risk in that setting."}]},{"id": 130,"name": "Crotalidae Polyvalent Immune Fab","brand": "CroFab","aka": ["FabAV","ovine Fab antivenom"],"cat": "Envenomation & Antivenom","cls": "Antivenom (ovine Fab fragments)","mech": "Sheep-derived Fab antibody fragments bind and neutralize North American pit-viper venom components.","dose": "Initial 4-6 vials IV, repeat until control achieved, then 2 vials at 6, 12, 18 h maintenance.","ind": "North American crotalid (rattlesnake, copperhead, cottonmouth) envenomation with progressing toxicity.","contra": "Known allergy to papaya/papain or sheep protein (relative; weigh against envenomation severity).","se": "Urticaria, serum sickness, recurrent coagulopathy/thrombocytopenia, rare anaphylaxis.","notes": "Dose to clinical control (halting progression), not to a fixed number of vials. Recurrent coagulopathy is common - check labs and re-dose over the following days.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "How should Crotalidae Polyvalent Immune Fab (CroFab) dosing be guided in pit-viper envenomation?","choices": ["To a fixed total of two vials regardless of response","By the patient body weight alone","To clinical control that halts progression of toxicity, then maintenance dosing","Only once coagulopathy has fully resolved"],"answer": 2,"explain": "CroFab is titrated to clinical control that halts progression, not to a fixed vial count, followed by scheduled maintenance doses."}]},{"id": 131,"name": "Crotalidae Immune F(ab')2","brand": "Anavip","aka": ["F(ab')2 antivenom","equine antivenom"],"cat": "Envenomation & Antivenom","cls": "Antivenom (equine F(ab')2 fragments)","mech": "Horse-derived larger F(ab')2 fragments neutralize pit-viper venom with a longer half-life, reducing late recurrent coagulopathy.","dose": "Initial 10 vials IV; additional 10 vials if not controlled, then 4-vial maintenance as needed.","ind": "North American pit-viper (rattlesnake) envenomation, especially where late hematologic recurrence is a concern.","contra": "Known horse-protein hypersensitivity (relative in severe envenomation).","se": "Hypersensitivity reactions, serum sickness, pruritus.","notes": "Longer-acting F(ab')2 means less late recurrent coagulopathy than CroFab, so often fewer follow-up doses. Equine-derived - watch for serum sickness.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What advantage does Crotalidae Immune F(ab')2 (Anavip) offer over CroFab in pit-viper envenomation?","choices": ["It is derived from sheep rather than horses","Its longer half-life means less late recurrent coagulopathy and often fewer follow-up doses","It carries no risk of serum sickness","It also neutralizes coral snake neurotoxin"],"answer": 1,"explain": "The larger F(ab')2 fragments have a longer half-life, reducing late recurrent coagulopathy and the need for follow-up dosing."}]},{"id": 132,"name": "Coral Snake Antivenin","brand": "Antivenin (Micrurus fulvius)","aka": ["NA coral snake antivenom"],"cat": "Envenomation & Antivenom","cls": "Antivenom (equine whole IgG)","mech": "Equine antibodies neutralize Micrurus (coral snake) neurotoxic venom that otherwise causes progressive descending paralysis.","dose": "3-5 vials IV initially, additional vials as needed; treat early before neurotoxicity is established.","ind": "Eastern coral snake (Micrurus fulvius) envenomation or high-suspicion bite.","contra": "Horse-serum hypersensitivity (relative; envenomation is life-threatening).","se": "Anaphylaxis, serum sickness, urticaria.","notes": "Coral-snake neurotoxicity can be delayed hours then progress to respiratory failure - treat early and prepare to support the airway. Remember 'red touch yellow, kill a fellow.'","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "Why should Coral Snake Antivenin be given early, even before signs appear?","choices": ["Because coral-snake venom destroys the antivenin if delayed","Because neurotoxicity can be delayed for hours then progress to respiratory failure","Because the bite causes immediate severe coagulopathy","Because the antivenin only works on fresh wounds"],"answer": 1,"explain": "Coral-snake neurotoxicity may be delayed hours then progress to respiratory failure, so early treatment and airway preparation are critical."}]},{"id": 133,"name": "Centruroides Immune F(ab')2","brand": "Anascorp","aka": ["scorpion antivenom","Centruroides antivenom"],"cat": "Envenomation & Antivenom","cls": "Antivenom (equine F(ab')2 fragments)","mech": "Equine F(ab')2 fragments bind and neutralize Centruroides scorpion venom, reversing neuromuscular and autonomic toxicity.","dose": "Initial 3 vials IV over 10 min; additional 1 vial q30-60 min until clinical resolution.","ind": "Severe Centruroides (bark scorpion) envenomation, especially in children with neuromotor signs.","contra": "Known horse-protein hypersensitivity (relative).","se": "Hypersensitivity, serum sickness, vomiting.","notes": "Dramatically reverses the severe neuromotor agitation and roving eye movements of bark-scorpion stings, often within an hour. Most envenomations in adults are managed supportively.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "Centruroides Immune F(ab')2 (Anascorp) most dramatically reverses which feature of severe bark-scorpion envenomation?","choices": ["Local tissue necrosis at the sting site","Severe neuromotor agitation and roving eye movements","Progressive coagulopathy","Acute renal failure"],"answer": 1,"explain": "Anascorp rapidly reverses the severe neuromotor agitation and roving eye movements of bark-scorpion stings, often within an hour."}]},{"id": 134,"name": "Box Jellyfish Antivenom","brand": "CSL Box Jellyfish Antivenom","aka": ["Chironex antivenom","sea wasp antivenom"],"cat": "Envenomation & Antivenom","cls": "Antivenom (ovine IgG)","mech": "Sheep-derived antibodies neutralize Chironex fleckeri (box jellyfish) venom that causes cardiovascular collapse and severe pain.","dose": "1 ampoule IV (or 3 IM); titrate up to 3-6 ampoules for cardiovascular instability.","ind": "Major Chironex fleckeri box-jellyfish envenomation with cardiorespiratory compromise.","contra": "None in life-threatening envenomation; ovine-protein caution.","se": "Hypersensitivity reactions, serum sickness.","notes": "Douse the area with vinegar (acetic acid) to inactivate undischarged nematocysts BEFORE removing tentacles - do not use fresh water. A real hazard for Indo-Pacific maritime SOF operations.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "Before removing tentacles in a Chironex fleckeri (box jellyfish) envenomation, the area should be doused with what?","choices": ["Fresh water","Vinegar (acetic acid) to inactivate undischarged nematocysts","Rubbing alcohol","Hot saline"],"answer": 1,"explain": "Vinegar inactivates undischarged nematocysts before tentacle removal; fresh water must be avoided as it can trigger further envenomation."}]},{"id": 135,"name": "Activated Charcoal","brand": "Actidose / EZ-Char","aka": ["AC","activated carbon"],"cat": "CBRN & Antidotes","cls": "GI adsorbent / decontaminant","mech": "Adsorbs ingested toxins onto its large surface area within the gut, preventing systemic absorption.","dose": "25-100 g PO/NG (adult), ideally within 1 h of ingestion; multi-dose 25-50 g q4h for select toxins.","ind": "Recent ingestion of many oral poisons and drug overdoses to limit absorption.","contra": "Unprotected airway/depressed mental status, bowel obstruction/perforation, caustic ingestion, hydrocarbons.","se": "Vomiting (aspiration risk), constipation, black stools, rare bowel obstruction with repeated dosing.","notes": "Does NOT bind iron, lithium, alcohols, or most heavy metals - know its blind spots. Protect the airway first; aspiration of charcoal is a serious complication.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Which of the following does activated charcoal NOT effectively bind?","choices": ["Most oral drug overdoses","Iron, lithium, alcohols, and most heavy metals","Many ingested organic poisons","Carbamazepine on multi-dose regimens"],"answer": 1,"explain": "Activated charcoal does not bind iron, lithium, alcohols, or most heavy metals, an important blind spot in poisoning management."}]},{"id": 136,"name": "Calcium Chloride","brand": "","aka": ["CaCl2","Calcium chloride 10%"],"cat": "IV Fluids & Electrolytes","cls": "Electrolyte / calcium salt","mech": "Provides ionized calcium that restores myocardial contractility, stabilizes the cardiac membrane, and supports the coagulation cascade.","dose": "1 g (10 mL of 10%) slow IV over 5-10 min via central or large-bore line; repeat per ionized calcium. Roughly 3x the elemental calcium of an equal volume of gluconate.","ind": "Hypocalcemia of massive transfusion (citrate toxicity), hyperkalemia, calcium-channel-blocker or magnesium toxicity, cardiac membrane stabilization.","contra": "Hypercalcemia, digoxin toxicity (use caution), do not mix with bicarbonate (precipitates).","se": "Tissue necrosis and severe extravasation injury, bradycardia, hypotension if pushed fast, vein irritation.","notes": "In massive-transfusion ratios SOF medics give calcium early to prevent the lethal-triad coagulopathy; flush the line before and after to avoid bicarb precipitation.","tccc": true,"duty": "go","scenarios": [],"quiz": [{"q": "Why do SOF medics give calcium early during massive-transfusion ratios?","choices": ["To raise the patient blood glucose","To prevent the lethal-triad coagulopathy from citrate-induced hypocalcemia","To reverse opioid-induced respiratory depression","To buffer metabolic acidosis"],"answer": 1,"explain": "Citrate in stored blood chelates calcium; giving calcium early prevents the resulting hypocalcemia that worsens lethal-triad coagulopathy."},{"q": "Which is true about administering 10% Calcium Chloride?","choices": ["It can be safely mixed in the same line as sodium bicarbonate","It must never be given through a large-bore line","It causes severe tissue necrosis on extravasation and should not be mixed with bicarbonate, which precipitates","It provides about one-third the elemental calcium of an equal volume of gluconate"],"answer": 2,"explain": "Calcium chloride causes severe extravasation necrosis and precipitates with bicarbonate, so the line must be flushed before and after; it delivers roughly 3x the elemental calcium of gluconate."}]},{"id": 137,"name": "Sodium Bicarbonate","brand": "","aka": ["NaHCO3","Bicarb","Sodium hydrogen carbonate"],"cat": "IV Fluids & Electrolytes","cls": "Alkalinizing agent / buffer","mech": "Dissociates to bicarbonate which buffers excess hydrogen ions, raising serum and urine pH.","dose": "1 mEq/kg IV bolus (typically 50 mEq of 8.4%) for severe metabolic acidosis or cardiotoxin overdose; repeat per pH/clinical response.","ind": "Severe metabolic acidosis, hyperkalemia, tricyclic antidepressant or sodium-channel-blocker toxicity, urinary alkalinization, prolonged arrest.","contra": "Metabolic or respiratory alkalosis, hypocalcemia, hypernatremia, inadequate ventilation (generates CO2).","se": "Hypernatremia, hypokalemia, metabolic alkalosis, fluid overload, tissue necrosis on extravasation.","notes": "Only useful if ventilation is adequate to blow off the generated CO2; never run in the same line as calcium or catecholamines.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Sodium bicarbonate is only useful for acidosis under what condition?","choices": ["When the patient is also alkalotic","When ventilation is adequate to blow off the generated CO2","When given in the same line as calcium","When serum sodium is already high"],"answer": 1,"explain": "Bicarbonate generates CO2 as it buffers acid, so it only helps if ventilation can clear that CO2; it must not share a line with calcium or catecholamines."}]},{"id": 138,"name": "Amiodarone","brand": "Cordarone, Nexterone, Pacerone","aka": ["Amio"],"cat": "Cardiovascular & Emergency","cls": "Class III antiarrhythmic","mech": "Blocks potassium, sodium, and calcium channels and beta receptors to prolong the action potential and refractory period.","dose": "Shock-refractory VF/pVT: 300 mg IV/IO push, then 150 mg. Stable VT/SVT: 150 mg IV over 10 min, then 1 mg/min for 6 h, then 0.5 mg/min.","ind": "Ventricular fibrillation, pulseless VT, stable wide-complex tachycardia, atrial fibrillation rate/rhythm control.","contra": "Severe sinus-node dysfunction, 2nd/3rd-degree block without pacing, cardiogenic shock, iodine allergy, marked QT prolongation.","se": "Hypotension and bradycardia (esp. with fast push), QT prolongation, pulmonary fibrosis and thyroid/liver toxicity with chronic use.","notes": "First-line antiarrhythmic in the TCCC/CPR arrest algorithm; push undiluted in arrest but dilute for the stable patient to limit hypotension.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What is the initial amiodarone dose for shock-refractory ventricular fibrillation or pulseless VT?","choices": ["150 mg IV over 10 minutes","1 mg/min infusion","300 mg IV/IO push, then 150 mg","6 mg rapid IV push"],"answer": 2,"explain": "In shock-refractory VF/pVT, amiodarone is given as 300 mg IV/IO push followed by a 150 mg dose."}]},{"id": 139,"name": "Adenosine","brand": "Adenocard","aka": ["ADO"],"cat": "Cardiovascular & Emergency","cls": "Endogenous nucleoside antiarrhythmic","mech": "Transiently activates potassium channels and blocks AV-nodal conduction, briefly interrupting reentrant SVT circuits.","dose": "6 mg rapid IV push into a proximal vein followed by a 20 mL saline flush; if no conversion, 12 mg, may repeat 12 mg once.","ind": "Stable narrow-complex paroxysmal SVT; diagnostic in regular wide-complex tachycardia of uncertain origin.","contra": "2nd/3rd-degree heart block or sick sinus without pacemaker, known WPW with atrial fibrillation, severe reactive airway disease.","se": "Transient asystole, flushing, chest pressure, dyspnea, sense of impending doom lasting seconds.","notes": "Half-life is under 10 seconds, so push as fast as possible immediately followed by a hard saline flush, ideally via a stopcock; warn the patient about the brief awful feeling.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Why must adenosine be pushed as fast as possible and followed by a rapid saline flush?","choices": ["Because it causes painful injection-site necrosis if slow","Because its half-life is under 10 seconds","Because slow administration triggers malignant hyperthermia","Because it precipitates in the vein at low flow"],"answer": 1,"explain": "Adenosine has a half-life under 10 seconds, so a rapid push and immediate hard saline flush are needed to reach the AV node before it is metabolized."}]},{"id": 140,"name": "Magnesium Sulfate","brand": "","aka": ["MgSO4","Mag"],"cat": "IV Fluids & Electrolytes","cls": "Electrolyte / antiarrhythmic / smooth-muscle relaxant","mech": "Acts as a physiologic calcium antagonist that stabilizes membranes, relaxes smooth muscle, and suppresses early after-depolarizations.","dose": "Torsades: 1-2 g IV over 5-15 min. Severe asthma: 2 g IV over 20 min. Eclampsia: 4-6 g load then 1-2 g/h.","ind": "Torsades de pointes, refractory ventricular arrhythmias, severe bronchospasm, eclampsia/pre-eclampsia, symptomatic hypomagnesemia.","contra": "Heart block, severe renal failure (risk of accumulation), myasthenia gravis.","se": "Hypotension, flushing, loss of deep-tendon reflexes, respiratory depression and cardiac arrest with overdose.","notes": "First-line for torsades regardless of magnesium level; loss of patellar reflex is the earliest field sign of toxicity, calcium is the antidote.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Magnesium sulfate is considered first-line therapy for which arrhythmia, regardless of the serum magnesium level?","choices": ["Stable narrow-complex SVT","Atrial fibrillation with rapid ventricular response","Torsades de pointes","Sinus bradycardia"],"answer": 2,"explain": "Magnesium sulfate is first-line for torsades de pointes regardless of the measured magnesium level."}]},{"id": 141,"name": "Procainamide","brand": "Pronestyl","aka": ["PCA"],"cat": "Cardiovascular & Emergency","cls": "Class Ia antiarrhythmic","mech": "Blocks fast sodium channels to slow conduction and prolong the action potential and refractory period.","dose": "20-50 mg/min IV until arrhythmia suppressed, hypotension, QRS widens 50%, or 17 mg/kg max; maintenance 1-4 mg/min.","ind": "Stable monomorphic VT, pre-excited atrial fibrillation (WPW), conversion of SVT when other agents fail.","contra": "Torsades/QT prolongation, 2nd/3rd-degree block, lupus, severe heart failure, myasthenia gravis.","se": "Hypotension, QRS/QT widening, proarrhythmia, drug-induced lupus with chronic use.","notes": "Preferred over amiodarone for stable, well-perfused wide-complex VT and the drug of choice for WPW with atrial fibrillation; stop infusion at the listed endpoints.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "For which arrhythmia is procainamide considered the drug of choice?","choices": ["Torsades de pointes","Pre-excited atrial fibrillation (WPW with atrial fibrillation)","Pulseless electrical activity","Sinus tachycardia"],"answer": 1,"explain": "Procainamide is the drug of choice for WPW with atrial fibrillation and is preferred over amiodarone for stable monomorphic VT."}]},{"id": 142,"name": "Vasopressin","brand": "Pitressin, Vasostrict","aka": ["ADH","Antidiuretic hormone","AVP"],"cat": "Cardiovascular & Emergency","cls": "Vasopressor / antidiuretic hormone analog","mech": "Stimulates V1 vascular receptors to cause direct vasoconstriction independent of adrenergic pathways.","dose": "Septic/vasodilatory shock: 0.03-0.04 units/min IV infusion (fixed, not titrated). GI/variceal bleed: 0.2-0.4 units/min.","ind": "Catecholamine-refractory distributive shock as a norepinephrine adjunct, vasodilatory shock, variceal hemorrhage.","contra": "Coronary artery disease (may provoke ischemia), severe heart failure, mesenteric ischemia.","se": "Excessive vasoconstriction, myocardial and mesenteric/digital ischemia, hyponatremia, decreased cardiac output.","notes": "Works when acidosis has blunted catecholamine response, so it is a useful add-on to norepi in deep septic shock; run at the fixed dose rather than titrating.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "How should vasopressin be administered in catecholamine-refractory septic shock?","choices": ["As a fixed 0.03-0.04 units/min infusion that is not titrated","As a rapid IV bolus repeated every minute","Titrated aggressively to a MAP above 90 mmHg","Only as a single subcutaneous injection"],"answer": 0,"explain": "Vasopressin is run at a fixed low infusion rate of 0.03-0.04 units/min as a norepinephrine adjunct rather than being titrated."}]},{"id": 143,"name": "Norepinephrine","brand": "Levophed","aka": ["Noradrenaline","Norepi","Levo"],"cat": "Cardiovascular & Emergency","cls": "Vasopressor (alpha/beta adrenergic agonist)","mech": "Stimulates alpha-1 receptors for potent vasoconstriction with modest beta-1 inotropy, raising mean arterial pressure.","dose": "Start 0.05-0.1 mcg/kg/min (about 5-10 mcg/min) IV infusion, titrate to MAP greater than 65 mmHg; central line preferred.","ind": "Septic and other distributive shock, vasodilatory/neurogenic shock, hypotension refractory to fluids.","contra": "Uncorrected hypovolemia (resuscitate first), use caution with peripheral lines and known dysrhythmias.","se": "Reflex bradycardia, arrhythmias, peripheral and organ ischemia, severe extravasation necrosis.","notes": "First-line vasopressor for septic shock and increasingly used in resuscitation; if peripheral, use a proximal large vein and watch the site, phentolamine is the extravasation antidote.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What is the extravasation antidote for norepinephrine injury at a peripheral IV site?","choices": ["Calcium gluconate","Phentolamine","Sodium bicarbonate","Hyaluronidase alone"],"answer": 1,"explain": "Phentolamine is the antidote for norepinephrine extravasation, which can otherwise cause severe local necrosis."}]},{"id": 144,"name": "Phenylephrine","brand": "Neo-Synephrine","aka": ["Neo","Phenyl"],"cat": "Cardiovascular & Emergency","cls": "Vasopressor (selective alpha-1 agonist)","mech": "Pure alpha-1 agonist that causes vasoconstriction and raises systemic vascular resistance with no direct cardiac stimulation.","dose": "Bolus 50-200 mcg IV for transient hypotension; infusion 0.1-0.5 mcg/kg/min titrated to pressure.","ind": "Hypotension during sedation/induction, peri-intubation hypotension, hypotension with tachycardia where avoiding beta effects is desired.","contra": "Severe hypertension, bradycardia, narrow-angle glaucoma, peripheral vascular disease.","se": "Reflex bradycardia, hypertension, reduced cardiac output, organ ischemia.","notes": "Handy push-dose pressor for the hypotensive, tachycardic patient peri-RSI because it raises pressure without worsening heart rate; dilute to 100 mcg/mL for bolus dosing.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Why is phenylephrine a useful push-dose pressor for the hypotensive, tachycardic patient peri-intubation?","choices": ["It increases heart rate through beta-1 stimulation","It raises blood pressure as a pure alpha-1 agonist without worsening the heart rate","It provides strong inotropy and chronotropy","It causes pulmonary vasodilation"],"answer": 1,"explain": "As a pure alpha-1 agonist, phenylephrine raises pressure without direct cardiac stimulation, so it does not worsen an already fast heart rate."}]},{"id": 145,"name": "Heparin","brand": "","aka": ["Unfractionated heparin","UFH"],"cat": "Hemostatic Agents","cls": "Anticoagulant","mech": "Binds antithrombin III, accelerating inactivation of thrombin and factor Xa to prevent clot propagation.","dose": "ACS/PE: 60-80 units/kg IV bolus then 12-18 units/kg/h infusion titrated to aPTT/anti-Xa. Line flush: 10-100 units/mL.","ind": "Acute coronary syndrome, venous thromboembolism/PE, atrial-fibrillation anticoagulation, maintaining catheter patency.","contra": "Active major bleeding, history of heparin-induced thrombocytopenia, recent neurosurgery or hemorrhagic stroke.","se": "Bleeding, heparin-induced thrombocytopenia, hyperkalemia, osteoporosis with prolonged use.","notes": "Effect is rapidly reversible with protamine, which makes it preferred over LMWH when bleeding risk or imminent surgery is a concern; rarely used in far-forward trauma care.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "What agent rapidly reverses the anticoagulant effect of unfractionated heparin?","choices": ["Vitamin K","Protamine","Fresh frozen plasma only","Idarucizumab"],"answer": 1,"explain": "Heparin is rapidly reversible with protamine, which makes it preferred over LMWH when bleeding risk or imminent surgery is a concern."}]},{"id": 146,"name": "Enoxaparin","brand": "Lovenox","aka": ["LMWH","Low-molecular-weight heparin"],"cat": "Hemostatic Agents","cls": "Low-molecular-weight heparin anticoagulant","mech": "Potentiates antithrombin to preferentially inhibit factor Xa, providing predictable anticoagulation.","dose": "VTE treatment 1 mg/kg SC q12h (or 1.5 mg/kg daily). Prophylaxis 40 mg SC daily. Reduce in renal impairment.","ind": "DVT/PE treatment and prophylaxis, ACS, bridging anticoagulation.","contra": "Active bleeding, HIT history, severe renal failure (use UFH), epidural catheter with treatment dosing.","se": "Bleeding, injection-site hematoma, thrombocytopenia, hyperkalemia.","notes": "Subcutaneous dosing and no routine lab monitoring make it field-friendly for VTE prophylaxis on prolonged casualty care; protamine only partially reverses it.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "What makes enoxaparin (Lovenox) relatively field-friendly for VTE prophylaxis in prolonged casualty care?","choices": ["It is fully reversed by protamine","It requires frequent aPTT monitoring","Subcutaneous dosing with no routine lab monitoring","It is dosed as a continuous IV infusion"],"answer": 2,"explain": "Enoxaparin uses subcutaneous dosing without routine lab monitoring, making it convenient for prolonged casualty care; protamine only partially reverses it."}]},{"id": 147,"name": "Etomidate","brand": "Amidate","aka": ["Etom"],"cat": "Sedation & RSI","cls": "Imidazole induction agent / sedative-hypnotic","mech": "Enhances GABA-A inhibition to produce rapid hypnosis with minimal cardiovascular depression.","dose": "Induction 0.3 mg/kg IV push over 30-60 sec; onset under 1 min, duration 5-10 min.","ind": "Induction agent for rapid sequence intubation, especially in hemodynamically tenuous trauma patients.","contra": "Known adrenal insufficiency (relative), septic shock (relative, single-dose suppression debated), no analgesia so pair with an opioid.","se": "Myoclonus, adrenal suppression (transient after single dose), nausea/vomiting, pain on injection, no analgesia.","notes": "The most hemodynamically stable induction agent, so it is favored for shocky trauma RSI; it provides zero analgesia, always pair with a paralytic and pain control.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Why is etomidate favored for induction in the hemodynamically tenuous trauma patient?","choices": ["It provides strong analgesia on its own","It is the most hemodynamically stable induction agent with minimal cardiovascular depression","It reliably lowers blood pressure to protect the brain","It has the longest duration of action"],"answer": 1,"explain": "Etomidate produces hypnosis with minimal cardiovascular depression, making it the most hemodynamically stable induction agent; it provides no analgesia."}]},{"id": 148,"name": "Propofol","brand": "Diprivan","aka": ["Prop","Milk of amnesia"],"cat": "Sedation & RSI","cls": "Alkylphenol sedative-hypnotic","mech": "Potentiates GABA-A chloride channels producing rapid, smoothly titratable sedation and hypnosis.","dose": "Induction 1.5-2.5 mg/kg IV; maintenance sedation 25-75 mcg/kg/min infusion titrated to effect.","ind": "Induction and maintenance of sedation, procedural sedation, post-intubation sedation, status epilepticus.","contra": "Hemodynamic instability/hypotension, egg or soy allergy (relative), hypovolemia.","se": "Dose-dependent hypotension and respiratory depression, injection-site pain, propofol-related infusion syndrome with prolonged high doses.","notes": "Rapid on/off makes it ideal for titrated post-intubation sedation, but it drops blood pressure, so it is a poor choice for the under-resuscitated trauma casualty.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "Why is propofol a poor choice for the under-resuscitated trauma casualty?","choices": ["Its onset is too slow for sedation","It causes dose-dependent hypotension","It has no effect on the GABA-A receptor","It cannot be titrated"],"answer": 1,"explain": "Propofol causes dose-dependent hypotension, so it is a poor choice for the hypovolemic, under-resuscitated trauma patient despite its rapid on/off profile."}]},{"id": 149,"name": "Rocuronium","brand": "Zemuron","aka": ["Roc"],"cat": "Muscle Relaxants","cls": "Non-depolarizing aminosteroid neuromuscular blocker","mech": "Competitively blocks the nicotinic acetylcholine receptor at the motor end plate, producing flaccid paralysis.","dose": "RSI 1.2 mg/kg IV for fastest onset (about 45-60 sec); standard intubating dose 0.6 mg/kg, duration 30-60 min.","ind": "Paralysis for rapid sequence intubation and to maintain intubation/ventilation conditions.","contra": "Inability to manage a failed airway (relative), known hypersensitivity.","se": "Prolonged paralysis, anaphylaxis (rare), no analgesia or sedation, tachycardia at high doses.","notes": "Preferred SOF paralytic when succinylcholine is contraindicated; at RSI dose it can be fully reversed within minutes by sugammadex if intubation fails.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What is the rocuronium dose that gives the fastest onset for rapid sequence intubation?","choices": ["0.1 mg/kg IV","0.6 mg/kg IV","1.2 mg/kg IV","3 mg/kg IM"],"answer": 2,"explain": "A 1.2 mg/kg IV dose of rocuronium gives the fastest onset (about 45-60 seconds) for RSI and can be reversed within minutes by sugammadex."}]},{"id": 150,"name": "Succinylcholine","brand": "Anectine, Quelicin","aka": ["Sux","Suxamethonium","SCh"],"cat": "Muscle Relaxants","cls": "Depolarizing neuromuscular blocker","mech": "Binds and persistently depolarizes the acetylcholine receptor, causing fasciculations then flaccid paralysis.","dose": "RSI 1-1.5 mg/kg IV (onset 30-45 sec, duration 5-10 min); 3-4 mg/kg IM if no IV access.","ind": "Rapid sequence intubation when fast onset and short duration are desired.","contra": "Burns or crush/denervation injury greater than 24-72 h, hyperkalemia, history of malignant hyperthermia, severe neuromuscular disease.","se": "Hyperkalemia, malignant hyperthermia, bradycardia (esp. peds/repeat dosing), fasciculation-related myalgias, raised intraocular/intracranial/intragastric pressure.","notes": "Fast on and off, but the hyperkalemia risk in burns and crush casualties is the classic battlefield trap, default to rocuronium in those patients.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "In which battlefield casualty is succinylcholine classically avoided because of hyperkalemia risk?","choices": ["A patient with an isolated forearm laceration","Burns or crush/denervation injury beyond 24-72 hours","A patient with mild dehydration","A patient with a simple anxiety reaction"],"answer": 1,"explain": "Succinylcholine can cause lethal hyperkalemia in burns and crush/denervation injuries beyond 24-72 hours, so rocuronium is the default in those patients."}]},{"id": 151,"name": "Vecuronium","brand": "Norcuron","aka": ["Vec"],"cat": "Muscle Relaxants","cls": "Non-depolarizing aminosteroid neuromuscular blocker","mech": "Competitively antagonizes the acetylcholine receptor at the neuromuscular junction to produce paralysis.","dose": "Intubation 0.1 mg/kg IV (onset 2-3 min, duration 30-45 min); maintenance 0.01-0.015 mg/kg as needed.","ind": "Maintenance of paralysis after intubation, alternative intubating paralytic.","contra": "Inability to ventilate/secure airway, known hypersensitivity.","se": "Prolonged block (esp. hepatic/renal impairment), no sedation or analgesia, rare anaphylaxis.","notes": "Reconstituted from powder, so it is shelf-stable for prolonged field care, but onset is too slow for primary RSI, reserve it for sustained paralysis with adequate sedation.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "Why is vecuronium reserved for sustained paralysis rather than primary rapid sequence intubation?","choices": ["It provides excessive sedation","Its onset of 2-3 minutes is too slow for primary RSI","It cannot be reconstituted in the field","It causes immediate hyperkalemia"],"answer": 1,"explain": "Vecuronium has a slow 2-3 minute onset, making it too slow for primary RSI; it is reserved for maintaining paralysis with adequate sedation."}]},{"id": 152,"name": "Flumazenil","brand": "Romazicon","aka": [],"cat": "Reversal Agents","cls": "Benzodiazepine receptor antagonist","mech": "Competitively blocks the benzodiazepine binding site on the GABA-A receptor, reversing sedation.","dose": "0.2 mg IV over 15 sec, repeat 0.2 mg q1min to a usual max of 1 mg; resedation possible as it wears off.","ind": "Reversal of benzodiazepine-induced sedation, suspected isolated benzodiazepine overdose.","contra": "Chronic benzodiazepine use/dependence, co-ingestion of proconvulsants or TCAs, benzodiazepines given for seizure or raised ICP control.","se": "Seizures (esp. in dependent patients), resedation, agitation, arrhythmias.","notes": "Use is sharply limited because precipitating refractory seizures is a real danger in unknown or mixed overdoses; it is rarely a battlefield drug.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "What is the major danger that sharply limits flumazenil use in unknown or mixed overdoses?","choices": ["Precipitating refractory seizures","Causing malignant hyperthermia","Triggering severe hyperkalemia","Inducing prolonged paralysis"],"answer": 0,"explain": "Flumazenil can precipitate refractory seizures, especially in benzodiazepine-dependent patients or co-ingestion of proconvulsants, sharply limiting its use."}]},{"id": 153,"name": "Sugammadex","brand": "Bridion","aka": [],"cat": "Reversal Agents","cls": "Selective relaxant binding agent","mech": "Encapsulates rocuronium or vecuronium molecules in plasma, rapidly removing them from the neuromuscular junction.","dose": "Routine reversal 2-4 mg/kg IV; immediate reversal of a 1.2 mg/kg roc RSI dose 16 mg/kg IV.","ind": "Reversal of rocuronium- or vecuronium-induced neuromuscular blockade, including a failed/cannot-intubate RSI.","contra": "Hypersensitivity to sugammadex; reduced efficacy in severe renal impairment.","se": "Bradycardia/hypotension, anaphylaxis, reduced efficacy of hormonal contraceptives, recurrence of block if underdosed.","notes": "The 16 mg/kg dose can rescue a paralyzed cannot-intubate-cannot-oxygenate patient within minutes, a key reason roc is favored over sux when sugammadex is on hand.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "What sugammadex dose is used for immediate reversal of a 1.2 mg/kg rocuronium RSI dose in a cannot-intubate situation?","choices": ["2 mg/kg IV","4 mg/kg IV","16 mg/kg IV","0.04 mg/kg IV"],"answer": 2,"explain": "The 16 mg/kg dose of sugammadex can rescue a paralyzed cannot-intubate-cannot-oxygenate patient within minutes after a 1.2 mg/kg roc RSI dose."}]},{"id": 154,"name": "Glucagon","brand": "GlucaGen, Baqsimi","aka": [],"cat": "Endocrine & Metabolic","cls": "Pancreatic hormone / counter-regulatory agent","mech": "Stimulates hepatic glycogenolysis and gluconeogenesis to raise blood glucose and exerts positive inotropy via cyclic-AMP independent of beta receptors.","dose": "Hypoglycemia 1 mg IM/SC/IV (or 3 mg intranasal). Beta-blocker/CCB overdose: 3-10 mg IV bolus then infusion.","ind": "Severe hypoglycemia without IV access, beta-blocker and calcium-channel-blocker toxicity, smooth-muscle relaxation for esophageal foreign body.","contra": "Pheochromocytoma, insulinoma, known hypersensitivity.","se": "Nausea and vomiting, hyperglycemia, hypokalemia, tachycardia.","notes": "The go-to for hypoglycemia when you cannot get a line, and the cardiac antidote that overrides beta-blockade in overdose; needs hepatic glycogen so it fails in the starved patient.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "In which patient will glucagon fail to correct hypoglycemia because it depends on hepatic glycogen?","choices": ["A patient with a beta-blocker overdose","A starved or glycogen-depleted patient","A patient with esophageal foreign body","A well-fed diabetic with an insulin reaction"],"answer": 1,"explain": "Glucagon raises glucose by stimulating hepatic glycogenolysis, so it fails in the starved, glycogen-depleted patient."}]},{"id": 155,"name": "Insulin (Regular)","brand": "Humulin R, Novolin R","aka": ["Regular insulin","Insulin R"],"cat": "Endocrine & Metabolic","cls": "Short-acting human insulin","mech": "Drives glucose and potassium into cells and suppresses hepatic glucose production and ketogenesis.","dose": "DKA 0.1 units/kg/h IV infusion (with or without 0.1 units/kg bolus). Hyperkalemia 10 units IV with 25 g dextrose.","ind": "Diabetic ketoacidosis, hyperosmolar hyperglycemic state, severe hyperkalemia, hyperglycemia management.","contra": "Hypoglycemia, hypokalemia (correct potassium first in DKA).","se": "Hypoglycemia, hypokalemia, weight gain, injection-site reactions.","notes": "The only insulin given IV; always pair with dextrose for the hyperkalemia protocol and recheck glucose, hypoglycemia is the dangerous downstream event.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "In the hyperkalemia protocol, what must always accompany IV regular insulin?","choices": ["A potassium supplement","Dextrose, to prevent dangerous hypoglycemia","A loop diuretic","Sodium bicarbonate in the same line"],"answer": 1,"explain": "Insulin given IV for hyperkalemia must be paired with dextrose because hypoglycemia is the dangerous downstream event; regular insulin is the only IV insulin."}]},{"id": 156,"name": "Metoclopramide","brand": "Reglan","aka": ["MCP"],"cat": "Antiemetics","cls": "Dopamine antagonist / prokinetic antiemetic","mech": "Blocks central D2 receptors in the chemoreceptor trigger zone and enhances upper-GI motility.","dose": "10 mg IV/IM/PO q6-8h (slow IV push over 1-2 min); 10-20 mg for migraine-associated nausea.","ind": "Nausea and vomiting, gastroparesis, migraine adjunct, aspiration prophylaxis before RSI.","contra": "Bowel obstruction or perforation, pheochromocytoma, seizure disorder, Parkinson disease.","se": "Extrapyramidal reactions and acute dystonia, akathisia, tardive dyskinesia, QT prolongation, drowsiness.","notes": "Effective antiemetic and prokinetic, but watch for restlessness/dystonia, treat acute reactions with diphenhydramine and push it slowly to avoid akathisia.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Which adverse effect of metoclopramide is treated with diphenhydramine?","choices": ["Acute dystonic/extrapyramidal reactions","Hyperkalemia","Malignant hyperthermia","Hypoglycemia"],"answer": 0,"explain": "Metoclopramide can cause acute dystonia and other extrapyramidal reactions, which are treated with diphenhydramine; slow pushing limits akathisia."}]},{"id": 157,"name": "Haloperidol","brand": "Haldol","aka": ["Haldol","Haldol decanoate"],"cat": "CNS & Neurological","cls": "Typical (butyrophenone) antipsychotic","mech": "Antagonizes central D2 dopamine receptors to control psychosis, agitation, and nausea.","dose": "Acute agitation 5-10 mg IM (2-5 mg in elderly); antiemetic 0.5-2 mg IV/IM. Often combined with a benzodiazepine.","ind": "Severe agitation and combative behavior, acute psychosis, refractory nausea, delirium.","contra": "Parkinson disease, prolonged QT, severe CNS depression, dementia-related psychosis (mortality warning).","se": "Extrapyramidal symptoms, QT prolongation/torsades, neuroleptic malignant syndrome, sedation, hypotension.","notes": "Useful chemical restraint for the dangerously agitated casualty when ketamine is unsuitable; get an ECG when feasible and watch the QT, especially with droperidol-class combinations.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "Which monitoring step is emphasized when using haloperidol for a dangerously agitated casualty?","choices": ["Checking blood glucose hourly","Obtaining an ECG and watching the QT interval","Monitoring serum magnesium","Measuring intraocular pressure"],"answer": 1,"explain": "Haloperidol prolongs the QT and risks torsades, so an ECG should be obtained when feasible and the QT watched, especially with droperidol-class combinations."}]},{"id": 158,"name": "Vancomycin","brand": "Vancocin","aka": ["Vanc"],"cat": "Antibiotics","cls": "Glycopeptide antibiotic","mech": "Inhibits bacterial cell-wall synthesis by binding D-alanyl-D-alanine peptidoglycan precursors.","dose": "15-20 mg/kg IV q8-12h (loading dose 25-30 mg/kg in serious infection), target trough or AUC guided. C. diff: 125 mg PO q6h.","ind": "MRSA and resistant gram-positive infections, severe skin/soft-tissue infection, sepsis empiric coverage, oral for C. difficile colitis.","contra": "Known hypersensitivity; dose-adjust in renal impairment.","se": "Nephrotoxicity, vancomycin infusion reaction (red man) with fast infusion, ototoxicity, thrombocytopenia.","notes": "Infuse over at least 60 min to avoid the flushing reaction; oral vanc is not absorbed and treats only C. diff, whereas IV vanc does nothing for colitis.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "Which statement about vancomycin routes is correct?","choices": ["IV vancomycin is the treatment of choice for C. difficile colitis","Oral vancomycin is not absorbed and treats only C. difficile, while IV vanc does nothing for colitis","Oral vancomycin reliably treats MRSA bacteremia","Vancomycin should be infused as a rapid push to avoid red man syndrome"],"answer": 1,"explain": "Oral vancomycin stays in the gut to treat C. difficile and is not absorbed systemically, whereas IV vancomycin has no effect on colitis; infuse IV over at least 60 minutes to avoid the flushing reaction."}]},{"id": 159,"name": "Linezolid","brand": "Zyvox","aka": [],"cat": "Antibiotics","cls": "Oxazolidinone antibiotic","mech": "Binds the 23S ribosomal RNA of the 50S subunit to block bacterial protein synthesis initiation.","dose": "600 mg IV or PO q12h; 100% oral bioavailability allows direct IV-to-PO transition.","ind": "MRSA, vancomycin-resistant enterococcus, resistant gram-positive pneumonia and skin/soft-tissue infections.","contra": "Concurrent serotonergic agents/MAOIs (serotonin syndrome risk), uncontrolled hypertension with sympathomimetics.","se": "Myelosuppression/thrombocytopenia with prolonged use, peripheral and optic neuropathy, serotonin syndrome, lactic acidosis.","notes": "Outstanding for prolonged field care because full oral bioavailability lets you treat MRSA without a line; avoid stacking it with SSRIs or tramadol.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "What property makes linezolid outstanding for treating MRSA in prolonged field care without IV access?","choices": ["It is only available as an IV formulation","It has 100% oral bioavailability, allowing direct IV-to-PO transition","It is unaffected by serotonergic drug interactions","It requires therapeutic drug monitoring"],"answer": 1,"explain": "Linezolid has 100% oral bioavailability, letting medics treat MRSA without a line; it must not be stacked with SSRIs or tramadol due to serotonin syndrome risk."}]},{"id": 160,"name": "Silver Sulfadiazine","brand": "Silvadene, SSD","aka": ["SSD cream"],"cat": "Dermatology","cls": "Topical antimicrobial (sulfonamide silver salt)","mech": "Releases silver ions that disrupt bacterial cell membranes and DNA across a broad spectrum.","dose": "Apply a 1-2 mm layer of 1% cream to cleaned burn wounds once or twice daily; cover with dressing.","ind": "Prevention and treatment of infection in partial- and full-thickness burns.","contra": "Sulfa allergy, term pregnancy/neonates, application to the face (relative).","se": "Transient leukopenia, local irritation, pseudo-eschar that can obscure wound assessment, rare argyria.","notes": "Standard burn-wound prophylaxis in prolonged care, but it forms a pseudo-eschar that complicates depth assessment and is avoided over the face, where bacitracin is preferred.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Which is a known limitation of silver sulfadiazine in burn-wound care?","choices": ["It is the preferred agent for facial burns","It forms a pseudo-eschar that complicates burn-depth assessment","It is safe in sulfa-allergic patients","It is fully absorbed systemically for bacteremia coverage"],"answer": 1,"explain": "Silver sulfadiazine forms a pseudo-eschar that obscures depth assessment and is avoided over the face, where bacitracin is preferred; it is contraindicated in sulfa allergy."}]},{"id": 161,"name": "Nifedipine","brand": "Procardia, Adalat","aka": [],"cat": "Altitude & Environmental","cls": "Dihydropyridine calcium-channel blocker","mech": "Blocks L-type calcium channels in vascular smooth muscle, causing arterial vasodilation including the pulmonary bed.","dose": "HAPE: 30 mg extended-release PO q12h (or 20 mg q8h). Hypertensive urgency: per protocol, avoid immediate-release sublingual.","ind": "High-altitude pulmonary edema (HAPE) treatment and prophylaxis, hypertension, Raynaud phenomenon.","contra": "Hypotension, cardiogenic shock, severe aortic stenosis, acute MI (immediate-release).","se": "Hypotension, reflex tachycardia, peripheral edema, headache, flushing.","notes": "Lowers pulmonary artery pressure in HAPE, but descent and oxygen remain primary, watch for hypotension and never give immediate-release sublingually for blood-pressure control.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "How does nifedipine help in high-altitude pulmonary edema (HAPE)?","choices": ["It increases pulmonary artery pressure","It blocks L-type calcium channels to vasodilate the pulmonary bed and lower pulmonary artery pressure","It acts as a diuretic to remove lung fluid","It directly increases the oxygen content of blood"],"answer": 1,"explain": "Nifedipine blocks L-type calcium channels causing arterial vasodilation including the pulmonary bed, lowering pulmonary artery pressure in HAPE, though descent and oxygen remain primary."}]},{"id": 162,"name": "Sildenafil","brand": "Viagra, Revatio","aka": [],"cat": "Altitude & Environmental","cls": "Phosphodiesterase-5 inhibitor","mech": "Inhibits PDE-5 to increase pulmonary cyclic GMP and nitric-oxide-mediated pulmonary vasodilation.","dose": "HAPE/altitude: 50 mg PO q8h (or 20 mg q8h). Adjust per response.","ind": "High-altitude pulmonary edema and prevention, pulmonary hypertension.","contra": "Concurrent nitrates or other PDE-5 inhibitors (severe hypotension), hypotension, recent MI/stroke.","se": "Headache, flushing, hypotension, visual disturbance, priapism.","notes": "A pulmonary vasodilator alternative to nifedipine for HAPE prophylaxis; never combine with nitrates, the combination can cause catastrophic hypotension.","tccc": false,"duty": "go","scenarios": [],"quiz": [{"q": "Sildenafil must never be combined with which class of drugs because of catastrophic hypotension?","choices": ["Nitrates","Loop diuretics","Beta-blockers","Antihistamines"],"answer": 0,"explain": "Combining the PDE-5 inhibitor sildenafil with nitrates can cause catastrophic hypotension, so the combination is contraindicated."}]},{"id": 163,"name": "Furosemide","brand": "Lasix","aka": ["Frusemide"],"cat": "Cardiovascular & Emergency","cls": "Loop diuretic","mech": "Inhibits the Na-K-2Cl cotransporter in the thick ascending loop of Henle to produce brisk diuresis.","dose": "20-40 mg IV (or 2x the home oral dose IV) for pulmonary edema; titrate to urine output.","ind": "Acute decompensated heart failure/pulmonary edema, volume overload, hypertensive emergency with edema, hyperkalemia adjunct.","contra": "Hypovolemia/dehydration, anuria, severe hypokalemia, sulfa allergy (relative).","se": "Hypokalemia and hyponatremia, hypovolemia/hypotension, ototoxicity with rapid high-dose IV, gout.","notes": "Reserve for cardiogenic pulmonary edema, it is harmful in HAPE and in hypovolemic shock, where the patient needs volume, not diuresis.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "In which condition is furosemide harmful rather than helpful?","choices": ["Acute cardiogenic pulmonary edema","Volume overload from heart failure","HAPE and hypovolemic shock, where the patient needs volume not diuresis","Hypertensive emergency with edema"],"answer": 2,"explain": "Furosemide is reserved for cardiogenic pulmonary edema; it is harmful in HAPE and in hypovolemic shock, where the patient needs volume rather than diuresis."}]},{"id": 164,"name": "Mannitol","brand": "Osmitrol","aka": [],"cat": "CNS & Neurological","cls": "Osmotic diuretic","mech": "Creates an osmotic gradient that draws water out of brain tissue and increases renal water excretion.","dose": "Raised ICP: 0.25-1 g/kg IV over 10-20 min via a filtered line; repeat per neuro status and osmolality.","ind": "Raised intracranial pressure/cerebral edema, impending herniation, reduction of intraocular pressure.","contra": "Hypovolemia/hypotension, anuria, active intracranial hemorrhage (relative), severe heart failure, pulmonary edema.","se": "Hypovolemia and hypotension from diuresis, electrolyte shifts, rebound ICP elevation, renal injury at high osmolality.","notes": "Use a filter (it crystallizes) and avoid in the hypotensive trauma patient, hypertonic saline is preferred for raised ICP when blood pressure is borderline.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "What practical administration step is required when giving mannitol for raised intracranial pressure?","choices": ["Mix it with sodium bicarbonate first","Use a filter, because it crystallizes","Give it as a slow subcutaneous injection","Warm it to body temperature to prevent hemolysis"],"answer": 1,"explain": "Mannitol crystallizes and must be given through a filtered line; it should be avoided in hypotensive trauma patients, where hypertonic saline is preferred."}]},{"id": 165,"name": "Ketotifen","brand": "Zaditor, Zaditen","aka": [],"cat": "Altitude & Environmental","cls": "Antihistamine / mast-cell stabilizer","mech": "Blocks H1 receptors and stabilizes mast cells to reduce histamine release.","dose": "1 mg PO twice daily; ophthalmic 1 drop of 0.025% per eye q8-12h.","ind": "Allergic conjunctivitis and rhinitis, urticaria, exercise- and cold-induced urticaria, asthma adjunct.","contra": "Hypersensitivity; caution with concurrent sedatives.","se": "Sedation, dry mouth, weight gain, dizziness.","notes": "Useful for cold-induced and chronic urticaria in austere environments; the oral form is sedating, so plan dosing around operational tempo.","tccc": false,"duty": "limited","scenarios": [],"quiz": [{"q": "What is a key practical consideration when using oral ketotifen for chronic or cold-induced urticaria in the field?","choices": ["It causes severe hypertension","The oral form is sedating, so dosing should be planned around operational tempo","It must be given intravenously only","It precipitates malignant hyperthermia"],"answer": 1,"explain": "Oral ketotifen is sedating, so medics should plan dosing around the operational tempo when treating cold-induced and chronic urticaria in austere settings."}]}];
